/*
 * sprite_main.c
 * -----------------------------------------------------------------------------
 * Per-type sprite behavior implementations for A Link to the Past.
 *
 * This is the largest single file in the project. It owns the body of every
 * "Sprite_XX_*" active handler and every "SpritePrep_*" one-shot initializer
 * that the sprite framework in sprite.c dispatches to. Each enemy, NPC,
 * boss, pickup, scenery object, and dungeon mechanism gets its own handler
 * here, plus the data tables (animation frames, velocity tables, OAM layouts,
 * palette indices) those handlers consume.
 *
 * Architectural role:
 *   - sprite.c is the framework: slot allocation, OAM emission, generic
 *     physics/collision plumbing, the per-tick "for each live slot" loop.
 *   - sprite_main.c is the policy: which specific state machine runs for
 *     sprite_type[k] == N. The handler is selected at the bottom of
 *     sprite.c via the two big function pointer tables defined here:
 *     kSpriteActiveRoutines[243] (per-tick) and kSpritePrep_Main[243]
 *     (one-shot on spawn).
 *
 * Conventions every handler in this file follows:
 *   - The argument `k` (sometimes `r`) is the sprite slot index into the
 *     sprite_* parallel-array WRAM mirrors (sprite_state, sprite_type,
 *     sprite_x_lo/hi, sprite_y_lo/hi, sprite_ai_state, sprite_subtype1/2,
 *     sprite_A/B/C/D/E/F, sprite_delay_main, sprite_graphics, ...).
 *   - sprite_ai_state[k] is the per-handler micro state machine (0 = initial
 *     wait, 1..N = sequential phases). Most handlers are switch statements
 *     keyed on it.
 *   - sprite_delay_main[k] is a generic frame countdown the framework
 *     decrements automatically; handlers gate state advance on it reaching 0.
 *   - sprite_subtype2[k] often functions as a sub-tick index (animation
 *     frame, segment index for chained sprites, retry counter).
 *   - sprite_oam_flags[k] carries the 4-bit palette select and priority bits
 *     for the slot's primary OAM entry.
 *
 * Existing author comments throughout the file are preserved verbatim,
 * including the occasional "zelda bug:" / "wtf" / "fixed bug" annotations
 * that document quirks of the original ROM that the C port reproduces for
 * byte-identical save-state compatibility.
 */

/* Sprite framework: slot lifecycle, OAM emission, generic physics. */
#include "sprite_main.h"
#include "sprite.h"
/* Followers (Old Man, dwarf, etc.) that piggyback on sprite slots. */
#include "tagalong.h"
/* Projectiles / effects (arrows, sparkles, splashes) spawned by handlers. */
#include "ancilla.h"
/* Overworld map state — needed for area-aware NPC scripting and warps. */
#include "overworld.h"
/* Palette/CHR loading triggered by certain transformations (Trinexx etc.). */
#include "load_gfx.h"
/* HUD refresh after item-grant handlers (Wish Pond, treasure chests). */
#include "hud.h"
/* Dungeon-room machinery: tile-attribute lookups, room flags, door state. */
#include "dungeon.h"
/* Link state queries (position, facing, immobilization, item ownership). */
#include "player.h"
/* Cross-module helpers: SFX pan, sprite-bank lookups, fade controllers. */
#include "misc.h"

/*
 * ============================================================================
 * Module data: WRAM aliases and per-sprite lookup tables
 * ============================================================================
 * The blocks below define two kinds of names used throughout the file:
 *   1. #defines that alias a specific WRAM byte/word region (g_ram + offset)
 *      into a typed accessor. These mirror the original ROM's direct-page
 *      addresses so we can express SNES-side bit-banging in plain C while
 *      keeping save-state byte identity with the reference emulator.
 *   2. `static const` lookup tables consumed by individual sprite handlers.
 *      Most are tiny (4/8/16-entry) arrays keyed on facing direction,
 *      animation frame index, or a sub-state counter. Their consumer is
 *      usually obvious from the symbol prefix (e.g. kZazak_* is read by
 *      Sprite_Zazak_Main further down).
 *
 * Sprite-slot bookkeeping byte at 0x7E:0x7FE01 used by a few handlers as
 * a scratch latch (see byte_7FFE01 references later).
 */
#define byte_7FFE01 (*(uint8*)(g_ram+0x1FE01))

/* Keese (bat) sinusoidal flight: 16-entry sin/cos pair used for circular
 * hover velocity. Tab2 is sin(theta), Tab3 is cos(theta) starting from a
 * different phase so the two together trace a Lissajous-like wobble. */
static const int8 kSpriteKeese_Tab2[16] = {0, 8, 11, 14, 16, 14, 11, 8, 0, -8, -11, -14, -16, -14, -11, -8};
static const int8 kSpriteKeese_Tab3[16] = {-16, -14, -11, -8, 0, 8, 11, 14, 16, 14, 11, 8, 0, -9, -11, -14};

/* Zazak (red goblin throwing fireballs) cardinal-direction Y velocity table,
 * indexed by facing direction 0=down,1=up,2=right,3=left. */
static const int8 kZazak_Yvel[4] = {0, 0, 16, -16};

/* Flute Boy's animals (chasing the boy in Lost Woods) cardinal X velocities. */
static const int8 kFluteBoyAnimal_Xvel[4] = {16, -16, 0, 0};

/* Desert Barrier (statues guarding the desert palace entrance) X/Y velocities,
 * keyed on the cardinal index that decides which barrier piece slides where. */
static const int8 kDesertBarrier_Xv[4] = {16, -16, 0, 0};
static const int8 kDesertBarrier_Yv[4] = {0, 0, 16, -16};

/* Crystal switch (orange/blue) palette indices for the two states. */
static const uint8 kCrystalSwitchPal[2] = {2, 4};

/* Zazak direction-remap table used when the goblin recalculates its facing
 * after a wall bonk; 8 entries cover the four cardinal+four reflected cases. */
static const uint8 kZazak_Dir2[8] = {2, 3, 2, 3, 0, 1, 0, 1};

/* Giant Moldorm (Tower of Hera mini-boss) keeps a 128-entry rolling history
 * of segment positions so the body trails the head with a configurable
 * lookback. moldorm_x_lo/hi and moldorm_y_lo/hi are the four banks of that
 * history (low byte / high byte / X / Y), shared across all moldorm slots
 * via the head's sprite_subtype2 cursor. */
#define moldorm_x_lo ((uint8*)(g_ram+0x1FC00))
#define moldorm_x_hi ((uint8*)(g_ram+0x1FC80))
#define moldorm_y_lo ((uint8*)(g_ram+0x1FD00))
#define moldorm_y_hi ((uint8*)(g_ram+0x1FD80))
/* Bad / trapped pull switch (drops a Spike Trap when yanked). The five-entry
 * parallel arrays describe the 5-tile composite sprite layout (X/Y offsets,
 * CHR index, OAM flags, and big/small flag) drawn each frame. _Tab4/_Tab5
 * are step LUTs used by the yank animation to pick a tile from kThief_Gfx
 * for each frame of the pull. */
static const int8 kBadPullDownSwitch_X[5] = {-4, 12, 0, -4, 4};
static const int8 kBadPullDownSwitch_Y[5] = {-3, -3, 0, 5, 5};
static const uint8 kBadPullDownSwitch_Char[5] = {0xd2, 0xd2, 0xc4, 0xe4, 0xe4};
static const uint8 kBadPullDownSwitch_Flags[5] = {0x40, 0, 0, 0x40, 0};
static const uint8 kBadPullDownSwitch_Big[5] = {0, 0, 2, 2, 2};
static const uint8 kBadPullSwitch_Tab5[6] = {0, 1, 2, 3, 4, 5};
static const uint8 kBadPullSwitch_Tab4[12] = {0, 0, 1, 1, 2, 2, 3, 3, 4, 5, 5, 5};

/* Thief sprite graphic frame remap: animation-frame index -> CHR offset for
 * the thief's 12-frame walk cycle. */
static const uint8 kThief_Gfx[12] = {11, 8, 2, 5, 9, 6, 0, 3, 10, 7, 1, 4};

/* Four 16-bit scratch latches at WRAM 0x7FE00..0x7FE06. Used by a few
 * handlers (Ganon, Trinexx, Mothula etc.) as cross-frame scratch storage
 * for sub-pixel position or angle accumulators that don't fit in a single
 * sprite_* byte. */
#define word_7FFE00 (*(uint16*)(g_ram+0x1FE00))
#define word_7FFE02 (*(uint16*)(g_ram+0x1FE02))
#define word_7FFE04 (*(uint16*)(g_ram+0x1FE04))
#define word_7FFE06 (*(uint16*)(g_ram+0x1FE06))
