/*
 * BottleMerchant_DetectFish — Scan all 16 sprite slots for an active fish
 * (type 0xd2). If one overlaps a 16x16 box around the merchant, latch its
 * slot in sprite_E[k] | 0x80 (the high bit distinguishes "fish offered"
 * from "bee offered" in the conversation state machine).
 */
void BottleMerchant_DetectFish(int k) {  // 868000
  for (int i = 15; i >= 0; i--) {
    if (sprite_state[i] && sprite_type[i] == 0xd2) {
      SpriteHitBox hb;
      hb.r0_xlo = sprite_x_lo[k];
      hb.r8_xhi = sprite_x_hi[k];
      hb.r2 = 16;
      hb.r1_ylo = sprite_y_lo[k];
      hb.r9_yhi = sprite_y_hi[k];
      hb.r3 = 16;
      Sprite_SetupHitBox(i, &hb);
      if (CheckIfHitBoxesOverlap(&hb))
        sprite_E[k] = 0x80 | i;
      return;
    }
  }
}

/*
 * BottleMerchant_BuyFish — Pay 5 rupees for the fish by spawning 5 rupee
 * pickups (kBottleVendor_FishRewardType picks rupee variants 0xdb..0xe2)
 * in a fan pattern from the merchant. X velocities -6..+7 px/frame and Y
 * velocities 11..16 give an outward-and-down arc; z_vel=32 makes them
 * hop. Each rupee has stunned=0xff so the player can immediately grab
 * them after they settle (delay_aux4=32 prevents instant grab on touch).
 */
void BottleMerchant_BuyFish(int k) {  // 868054
  static const uint8 kBottleVendor_FishRewardType[5] = {0xdb, 0xe0, 0xde, 0xe2, 0xd9};
  static const int8 kBottleVendor_FishRewardXv[5] = {-6, -3, 0, 4, 7};
  static const int8 kBottleVendor_FishRewardYv[5] = {11, 14, 16, 14, 11};
  SpriteSpawnInfo info;
  SpriteSfx_QueueSfx3WithPan(k, 0x13);
  tmp_counter = 4;
  do {
    int j = Sprite_SpawnDynamically(k, kBottleVendor_FishRewardType[tmp_counter], &info);
    if (j < 0)
      return;
    Sprite_SetSpawnedCoordinates(j, &info);
    sprite_x_lo[j] = info.r0_x + 4;
    sprite_stunned[j] = 0xff;
    sprite_x_vel[j] = kBottleVendor_FishRewardXv[tmp_counter];
    sprite_y_vel[j] = kBottleVendor_FishRewardYv[tmp_counter];
    sprite_z_vel[j] = 32;
    sprite_delay_aux4[j] = 32;
  } while (!sign8(--tmp_counter));
}

/* SpritePrep_ThrowableScenery — One-shot init for skull/pot/sign throwables.
 * Empty body — all defaults inherited from the framework. */
void SpritePrep_ThrowableScenery(int k) {  // 86850f
}

/*
 * SpriteModule_Initialize — Framework hook: when a slot transitions from
 * dead to alive, run common Sprite_LoadProperties (palette, HP, base flags)
 * then dispatch to the per-type one-shot prep handler via the
 * kSpritePrep_Main lookup. After this returns, the slot is fully live and
 * the per-tick handler takes over.
 */
void SpriteModule_Initialize(int k) {  // 86864d
  SpritePrep_LoadProperties(k);
  sprite_state[k]++;
  kSpritePrep_Main[sprite_type[k]](k);
}

/* SpritePrep_Mantle — Movable Mantle spawn nudge: 3 px down, 8 px right
 * so the mantle aligns with its destination tile. */
void SpritePrep_Mantle(int k) {  // 868841
  sprite_y_lo[k] += 3;
  sprite_x_lo[k] += 8;
}

/*
 * SpritePrep_Switch — Pull switch palette tweak: in three specific rooms
 * (Eastern Palace bumper, the Aquarium-room dungeon, and Misery Mire),
 * force the switch's OAM palette to 0xD so it visually matches the
 * surrounding tilework.
 */
void SpritePrep_Switch(int k) {  // 868859
  int j = BYTE(dungeon_room_index2);
  if (j == 0xce || j == 4 || j == 0x3f)
    sprite_oam_flags[k] = 0xD;
}

/* SpritePrep_SwitchFacingUp — No-op; up-facing variants use defaults. */
