/*
 * Sprite_22_Ropa — Ropa (frog-like enemy that pounces). 2-state:
 *   0 Stationary : Wait for delay_main; on expiry, apply Link-speed and
 *                  random z_vel (20..35) for the pounce.
 *   1 Pounce     : Move XY; on tile collision zero velocity. Apply z
 *                  gravity (z_vel -= 2); on landing reset to state 0
 *                  with 48-frame post-hop rest.
 * subtype2 >> 3 picks one of 4 mouth-open animation frames each tick.
 */
void Sprite_22_Ropa(int k) {  // 869e1f
  Ropa_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  Sprite_CheckDamageToAndFromLink(k);
  sprite_subtype2[k]++;
  sprite_graphics[k] = sprite_subtype2[k] >> 3 & 3;
  switch(sprite_ai_state[k]) {
  case 0:  // stationary
    if (!sprite_delay_main[k]) {
      Sprite_ApplySpeedTowardsLink(k, 16);
      sprite_z_vel[k] = (GetRandomNumber() & 15) + 20;
      sprite_ai_state[k]++;
    }
    break;
  case 1:  // pounce
    Sprite_MoveXY(k);
    if (Sprite_CheckTileCollision(k))
      Sprite_ZeroVelocity_XY(k);
    Sprite_MoveZ(k);
    sprite_z_vel[k] -= 2;
    if (sign8(sprite_z[k])) {
      sprite_z[k] = 0;
      sprite_delay_main[k] = 48;
      sprite_ai_state[k] = 0;
    }
    break;
  }
}

