/*
 * Sprite_23_RedBari — Red Bari (electric jellyfish). Per-tick:
 *   Sign-negative sprite_C tracks a "split-then-reform" cooldown: head_dir
 *     counts up to 16 then the Bari checks the tile under it; if clear,
 *     re-arm the electrocute delay; otherwise stays buried.
 *   sprite_C != 0 (split-half): render as small single tile.
 *   graphics >= 2 (recoiled): single large tile.
 *   Otherwise: RedBari_Draw composite.
 *
 * Movement: sin/cos circle via kBari_Xvel2/Yvel2 (16 entries). On the
 * "recoil_from_split" path (delay_aux2 set after splitting) the Bari
 * uses the alternate movement loop. Every 16 frames perturb sprite_A
 * (orbit phase) by ±1 driven by sprite_B parity, with 25% chance to
 * flip B (direction reversal).
 *
 * 3-state AI sub-machine via ai_state:
 *   0 Normal      : Standard wander; 50% chance per electrocute interval
 *                   to advance to state 1 (charging).
 *   1 Charging    : Hold pose for delay_main (128 frames); flicker palette
 *                   via (frame_counter >> 1 & 2) + kBari_Gfx[C].
 *   2 Splitting   : When killed at full HP, split into two halves
 *                   (RedBari_Split). The two halves use the same handler
 *                   with C=1 (small Bari).
 */
void Sprite_23_RedBari(int k) {  // 86a23d
  static const int8 kBari_Xvel2[16] = {0, 8, 11, 14, 16, 14, 11, 8, 0, -8, -11, -14, -16, -14, -11, -8};
  static const int8 kBari_Yvel2[16] = {-16, -14, -11, -8, 0, 8, 11, 14, 16, 14, 11, 8, 0, -9, -11, -14};
  static const uint8 kBari_Gfx[2] = {0, 3};
  int j;

  if (sign8(sprite_C[k])) {
    if (sprite_head_dir[k] != 16) {
      sprite_head_dir[k]++;
    } else {
      sprite_x_vel[k] = 255;
      sprite_subtype[k] = 255;
      Sprite_CheckTileCollision2(k);
      sprite_subtype[k] = 0;
      if (!sprite_tiletype) {
        sprite_C[k] = 0;
        sprite_ignore_projectile[k] = 0;
        goto set_electrocute_delay;
      }
      sprite_ignore_projectile[k] = sprite_tiletype;
    }
    return;
  }
  if (sprite_C[k] != 0) {
    SpriteDraw_SingleSmall(k);
  } else if (sprite_graphics[k] >= 2) {
    SpriteDraw_SingleLarge(k);
  } else {
    RedBari_Draw(k);
  }

  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  if (sprite_delay_aux2[k])
    goto recoil_from_split;

  if (sprite_ai_state[k] == 2) {
    static const int8 kBari_Xvel[2] = {8, -8};
    sprite_ignore_projectile[k] = sprite_ai_state[k];
    sprite_x_vel[k] = kBari_Xvel[frame_counter >> 1 & 1];
    Sprite_MoveX(k);
    if (!sprite_delay_main[k]) {
      RedBari_Split(k);
      sprite_state[k] = 0;
    }
    return;
  }

  Sprite_CheckDamageToAndFromLink(k);
  if (!((k ^ frame_counter) & 15)) {
    sprite_A[k] += (sprite_B[k] & 1) ? -1 : 1;
    if (!(GetRandomNumber() & 3))
      sprite_B[k]++;
  }
  j = sprite_A[k] & 15;
  sprite_x_vel[k] = kBari_Xvel2[j];
  sprite_y_vel[k] = kBari_Yvel2[j];

  if (!((k ^ frame_counter) & 3 | sprite_delay_main[k])) {
recoil_from_split:
    if (!sprite_wallcoll[k])
      Sprite_MoveXY(k);
    Sprite_CheckTileCollision2(k);
  }
  j = sprite_C[k];
  sprite_graphics[k] = (frame_counter >> 3 & 1) + kBari_Gfx[j];
  if (sprite_ai_state[k]) {
    if (sprite_delay_main[k]) {
      sprite_graphics[k] = (frame_counter >> 1 & 2) + kBari_Gfx[j];
      return;
    }
    sprite_ai_state[k] = 0;
  } else if (sprite_delay_aux1[k]) {
    return;
  } else if (!(GetRandomNumber() & 1)) {
    sprite_delay_main[k] = 128;
    sprite_ai_state[k]++;
    return;
  }
set_electrocute_delay:
  sprite_delay_aux1[k] = (GetRandomNumber() & 63) + 128;
}

/*
 * RedBari_Split — Spawn 2 child Baris (the split halves) flying out left
 * and right at 32 px/frame. Both children get sprite_C=1 (small) and
 * 64-frame post-split invulnerability (delay_aux1).
 */
void RedBari_Split(int k) {  // 86a34e
  static const int8 kRedBari_SplitX[2] = {0, 8};
  static const int8 kRedBari_SplitXvel[2] = {-32, 32};

  tmp_counter = 1;
  do {
    SpriteSpawnInfo info;
    int j = Sprite_SpawnDynamically(k, 0x23, &info);
    if (j >= 0) {
      Sprite_SetSpawnedCoordinates(j, &info);
      sprite_flags3[j] = 0x33;
      sprite_oam_flags[j] = 3;
      sprite_flags4[j] = 1;
      sprite_C[j] = 1;
      Sprite_SetX(j, info.r0_x + kRedBari_SplitX[tmp_counter]);
      sprite_x_vel[j] = kRedBari_SplitXvel[tmp_counter];
      sprite_delay_aux2[j] = 8;
      sprite_delay_aux1[j] = 64;
    }
  } while (!sign8(--tmp_counter));

}

/* RedBari_Draw — 4-tile 2x2 composite. 2 graphics frames (8 entries).
 * Adds standard shadow beneath. */
void RedBari_Draw(int k) {  // 86a3dc
  static const DrawMultipleData kRedBari_Dmd[8] = {
    {0, 0, 0x0022, 0},
    {8, 0, 0x4022, 0},
    {0, 8, 0x0032, 0},
    {8, 8, 0x4032, 0},
    {0, 0, 0x0023, 0},
    {8, 0, 0x4023, 0},
    {0, 8, 0x0033, 0},
    {8, 8, 0x4033, 0},
  };
  PrepOamCoordsRet info;
  Sprite_DrawMultiple(k, &kRedBari_Dmd[sprite_graphics[k] * 4], 4, &info);
  SpriteDraw_Shadow(k, &info);
}

/*
 * Sprite_13_MiniHelmasaur — Mini-Helmasaur (the small mask-wearing
 * dungeon enemy). Direction D is re-derived every 16 frames from the
 * dominant axis of velocity (whichever of |x_vel|, |y_vel| is larger),
 * with the +2 Y offset selecting up vs down. Frame animation flips
 * between two poses via subtype2 bit 2.
 *
 * Shares HelmasaurHardHatBeetleCommon with Hardhat Beetle for tile-collide
 * + per-32-frames Link homing.
 */
void Sprite_13_MiniHelmasaur(int k) {  // 86a409
  static const uint8 kHelmasaur_Gfx[8] = {3, 4, 3, 4, 2, 2, 5, 5};
  static const uint8 kHelmasaur_OamFlags[8] = {0x40, 0x40, 0, 0, 0, 0x40, 0x40, 0};
  int j = sprite_subtype2[k] >> 2 & 1 | sprite_D[k] << 1;
  sprite_graphics[k] = kHelmasaur_Gfx[j];
  sprite_oam_flags[k] = sprite_oam_flags[k] & ~0x40 | kHelmasaur_OamFlags[j];
  if (!((k ^ frame_counter) & 15)) {
    uint8 x = sprite_x_vel[k];
    if (sign8(x)) x = -x;
    uint8 y = sprite_y_vel[k];
    if (sign8(y)) y = -y;
    sprite_D[k] = (x >= y) ? (sprite_x_vel[k] >> 7) : (sprite_y_vel[k] >> 7) + 2;
  }
  SpriteDraw_SingleLarge(k);
  HelmasaurHardHatBeetleCommon(k);
}

/*
 * Sprite_26_HardhatBeetle — Hardhat Beetle. Animation toggles 2 frames
 * (subtype2 bit 2). Shares the common bouncing-pursue loop.
 */
void Sprite_26_HardhatBeetle(int k) {  // 86a460
  sprite_graphics[k] = sprite_subtype2[k] >> 2 & 1;
  HardHatBeetle_Draw(k);
  HelmasaurHardHatBeetleCommon(k);
}

/*
 * HelmasaurHardHatBeetleCommon — Shared movement tick. Wall-collide zeros
 * the appropriate velocity axis; otherwise step XY. Every 32 frames
 * snapshot the speed-toward-Link vector into B/C (target velocity). On
 * the (k ^ frame_counter) & ai_state schedule, drift current velocity
 * by ±1 toward the target so the enemy slowly homes in.
 */
void HelmasaurHardHatBeetleCommon(int k) {  // 86a46d
  if (Sprite_ReturnIfInactive(k))
    return;
  sprite_subtype2[k]++;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  Sprite_CheckDamageToAndFromLink(k);
  if (sprite_wallcoll[k] & 15) {
    if (sprite_wallcoll[k] & 3)
      sprite_x_vel[k] = 0;
    sprite_y_vel[k] = 0;
  } else {
    Sprite_MoveXY(k);
  }
  Sprite_CheckTileCollision(k);
  if (!((k ^ frame_counter) & 31)) {
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLink(k, sprite_A[k]);
    sprite_B[k] = pt.y;
    sprite_C[k] = pt.x;
  }
  if ((k ^ frame_counter) & sprite_ai_state[k])
    return;
  sprite_y_vel[k] += sign8(sprite_y_vel[k] - sprite_B[k]) ? 1 : -1;
  sprite_x_vel[k] += sign8(sprite_x_vel[k] - sprite_C[k]) ? 1 : -1;
}

/* HardHatBeetle_Draw — 2-tile (hat + body) composite, 2 frames. Shadow
 * only drawn when flags3 bit 0x10 (on ground). */
void HardHatBeetle_Draw(int k) {  // 86a4f2
  static const DrawMultipleData kHardHatBeetle_Dmd[4] = {
    {0, -4, 0x0140, 2},
    {0,  2, 0x0142, 2},
    {0, -5, 0x0140, 2},
    {0,  2, 0x0144, 2},
  };
  PrepOamCoordsRet info;
  Sprite_DrawMultiple(k, &kHardHatBeetle_Dmd[sprite_graphics[k] * 2], 2, &info);
  if (sprite_flags3[k] & 0x10)
    SpriteDraw_Shadow(k, &info);
}

/*
 * Sprite_15_Antifairy — Antifairy (bubble that drains magic on contact).
 * On Link contact (and 16-frame cooldown), drain 8 magic from link_magic_power
 * (clamped at 0); only play the drain SFX if magic was actually drained.
 * Otherwise just bounce off walls (Sprite_BounceFromTileCollision).
 */
void Sprite_15_Antifairy(int k) {  // 86a50c
  SpriteDraw_Antfairy(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_CheckDamageToLink(k) && sprite_delay_main[k] == 0) {
    sprite_delay_main[k] = 16;
    int t = link_magic_power - 8;
    if (t < 0)
      t = 0;
    else
      sound_effect_2 = 0x1d;
    link_magic_power = t;
  }
  Sprite_MoveXY(k);
  Sprite_BounceFromTileCollision(k);
}

/*
 * Sprite_0B_Cucco — Cucco (chicken). Slot handles 4 distinct "modes" via
 * head_dir, state, and C:
 *   head_dir != 0: Cucco transmutes to its avenger (type 0x3d) and starts
 *                  attacking. Used after Link hits the cucco too many
 *                  times.
 *   state == 10  : Cucco being held by Link. Run the panic animation.
 *   C != 0       : Cucco mid-air after being thrown.
 *   else         : Normal idle/walk/flee/carried logic via ai_state:
 *                   0 Calm    : pick a random 16-direction velocity.
 *                   1 Hopping : apply z gravity, bounce off walls.
 *                   2 Flee    : run away from Link every 32 frames, plays
 *                               the distress overlay.
 *                   3 Carried : "stuck on Link's head" state — recoils
 *                               when colliding with a wall.
 *
 * Cucco_SummonAvenger runs every 16 frames once sprite_B (hit count)
 * reaches 35, spawning an avenging Cucco type 0x0B with C=1 from outside
 * the camera bounds.
 */
void Sprite_0B_Cucco(int k) {  // 86a5c2
  if (sprite_x_vel[k] != 0)
    sprite_oam_flags[k] = sprite_oam_flags[k] & ~0x40 | (sign8(sprite_x_vel[k]) ? 0 : 0x40);

  SpriteDraw_SingleLarge(k);
  if (sprite_head_dir[k] != 0) {
    sprite_type[k] = 0x3d;
    SpritePrep_LoadProperties(k);
    sprite_subtype[k]++;
    sprite_delay_main[k] = 48;
    sound_effect_1 = 21;
    sprite_ignore_projectile[k] = 21;
    return;
  }
  if (sprite_state[k] == 10) {
    sprite_ai_state[k] = 3;
    if (submodule_index == 0) {
      Chicken_IncrSubtype2(k, 3);
      Cucco_DrawPANIC(k);
      if (!(frame_counter & 0xf))
        BawkBawk(k);
    }
  }
  if (Sprite_ReturnIfInactive(k))
    return;
  if (sprite_C[k] != 0) {
    sprite_oam_flags[k] |= 0x10;
    Sprite_MoveXY(k);
    sprite_z[k] = 12;
    sprite_ignore_projectile[k] = 12;
    if (((k ^ frame_counter) & 7) == 0)
      Sprite_CheckDamageToLink(k);
    Chicken_IncrSubtype2(k, 4);
  } else {
    sprite_health[k] = 255;
    if (sprite_B[k] >= 35)
      Cucco_SummonAvenger(k);
    if (sprite_F[k] != 0) {
      sprite_F[k] = 0;
      if (sprite_B[k] < 35) {
        sprite_B[k]++;
        BawkBawk(k);
      }
      sprite_ai_state[k] = 2;
    }
    Sprite_CheckDamageFromLink(k);
    switch (sprite_ai_state[k]) {
    case 0: Cucco_Calm(k); break;
    case 1: Chicken_Hopping(k); break;
    case 2: Cucco_Flee(k); break;
    case 3: Cucco_Carried(k); break;
    }
  }
}

/*
 * Cucco_Calm — Idle state. On delay 0, pick a random 16-point velocity
 * (kSpriteKeese_Tab2/Tab3 sin/cos) and a 16..47-frame walk timer.
 * Animates at graphics 0 (standing pose). Sprite_ReturnIfLifted exits
 * early if Link is currently holding the Cucco.
 */
void Cucco_Calm(int k) {  // 86a67f
  if (sprite_delay_main[k] == 0) {
    int j = GetRandomNumber() & 0xf;
    sprite_x_vel[k] = kSpriteKeese_Tab2[j];
    sprite_y_vel[k] = kSpriteKeese_Tab3[j];
    sprite_delay_main[k] = (GetRandomNumber() & 0x1f) + 0x10;
    sprite_ai_state[k]++;
  }
  sprite_graphics[k] = 0;
  Sprite_ReturnIfLifted(k);
}

/*
 * Chicken_Hopping — Hop state. Apply z gravity (-2 per frame); on landing
 * (z negative), schedule 32-frame idle and reset z_vel to 10 for the
 * landing micro-hop. On wall hit while moving, return to calm.
 */
void Chicken_Hopping(int k) {  // 86a6b1
  if ((k ^ frame_counter) & 1 && Cucco_DoMovement_XY(k))
    sprite_ai_state[k] = 0;
  Sprite_MoveZ(k);
  sprite_z_vel[k] -= 2;
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    if (sprite_delay_main[k] == 0) {
      sprite_delay_main[k] = 32;
      sprite_ai_state[k] = 0;
    }
    sprite_z_vel[k] = 10;
  }
  Chicken_IncrSubtype2(k, 4);
}

/*
 * Cucco_Flee — Panic-flee state. Every 32 frames project speed-toward-Link
 * and NEGATE it (so the cucco runs away). Always show the "!!" distress
 * sprite via Cucco_DrawPANIC and pin z to 0 (no hopping during flee).
 */
void Cucco_Flee(int k) {  // 86a6fc
  Sprite_ReturnIfLifted(k);
  Cucco_DoMovement_XY(k);
  sprite_z[k] = 0;
  if (!((k ^ frame_counter) & 0x1f)) {
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLink(k, 16);
    sprite_x_vel[k] = -pt.x;
    sprite_y_vel[k] = -pt.y;
  }
  Chicken_IncrSubtype2(k, 5);
  Cucco_DrawPANIC(k);
}

/* Cucco_DrawPANIC — Draw the "!!" distress overlay (a sprite of two
 * exclamation marks) above the cucco. Animation pulses by frame_counter. */
void Cucco_DrawPANIC(int k) {  // 86a727
  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  Sprite_DrawDistress_custom(info.x, info.y, frame_counter);
}

/*
 * Cucco_Carried — "Stuck on Link's head" state. Apply z motion; on wall
 * hit while in motion, reverse velocity (escape attempt) and damp speed
 * by 1/4 each iteration; on landing (z negative), eject the cucco into
 * flee state with negative-Link-speed velocity.
 */
void Cucco_Carried(int k) {  // 86a78e
  Sprite_MoveZ(k);
  if (Cucco_DoMovement_XY(k)) {
    sprite_x_vel[k] = -sprite_x_vel[k];
    sprite_y_vel[k] = -sprite_y_vel[k];
    Sprite_MoveXY(k);
    Sprite_HalveSpeed_XY(k);
    Sprite_HalveSpeed_XY(k);
    BawkBawk(k);
  }
  sprite_z_vel[k]--;
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    sprite_ai_state[k] = 2;
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLink(k, 16);
    sprite_x_vel[k] = -pt.x;
    sprite_y_vel[k] = -pt.y;
    Chicken_IncrSubtype2(k, 5);
    Cucco_DrawPANIC(k);
  } else {
    Chicken_IncrSubtype2(k, 4);
  }
}

/* Cucco_DoMovement_XY — Single-step move + return collision mask. */
uint8 Cucco_DoMovement_XY(int k) {  // 86a7bb
  Sprite_MoveXY(k);
  return Sprite_CheckTileCollision(k);
}

/*
 * Cucco_SummonAvenger — Every 16 frames (outdoors only), spawn an
 * "avenger" cucco from a random off-screen position computed by adding
 * a random value to BG2HOFS/VOFS_copy2. The bits in `t` pick whether the
 * spawn is off the X or Y edge (and which side via kChicken_Avenger).
 * The avenger gets sprite_C=1 and Link-speed velocity so it dive-bombs.
 */
void Cucco_SummonAvenger(int k) {  // 86a7d3
  static const uint8 kChicken_Avenger[2] = {0, 0xff};
  if ((k ^ frame_counter) & 0xf | player_is_indoors)
    return;
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamicallyEx(k, 0xB, &info, 10);
  if (j < 0)
    return;
  SpriteSfx_QueueSfx3WithPan(j, 0x1e);
  sprite_C[j] = 1;
  uint8 t = GetRandomNumber();
  uint16 x = BG2HOFS_copy2, y = BG2VOFS_copy2;
  if (t & 2)
    x += t, y += kChicken_Avenger[t & 1];
  else
    y += t, x += kChicken_Avenger[t & 1];
  Sprite_SetX(j, x);
  Sprite_SetY(j, y);
  Sprite_ApplySpeedTowardsLink(j, 32);
  BawkBawk(k);
}

/* BawkBawk — The famous "BAWK!" cucco SFX (0x30) panned at the cucco. */
void BawkBawk(int k) {  // 86a84c
  SpriteSfx_QueueSfx2WithPan(k, 0x30);
}

/*
 * Sprite_17_Hoarder — Rupee-crab (the rupee-thief enemy). 2 sub-states:
 *   ai_state 0 : "Covered" — pretends to be a rock with a rupee underneath.
 *                On Link approach, scuttles toward Link and reveals the
 *                rupee, then despawns into an Ancilla.
 *   ai_state 1+: "Frantic" — actively running away with the rupees.
 */
void Sprite_17_Hoarder(int k) {  // 86a86c
  if (sprite_ai_state[k])
    Sprite_Hoarder_Frantic(k);
  else
    Sprite_Hoarder_Covered(k);
}

/*
 * Sprite_Hoarder_Covered — Disguised rupee-crab. Look for Link in a
 * (0x60 wide x 0x40 tall) approach box; on entry, scuttle toward him for
 * 32 frames using kRupeeCoveredGrab_Xvel/Yvel + 4-frame animation cycle.
 * When killed (or after the lift state ends), transmute to type 0xec
 * (ancilla splash) and spawn a green rupee (type 0x3e) so dropping a
 * rock kicks the rupee out. The "Sprite_ReturnIfLiftedPermissive" path
 * is used so lifting is allowed even when Link doesn't own the glove
 * (some hoarder types are pre-glove pickups).
 */
void Sprite_Hoarder_Covered(int k) {  // 86a874
  static const uint8 kRupeeCoveredGrab_Gfx[4] = {3, 4, 5, 4};
  static const int8 kRupeeCoveredGrab_Xvel[4] = {-12, 12, 0, 0};
  static const int8 kRupeeCoveredGrab_Yvel[4] = {0, 0, -12, 12};
  CoveredRupeeCrab_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  sprite_graphics[k] = 0;
  PointU8 pt;
  uint8 dir = Sprite_DirectionToFaceLink(k, &pt);
  if (sprite_delay_main[k])
    goto lbl;
  if ((uint8)(pt.y + 0x30) < 0x60 && (uint8)(pt.x + 0x20) < 0x40) {
    sprite_delay_main[k] = 32;
lbl:sprite_x_vel[k] = kRupeeCoveredGrab_Xvel[dir];
    sprite_y_vel[k] = kRupeeCoveredGrab_Yvel[dir];
    if (!sprite_wallcoll[k])
      Sprite_MoveXY(k);
    Sprite_CheckTileCollision2(k);
    Sprite_CheckDamageFromLink(k);
    sprite_graphics[k] = kRupeeCoveredGrab_Gfx[++sprite_subtype2[k] >> 1 & 3];
  }
  if (sprite_type[k] != 0x3e || link_item_gloves >= 1)
    Sprite_ReturnIfLiftedPermissive(k);  // note, dont ret
  if (sprite_state[k] != 9) {
    sprite_C[k] = (sprite_type[k] == 0x17) ? 2 : 1;
    sprite_type[k] = 0xec;
    sprite_oam_flags[k] &= ~1;
    sprite_graphics[k] = 0;
    SpriteSpawnInfo info;
    int j = Sprite_SpawnDynamically(k, 0x3e, &info);
    if (j >= 0) {
      Sprite_SetSpawnedCoordinates(j, &info);
      sprite_flags2[j] &= ~0x80;
      sprite_delay_aux2[j] = 128;
      sprite_oam_flags[j] = 9;
      sprite_ai_state[j] = 9;
    }
  }
}

/*
 * Sprite_Hoarder_Frantic — Active fleeing rupee-crab. Velocity in
 * diagonal cardinals (kRupeeCrab_Xvel/Yvel). On wall hit, randomly pick a
 * new diagonal direction (16-frame post-hit cooldown delay_aux4).
 * Every 32 frames re-project NEGATIVE Link-speed (run away).
 *
 * Rupee scatter: sprite_G counts up. At G==192 (~5 sec) the crab dies
 * and drops a single green rupee (type 0xd9). Every 16 frames in between
 * it drops sub-rupees: green (0xd9) for the lower-tier hoarder, blue
 * (0xdb) for the higher-tier hoarder (head_dir == 6).
 */
void Sprite_Hoarder_Frantic(int k) {  // 86a91d
  static const uint8 kRupeeCrab_Gfx[4] = {0, 1, 0, 1};
  static const uint8 kRupeeCrab_OamFlags[4] = {0, 0, 0x40, 0};
  static const int8 kRupeeCrab_Xvel[4] = {-16, 16, -16, 16};
  static const int8 kRupeeCrab_Yvel[4] = {-16, -16, 16, 16};

  SpriteDraw_SingleLarge(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  Sprite_CheckDamageFromLink(k);
  if (!sprite_delay_aux2[k])
    Sprite_CheckDamageToLink(k);
  int j = ++sprite_subtype2[k] >> 1 & 3;
  sprite_graphics[k] = kRupeeCrab_Gfx[j];
  sprite_oam_flags[k] = sprite_oam_flags[k] & ~0x40 | kRupeeCrab_OamFlags[j];
  if (sprite_wallcoll[k]) {
    sprite_delay_aux4[k] = 16;
    j = GetRandomNumber() & 3;
    sprite_x_vel[k] = kRupeeCrab_Xvel[j];
    sprite_y_vel[k] = kRupeeCrab_Yvel[j];
  } else {
    Sprite_MoveXY(k);
  }
  Sprite_CheckTileCollision2(k);
  if (!sprite_delay_aux4[k] && !((k ^ frame_counter) & 31)) {
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLink(k, 16);
    sprite_y_vel[k] = -pt.y;
    sprite_x_vel[k] = -pt.x;
  }
  if (frame_counter & 1)
    return;

  int end;
  uint8 type;
  if (++sprite_G[k] == 192) {
    sprite_delay_main[k] = 15;
    sprite_state[k] = 6;
    sprite_flags2[k] += 4;
    end = 1;
    type = 0xd9;
  } else {
    if (sprite_G[k] & 15)
      return;
    end = 0;
    type = sprite_head_dir[k] == 6 ? 0xdb : 0xd9;
  }
  SpriteSpawnInfo info;
  j = Sprite_SpawnDynamicallyEx(k, type, &info, end);
  if (j >= 0) {
    sprite_head_dir[k]++;
    Sprite_SetSpawnedCoordinates(j, &info);
    Sprite_SetX(j, info.r0_x + 8);
    sprite_z_vel[j] = 32;
    sprite_delay_aux4[j] = 16;
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLink(j, 16);
    sprite_y_vel[j] = ~pt.y;
    sprite_x_vel[j] = ~pt.x;
    SpriteSfx_QueueSfx3WithPan(k, 0x30);
  }
}

/*
 * CoveredRupeeCrab_Draw — Render the disguised hoarder. 2-tile composite
 * (rock + sub-tile). Skip rendering entirely during a mid-fade
 * (byte_7E0FC6 >= 3). For Sprite_17 (small hoarder), substitute chr 0x44
 * with a different rock variant via the r7 offset; the second tile shows
 * a peek of rupee underneath via the per-frame Y-offset table.
 */
void CoveredRupeeCrab_Draw(int k) {  // 86aa48
  static const int8 kCoveredRupeeCrab_DrawY[12] = {0, 0, 0, -3, 0, -5, 0, -6, 0, -6, 0, -6};
  static const uint8 kCoveredRupeeCrab_DrawChar[12] = {0x44, 0x44, 0xe8, 0x44, 0xe8, 0x44, 0xe6, 0x44, 0xe8, 0x44, 0xe6, 0x44};
  static const uint8 kCoveredRupeeCrab_DrawFlags[12] = {0, 0xc, 3, 0xc, 3, 0xc, 3, 0xc, 3, 0xc, 0x43, 0xc};
  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  if (byte_7E0FC6 >= 3)
    return;
  OamEnt *oam = GetOamCurPtr();
  uint8 r7 = (sprite_type[k] == 0x17) ? 2 : 0;
  uint8 r6 = sprite_graphics[k] * 2;
  for (int i = 1; i >= 0; i--, oam++) {
    int j = i + r6;
    uint8 ch = kCoveredRupeeCrab_DrawChar[j];
    SetOamHelper0(oam, info.x, info.y + kCoveredRupeeCrab_DrawY[j],
                  ch + (ch == 0x44 ? r7 : 0),
                  (info.flags & ~1) | kCoveredRupeeCrab_DrawFlags[j], 2);
  }
}

/*
 * Sprite_EC_ThrownItem — Generic throwable scenery sprite (pots, signs,
 * grass, etc. that Link picks up and tosses). Uses a custom OAM region
 * (slot 0x2c + (k & 3)) when sprite-sort is enabled so multiple thrown
 * items don't fight for slot priority. sprite_C selects the item type:
 *   >= 6 : Large 4-tile item (use SpriteDraw_ThrownItem_Gigantic).
 *   else : Single 16x16 tile with palette pulled from kThrowableScenery_
 *          Char (Light/Dark world variant) + kThrowableScenery_Flags.
 * The slot's flags inherit the bottom nibble of the chosen flag so the
 * lift animation matches the picked-up palette.
 *
 * sprite_state == 9 runs the throw physics (ThrowableScenery_InteractWith-
 * SpritesAndTiles) which handles arc, collision, and shatter.
 */
void Sprite_EC_ThrownItem(int k) {  // 86aae0
  if (byte_7E0FC6 < 3) {
    if (sort_sprites_setting && sprite_floor[k]) {
      int spr_slot = 0x2c + (k & 3);
      oam_cur_ptr = 0x0800 + spr_slot * 4;
      oam_ext_cur_ptr = 0x0A20 + spr_slot;
    }
    sprite_ignore_projectile[k] = sprite_state[k];
    if (sprite_C[k] >= 6) {
      SpriteDraw_ThrownItem_Gigantic(k);
    } else {
      SpriteDraw_SingleLarge(k);
      OamEnt *oam = GetOamCurPtr();
      uint8 t = player_is_indoors + is_in_dark_world;
      int j = sprite_C[k];
      oam->charnum = kThrowableScenery_Char[j + ((t >= 2) ? 6 : 0)];
      oam->flags = (oam->flags & 0xf0) | kThrowableScenery_Flags[j];
      sprite_oam_flags[k] = (sprite_oam_flags[k] & 0xc0) | (oam->flags & 0xf);
    }
  }
  if (sprite_state[k] == 9) {
    if (Sprite_ReturnIfInactive(k))
      return;
    ThrowableScenery_InteractWithSpritesAndTiles(k);
  }
}

/*
 * SpriteDraw_ThrownItem_Gigantic — Render the large (4-tile + 3-tile
 * shadow) variant for skull and tombstone pickups. The 4 tiles are
 * stamped from the kThrowableScenery_DrawLarge_* tables; the 3 shadow
 * tiles use chr 0x6c (the wide cast-shadow tile) at the ground Y.
 */
void SpriteDraw_ThrownItem_Gigantic(int k) {  // 86ab76
  PrepOamCoordsRet info;
  sprite_oam_flags[k] = kThrowableScenery_DrawLarge_OamFlags[sprite_C[k] - 6];

  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;

  OamEnt *oam = GetOamCurPtr();
  for (int i = 3; i >= 0; i--, oam++) {
    SetOamHelper0(oam, info.x + kThrowableScenery_DrawLarge_X[i], info.y + kThrowableScenery_DrawLarge_Y[i],
                  0x4a, kThrowableScenery_DrawLarge_Flags[i] | info.flags, 2);
  }
  Oam_AllocateFromRegionB(12);
  oam = GetOamCurPtr();
  info.y = Sprite_GetY(k) - BG2VOFS_copy2;
  for (int i = 2; i >= 0; i--, oam++) {
    SetOamHelper0(oam, info.x + kThrowableScenery_DrawLarge_X2[i], info.y + 12, 0x6c, 0x24, 2);
  }
}

/*
 * ThrowableScenery_ScatterIntoDebris — Shatter the thrown item into 4
 * smaller debris sprites at the 4 diagonal offsets (kScatterDebris_X/Y).
 *   Gigantic variant (C >= 6): spawn 4 type-0xec child sprites with z
 *                              inherited so the debris falls with the
 *                              source. Children get C=1, scheduled for
 *                              breakage, and palette 12 (or default for
 *                              the very largest C >= 7 variant).
 *   Standard variant         : Steal a garnish slot, emit garnish type 22
 *                              (single-frame shatter dust) at the source
 *                              with 31-frame countdown.
 */
void ThrowableScenery_ScatterIntoDebris(int k) {  // 86ac41
  if (!sign8(sprite_C[k]) && sprite_C[k] >= 6) {
    for (int i = 3; i >= 0; i--) {
      SpriteSpawnInfo info;
      int j = Sprite_SpawnDynamically(k, 0xec, &info);
      if (j >= 0) {
        sprite_z[j] = sprite_z[k];
        Sprite_SetX(j, info.r0_x + kScatterDebris_X[i]);
        Sprite_SetY(j, info.r2_y + kScatterDebris_Y[i]);
        sprite_C[j] = 1;
        Sprite_ScheduleForBreakage(j);
        sprite_oam_flags[j] = (sprite_C[k] < 7) ? 12 : 0;
      }
    }
    sprite_state[k] = 0;
  } else {
    sprite_state[k] = 0;
    PrepOamCoordsRet info;
    if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
      return;
    int j = 29;
    while (garnish_type[j--] && j >= 0) {}
    j++;
    garnish_type[j] = 22;
    garnish_active = 22;
    garnish_x_lo[j] = sprite_x_lo[k];
    garnish_x_hi[j] = sprite_x_hi[k];
    uint16 y = Sprite_GetY(k) - sprite_z[k] + 0x10;
    garnish_y_lo[j] = (uint8)y;
    garnish_y_hi[j] = (uint8)(y >> 8);
    garnish_oam_flags[j] = info.flags;
    garnish_floor[j] = sprite_floor[k];
    garnish_countdown[j] = 31;
    garnish_sprite[j] = sprite_C[k];
  }
}

/*
 * Sprite_TransmuteToBomb — Convert an existing slot to a flying bomb
 * (type 0x4a, C=1, 255-frame fuse, flags3=0x18, palette 8, 0 HP). Used
 * by Hinox, Sluggula, Bomb Guard, etc.
 */
void Sprite_TransmuteToBomb(int k) {  // 86ad50
  sprite_type[k] = 0x4a;
  sprite_C[k] = 1;
  sprite_delay_aux1[k] = 255;
  sprite_flags3[k] = 0x18;
  sprite_oam_flags[k] = 8;
  sprite_health[k] = 0;
}

/*
 * Sprite_28_DarkWorldHintNPC — Dark World hint-NPC family. Per subtype2,
 * shows one of 5 hint stories with the same general layout: idle prompt
 * 0xfe (subtype2 0..2), 0x149 (subtype2 3 — the witch on the floor), or
 * subtype2 4 (Mad Batter — hops with z animation). Each variant has its
 * own custom hint message (0xff/0x101/0x102/0x103).
 *
 * Common flow (states 0..2):
 *   0 Idle      : DarkWorldHintNPC_Idle (msg 0xfe).
 *   1 Payment   : 20-rupee charge via DarkWorldHintNPC_HandlePayment;
 *                 on success show the personalized hint; else show
 *                 the refusal 0x100.
 *   2 Reward    : DarkWorldHintNPC_RestoreHealth (refill 10 hearts) and
 *                 return to idle.
 *
 * Subtype 4 (Mad Batter): adds a z-hop animation (z_vel oscillates around
 * z=4) and 2-frame walk cycle via frame_counter parity.
 */
void Sprite_28_DarkWorldHintNPC(int k) {  // 86ad6f
  StoryTeller_1_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);
  if (!sprite_delay_main[k])
    sprite_graphics[k] = frame_counter >> 4 & 1;

  switch(sprite_subtype2[k]) {
  case 0:
    switch (sprite_ai_state[k]) {
    case 0: DarkWorldHintNPC_Idle(k); break;
    case 1:
      if (choice_in_multiselect_box == 0 && DarkWorldHintNPC_HandlePayment()) {
        Sprite_ShowMessageUnconditional(0xff);
        sprite_ai_state[k] = 2;
      } else {
        Sprite_ShowMessageUnconditional(0x100);
        sprite_ai_state[k] = 0;
      }
      break;
    case 2: DarkWorldHintNPC_RestoreHealth(k); break;
    }
    break;
  case 1:
    switch (sprite_ai_state[k]) {
    case 0: DarkWorldHintNPC_Idle(k); break;
    case 1:
      if (choice_in_multiselect_box == 0 && DarkWorldHintNPC_HandlePayment()) {
        Sprite_ShowMessageUnconditional(0x101);
        sprite_ai_state[k] = 2;
      } else {
        Sprite_ShowMessageUnconditional(0x100);
        sprite_ai_state[k] = 0;
      }
      break;
    case 2: DarkWorldHintNPC_RestoreHealth(k); break;
    }
    break;
  case 2:
    switch (sprite_ai_state[k]) {
    case 0: DarkWorldHintNPC_Idle(k); break;
    case 1:
      if (choice_in_multiselect_box == 0 && DarkWorldHintNPC_HandlePayment()) {
        Sprite_ShowMessageUnconditional(0x102);
        sprite_ai_state[k] = 2;
      } else {
        Sprite_ShowMessageUnconditional(0x100);
        sprite_ai_state[k] = 0;
      }
      break;
    case 2: DarkWorldHintNPC_RestoreHealth(k); break;
    }
    break;
  case 3:
    if (sprite_delay_main[k] == 0) {
      if ((frame_counter & 0x3f) == 0)
        sprite_oam_flags[k] ^= 0x40;
      if (GetRandomNumber() == 0)
        sprite_delay_main[k] = 32;
    }
    Sprite_ShowSolicitedMessage(k, 0x149);
    break;
  case 4:
    sprite_graphics[k] = frame_counter >> 1 & 1;
    Sprite_MoveZ(k);
    if (sign8(sprite_z[k]))
      sprite_z[k] = 0;
    sprite_z_vel[k] += (sprite_z[k] >= 4) ? -1 : 1;
    switch (sprite_ai_state[k]) {
    case 0: DarkWorldHintNPC_Idle(k); break;
    case 1:
      if (choice_in_multiselect_box == 0 && DarkWorldHintNPC_HandlePayment()) {
        Sprite_ShowMessageUnconditional(0x103);
        sprite_ai_state[k] = 2;
      } else {
        Sprite_ShowMessageUnconditional(0x100);
        sprite_ai_state[k] = 0;
      }
      break;
    case 2: DarkWorldHintNPC_RestoreHealth(k); break;
    }
    break;
  }
}

/* DarkWorldHintNPC_Idle — Show greeting msg 0xfe; on dismiss advance to
 * payment state. */
void DarkWorldHintNPC_Idle(int k) {  // 86ada7
  if (Sprite_ShowSolicitedMessage(k, 0xfe) & 0x100)
    sprite_ai_state[k] = 1;
}

/* DarkWorldHintNPC_RestoreHealth — Top off hearts (~10), return to idle. */
void DarkWorldHintNPC_RestoreHealth(int k) {  // 86adb5
  link_hearts_filler = 0xa0;
  sprite_ai_state[k] = 0;
}

/* DarkWorldHintNPC_HandlePayment — Deduct 20 rupees if affordable; return
 * true on success. */
bool DarkWorldHintNPC_HandlePayment() {  // 86aeab
  if (link_rupees_goal < 20)
    return false;
  link_rupees_goal -= 20;
  return true;
}

/*
 * StoryTeller_1_Draw — 1-tile NPC composite drawn via the deferred-OAM
 * path. 10 entries cover 5 subtype2 stories * 2 walk frames. The pose
 * index is (subtype2 * 2 + graphics).
 */
void StoryTeller_1_Draw(int k) {  // 86af1a
  static const DrawMultipleData kStoryTeller_Dmd[10] = {
    {0, 0, 0x0a4a, 2},
    {0, 0, 0x4a6e, 2},
    {0, 0, 0x0a24, 2},
    {0, 0, 0x4a24, 2},
    {0, 0, 0x0804, 2},
    {0, 0, 0x4804, 2},
    {0, 0, 0x0a6a, 2},
    {0, 0, 0x0a6c, 2},
    {0, 0, 0x0a0e, 2},
    {0, 0, 0x0a2e, 2},
  };
  PrepOamCoordsRet info;
  Sprite_DrawMultiplePlayerDeferred(k, &kStoryTeller_Dmd[sprite_subtype2[k] * 2 + sprite_graphics[k]], 1, &info);
  SpriteDraw_Shadow(k, &info);
}

/*
 * Sprite_2E_FluteKid — Flute kid encounters. head_dir picks sub-mode:
 *   0 + subtype2 0 : FluteKid_Human       (Light World boy w/ flute).
 *   0 + subtype2 1 : Sprite_FluteKid_Stumpy (Dark World tree stump that
 *                                            holds the flute).
 *   1              : Sprite_FluteKid_Quaver (musical note projectile that
 *                                            the boy emits while playing).
 */
void Sprite_2E_FluteKid(int k) {  // 86af3b
  switch (sprite_head_dir[k]) {
  case 0:
    switch (sprite_subtype2[k]) {
    case 0: FluteKid_Human(k); break;
    case 1: Sprite_FluteKid_Stumpy(k); break;
    }
    break;
  case 1: Sprite_FluteKid_Quaver(k); break;
  }
}

/*
 * FluteKid_Human — Light World Flute Kid (plays on the bench). 4-state:
 *   0 Wait         : Idle ambient music 11. On Link approach (within
 *                    proximity) or once Link owns the flute (item >= 2):
 *                    arm phase-out animation (state 1, 176-frame timer),
 *                    increment byte_7E0FDD beacon (flute-kid disappeared),
 *                    immobilize Link. Periodically spawn note Quavers.
 *   1 PrepPhaseOut : On expiry, kick off translucency-swap palette filter
 *                    + play SFX 0x33 (vanish sound).
 *   2 PhaseOut     : Run palette filter every 16 frames until it reaches 0.
 *   3 PhasedOut    : Restore palette, kill slot, unfreeze Link.
 *
 * The 4-frame "playing flute" animation runs throughout via
 * frame_counter >> 5.
 */
void FluteKid_Human(int k) {  // 86af51
  if (sprite_ai_state[k] != 3)
    sprite_C[k] = FluteBoy_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (!sprite_C[k] && !sprite_B[k]) {
    sound_effect_ambient = 11;
    sprite_B[k] = 11;
  }
  sprite_graphics[k] = frame_counter >> 5 & 1;
  switch (sprite_ai_state[k]) {
  case 0:  // wait
    if (link_item_flute >= 2 || FluteBoy_CheckIfPlayerClose(k)) {
      sprite_ai_state[k] = 1;
      sprite_D[k]++;
      byte_7E0FDD++;
      sprite_delay_main[k] = 176;
      flag_is_link_immobilized = 1;
    }
    if (!sprite_delay_main[k]) {
      sprite_delay_main[k] = 25;
      FluteKid_SpawnQuaver(k);
    }
    break;
  case 1:  // prep phase out
    flag_is_link_immobilized = 1;
    if (!sprite_delay_main[k]) {
      TS_copy = 2;
      CGADSUB_copy = 48;
      BYTE(palette_filter_countdown) = 0;
      BYTE(darkening_or_lightening_screen) = 0;
      Palette_AssertTranslucencySwap();
      sprite_ai_state[k] = 2;
      sound_effect_ambient = 128;
      SpriteSfx_QueueSfx2WithPan(k, 0x33);
    }
    break;
  case 2:  // phase out
    if (!(frame_counter & 15)) {
      PaletteFilter_SP5F();
      if (!BYTE(palette_filter_countdown))
        sprite_ai_state[k] = 3;
    }
    break;
  case 3:  // phased out
    PaletteFilter_RestoreSP5F();
    Palette_RevertTranslucencySwap();
    sprite_state[k] = 0;
    flag_is_link_immobilized = 0;
    break;
  }
}

/*
 * Sprite_FluteKid_Stumpy — Dark World "tree stump" version of the Flute
 * Kid (the kid was transformed into a stump). 6-state machine:
 *   0 IdleByFluteLevel : Dialogue branches on link_item_flute & 3:
 *                          0 supplicate   (msg 0xe5, advance to state 1)
 *                          1 give flute   (msg 0xe8)
 *                          2 thanks       (msg 0xe9, advance to state 3)
 *                          3 already gave (msg)
 *   1 GrantShovelChoice: Yes -> show acceptance (msg 0xe6, state 2),
 *                        No -> bounce back to idle (msg 0xe7).
 *   2 GrantShovel      : Give shovel (item 0x13), return to idle.
 *   3 WaitForMusic     : When Link holds flute and presses Y, snap into
 *                        playing state (state 4); pause music, play
 *                        ambient flute SFX 23, immobilize Link.
 *   4 PlayFluteAnim    : Animate via kFluteAardvark_Gfx/Delay (20-entry
 *                        choreographed note pattern); -1 sentinel ends.
 *                        Plays note SFX 0x33 every 3rd frame.
 *   5 Done             : Hold final pose; set progress bit 8.
 */
void Sprite_FluteKid_Stumpy(int k) {  // 86b040
  static const int8 kFluteAardvark_Gfx[20] = {
    1, 1, 1, 1, 2, 1, 2, 1, 2, 1, 2, 3, 2, 3, 2, 3, 2, 3, 2, -1,
  };
  static const int8 kFluteAardvark_Delay[19] = {
    -1, -1, -1, 16, 2, 12, 6, 8, 10, 4, 14, 2, 10, 6, 6, 10, 2, 14,  2,
  };
  FluteAardvark_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  switch (sprite_ai_state[k]) {
  case 0:  //
    switch (link_item_flute & 3) {
    case 0:  // supplicate
      if (Sprite_ShowSolicitedMessage(k, 0xe5) & 0x100)
        sprite_ai_state[k] = 1;
      break;
    case 1:  // give me flute
      Sprite_ShowSolicitedMessage(k, 0xe8);
      break;
    case 2:  // thanks
      sprite_graphics[k] = 1;
      if (Sprite_ShowSolicitedMessage(k, 0xe9) & 0x100)
        sprite_ai_state[k] = 3;
      break;
    case 3:  // already did
      sprite_graphics[k] = 3;
      break;
    }
    break;
  case 1:  //
    if (!choice_in_multiselect_box) {
      Sprite_ShowMessageUnconditional(0xe6);
      sprite_ai_state[k] = 2;
    } else {
      Sprite_ShowMessageUnconditional(0xe7);
      sprite_ai_state[k] = 0;
    }
    break;
  case 2:  // grant shovel
    item_receipt_method = 0;
    Link_ReceiveItem(0x13, 0);
    sprite_ai_state[k] = 0;
    break;
  case 3:  // wait for music
    if (hud_cur_item == kHudItem_Flute && joypad1H_last & 0x40) {
      sprite_ai_state[k] = 4;
      music_control = 0xf2;
      sound_effect_1 = 0;
      sound_effect_ambient = 23;
      flag_is_link_immobilized++;
    }
    break;
  case 4:  //
    if (!sprite_delay_main[k]) {
      if (sprite_A[k] >= 3)
        SpriteSfx_QueueSfx2WithPan(k, 0x33);
      int j = sprite_A[k]++;
      if (kFluteAardvark_Gfx[j] >= 0) {
        sprite_graphics[k] = kFluteAardvark_Gfx[j];
        sprite_delay_main[k] = kFluteAardvark_Delay[j];
      } else {
        music_control = 0xf3;
        sprite_ai_state[k] = 5;
        flag_is_link_immobilized = 0;
      }
    }
    break;
  case 5:  // done
    sprite_graphics[k] = 3;
    sram_progress_indicator_3 |= 8;
    break;
  }
}

/*
 * Sprite_FluteKid_Quaver — Musical note projectile emitted by the flute
 * kid. Simple drift: every other frame nudge x_vel by ±1 driven by
 * (frame_counter >> 5 ^ slot) parity, creating a meander. delay_main
 * countdown self-destructs the note.
 */
void Sprite_FluteKid_Quaver(int k) {  // 86b173
  SpriteDraw_SingleSmall(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_MoveXY(k);
  Sprite_MoveZ(k);
  if (!sprite_delay_main[k])
    sprite_state[k] = 0;
  if (!(frame_counter & 1))
    sprite_x_vel[k] += (frame_counter >> 5 ^ cur_object_index) & 1 ? -1 : 1;
}

/*
 * FluteKid_SpawnQuaver — Spawn one note (sprite type 0x2e, head_dir=1)
 * just above the kid with 8 z velocity and a 96-frame lifespan.
 */
void FluteKid_SpawnQuaver(int k) {  // 86b1a5
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x2e, &info);
  if (j >= 0) {
    Sprite_SetX(j, info.r0_x + 4);
    Sprite_SetY(j, info.r2_y - 4);
    sprite_head_dir[j] = 1;
    sprite_z_vel[j] = 8;
    sprite_delay_main[j] = 96;
    sprite_ignore_projectile[j] = 96;
  }
}

/*
 * Sprite_1A_Smithy — Smithy NPC family dispatcher. subtype2:
 *   0 Main       : The Dwarven Smith at the anvil (tempering quest).
 *   1 Spark      : Anvil sparks particles.
 *   2 Frog       : The Frog Smith (Dark World transformation).
 *   3 Homecoming : Smith walking back to his anvil after escort.
 */
void Sprite_1A_Smithy(int k) {  // 86b1ee
  switch (sprite_subtype2[k]) {
  case 0: Smithy_Main(k); break;
  case 1: Smithy_Spark(k); break;
  case 2: Smithy_Frog(k); break;
  case 3: Smithy_Homecoming(k); break;
  }
}

/*
 * Smithy_Homecoming — Smith returning to his anvil after Link delivers
 * him. 2-state:
 *   0 ApproachTheBench : 3-step scripted patrol (104-frame walk south, 12
 *                        frames east, stop). On final step, advance to
 *                        Thankful.
 *   1 Thankful         : Static barrier, show solicited msg 0xe3, unfreeze
 *                        Link, set sram bit 32 (smith delivered).
 */
void Smithy_Homecoming(int k) {  // 86b1fd
  ReturningSmithy_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  switch(sprite_ai_state[k]) {
  case 0: { // ApproachTheBench
    static const int8 kReturningSmithy_Delay[3] = {104, 12, 0};
    static const int8 kReturningSmithy_Dir[3] = {0, 2, -1};
    static const int8 kReturningSmithy_Xvel[4] = {0, 0, -13, 13};
    static const int8 kReturningSmithy_Yvel[4] = {-13, 13, 0, 0};
    Sprite_MoveXY(k);
    sprite_graphics[k] = frame_counter >> 3 & 1;
    if (sprite_delay_main[k])
      return;
    int j = sprite_A[k]++;
    sprite_delay_main[k] = kReturningSmithy_Delay[j];
    if ((j = kReturningSmithy_Dir[j]) >= 0) {
      sprite_D[k] = j;
      sprite_x_vel[k] = kReturningSmithy_Xvel[j];
      sprite_y_vel[k] = kReturningSmithy_Yvel[j];
    } else {
      sprite_ai_state[k] = 1;
    }
    break;
  }
  case 1: // Thankful
    Sprite_BehaveAsBarrier(k);
    Sprite_ShowSolicitedMessage(k, 0xe3);
    flag_is_link_immobilized = 0;
    sprite_D[k] = 1;
    sram_progress_indicator_3 |= 32;
    break;
  }
}

/*
 * Smithy_Frog — Smith's frog form (Dark World, before transformation
 * back). Hopping body with z gravity (-2/frame, bounce 16 z_vel). On
 * Link contact run dialog 0xe1; on yes, become follower slot 7 and clear
 * the slot. The "zelda bug: doesn't save X" note is preserved from the
 * original — the original code didn't snapshot the X-coordinate of the
 * frog, so when Link drops the follower back into the world, position
 * can drift slightly.
 */
void Smithy_Frog(int k) {  // 86b274
  SmithyFrog_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);
  sprite_z_vel[k] -= 2;
  Sprite_MoveZ(k);
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    sprite_z_vel[k] = 16;
  }
  if (!sprite_ai_state[k]) {
    sprite_D[k] = 1;
    if (Sprite_ShowSolicitedMessage(k, 0xe1) & 0x100)
      sprite_ai_state[k] = 1;
  } else {
    follower_indicator = 7;
    LoadFollowerGraphics();
    Sprite_BecomeFollower(k);  // zelda bug: doesn't save X
    sprite_state[k] = 0;
  }
}

/*
 * ReturningSmithy_Draw — Render the homecoming Smith as a single tile.
 * 4 directions * 2 walk frames = 8 entries; the dma_var7 byte selects
 * which CHR tile gets uploaded to VRAM this frame via DMA.
 */
void ReturningSmithy_Draw(int k) {  // 86b308
  static const DrawMultipleData kReturningSmithy_Dmd[8] = {
    {0, 0, 0x4122, 2},
    {0, 0, 0x0122, 2},
    {0, 0, 0x4122, 2},
    {0, 0, 0x0122, 2},
    {0, 0, 0x0122, 2},
    {0, 0, 0x0122, 2},
    {0, 0, 0x4122, 2},
    {0, 0, 0x4122, 2},
  };
  static const uint8 kReturningSmithy_Dma[8] = {0xc0, 0xc0, 0xa0, 0xa0, 0x80, 0x60, 0x80, 0x60};
  int j = sprite_D[k] * 2 + sprite_graphics[k];
  PrepOamCoordsRet info;
  BYTE(dma_var7) = kReturningSmithy_Dma[j];
  Sprite_DrawMultiplePlayerDeferred(k, &kReturningSmithy_Dmd[j], 1, &info);
  SpriteDraw_Shadow(k, &info);
}

/* SmithyFrog_Draw — Single-tile frog pose (chr 0xc8) with shadow. */
void SmithyFrog_Draw(int k) {  // 86b339
  static const DrawMultipleData kSmithyFrog_Dmd[1] = {
    {0, 0, 0x00c8, 2},
  };
  PrepOamCoordsRet info;
  Sprite_DrawMultiplePlayerDeferred(k, kSmithyFrog_Dmd, 1, &info);
  SpriteDraw_Shadow(k, &info);
}

/*
 * Smithy_Main — Dwarven Smith. Per-frame: apply z gravity. Hammer
 * animation runs when EITHER smith is in a hammering state (5/7/9) or
 * both are idle (i|j==0). 8-frame animation cycle via kSmithy_Gfx/_B
 * picks chr and delay-to-next-frame; on frame 3, spawn the anvil spark
 * (Smithy_SpawnSpark) and play clang SFX 0x5.
 *
 * 12-state conversation:
 *   0 ConversationStart    : If listening for hammer (Link bonking with
 *                            hammer), show msg 0xe4 and start spark anim.
 *                            Otherwise branch by sram bit 0x20 (smith
 *                            delivered): dialog 0xd8 (tempering offer)
 *                            vs 0xdf (pre-rescue, "I lost my friend").
 *                            If carrying the smith as follower (8) and
 *                            Link is north of the bench, run msg 0xe0
 *                            (drop instruction).
 *   1 ProvideTemperingChoice: Yes -> show 0xd9 (tempering details).
 *                            No  -> dismiss 0xdc.
 *   2 HandleTemperingChoice : Yes -> if sword level < 3, show price (0xda)
 *                            and advance; else "already best" (0xdb).
 *                            No  -> dismiss.
 *   3 HandleTemperingCost   : Confirm Y AND >= 10 rupees, deduct 10,
 *                            show 0xdd, advance both smiths to state 5,
 *                            set sword to 255 (temporary "no sword"),
 *                            set sram bit 0x80.
 *   4/5 TemperingSword     : Listen for hammer + continue spark anim.
 *                            On area-change show msg 0xde and advance;
 *                            else loop msg 0xe2.
 *   6 GiveTemperedSword    : Reset both smiths, give Tempered Sword
 *                            (item 2), clear progress bit 0x80.
 *   7/8/9                  : Idle holding poses.
 *   10 Smithy_SpawnFriend  : Spawn the dwarf pal sprite at Link's
 *                            position with subtype2=3, clear follower
 *                            slot.
 *   11 CopiouslyThankful   : Show msg 0xe3 (thanks loop).
 */
void Smithy_Main(int k) {  // 86b34e
  Smithy_Draw(k);
  sprite_z_vel[k] -= 2;
  Sprite_MoveZ(k);
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    sprite_z_vel[k] = 0;
  }
  if (Sprite_ReturnIfInactive(k))
    return;

  int j = sprite_ai_state[sprite_E[k]];
  int i = sprite_ai_state[k];
  if ((j == 5 || j == 7 || j == 9 || i == 5 || i == 7 || i == 9 || (i | j) == 0) && sprite_B[k]-- == 0) {
    static const uint8 kSmithy_Gfx[8] = {0, 1, 2, 3, 3, 2, 1, 0};
    static const uint8 kSmithy_B[8] = {24, 4, 1, 16, 16, 5, 10, 16};
    j = sprite_A[k];
    sprite_A[k] = j + 1 & 7;
    sprite_graphics[k] = kSmithy_Gfx[j];
    sprite_B[k] = kSmithy_B[j];
    if (j == 1)
      sprite_z_vel[k] = 16;
    if (j == 3) {
      Smithy_SpawnSpark(k);
      SpriteSfx_QueueSfx2WithPan(k, 0x5);
    }
  }
  switch(sprite_ai_state[k]) {
  case 0:  // ConversationStart
    sprite_C[k] = 0;
    if (follower_indicator != 8) {
      if (Smithy_ListenForHammer(k)) {
        Sprite_ShowMessageUnconditional(0xe4);
        sprite_delay_aux1[k] = 96;
        sprite_C[k]++;
      } else if (sram_progress_indicator_3 & 0x20) {
        if (Sprite_ShowSolicitedMessage(k, 0xd8) & 0x100) {
          sprite_ai_state[k]++;
          sprite_C[k]++;
        }
      } else {
        Sprite_ShowSolicitedMessage(k, 0xdf);
      }
    } else {
      if (BYTE(link_y_coord) < 0xc2) {
        Sprite_ShowMessageUnconditional(0xe0);
        sprite_ai_state[k] = 10;
        flag_is_link_immobilized++;
      }
    }
    break;
  case 1:  // ProvideTemperingChoice
    if (!choice_in_multiselect_box) {
      Sprite_ShowMessageUnconditional(0xd9);
      sprite_ai_state[k] = 2;
    } else {
      Sprite_ShowMessageUnconditional(0xdc);
      sprite_ai_state[k] = 0;
    }
    break;
  case 2:  // HandleTemperingChoice
    if (choice_in_multiselect_box == 0) {
      if (link_sword_type < 3) {
        Sprite_ShowMessageUnconditional(0xda);
        sprite_ai_state[k] = 3;
      } else {
        Sprite_ShowMessageUnconditional(0xdb);
        sprite_ai_state[k] = 0;
      }
    } else {
      Sprite_ShowMessageUnconditional(0xdc);
      sprite_ai_state[k] = 0;
    }
    break;
  case 3:  // HandleTemperingCost
    if (choice_in_multiselect_box || link_rupees_goal < 10) {
      Sprite_ShowMessageUnconditional(0xdc);
      sprite_ai_state[k] = 0;
    } else {
      link_rupees_goal -= 10;
      Sprite_ShowMessageUnconditional(0xdd);
      sprite_ai_state[sprite_E[k]] = 5;
      sprite_ai_state[k] = 5;
      flag_overworld_area_did_change = 0;
      link_sword_type = 255;
      sram_progress_indicator_3 |= 128;
    }
    break;
  case 4:  // TemperingSword
  case 5:  //
    sprite_C[k] = 0;
    if (Smithy_ListenForHammer(k)) {
      Sprite_ShowMessageUnconditional(0xe4);
      sprite_delay_aux1[k] = 96;
      sprite_C[k]++;
    } else if (flag_overworld_area_did_change) {
      if (Sprite_ShowSolicitedMessage(k, 0xde) & 0x100) {
        sprite_ai_state[k]++;
        sprite_graphics[k] = 4;
      }
    } else {
      Sprite_ShowSolicitedMessage(k, 0xe2);
    }
    break;
  case 6:  // Smithy_GiveTemperedSword
    sprite_ai_state[k] = 0;
    sprite_ai_state[sprite_E[k]] = 0;
    item_receipt_method = 0;
    Link_ReceiveItem(2, 0);
    sram_progress_indicator_3 &= ~0x80;
    break;
  case 7:  //
  case 8:  //
  case 9:  //
    break;
  case 10: { // Smithy_SpawnFriend
    SpriteSpawnInfo info;
    int j = Sprite_SpawnDynamically(k, 0x1a, &info);
    if (j >= 0) {
      Sprite_SetX(j, link_x_coord);
      Sprite_SetY(j, link_y_coord);
      sprite_subtype2[j] = 3;
      sprite_ignore_projectile[j] = 3;
    }
    sprite_ai_state[k] = 11;
    follower_indicator = 0;
    sprite_graphics[k] = 4;
    break;
  }
  case 11:  // Smithy_CopiouslyThankful
    Sprite_ShowSolicitedMessage(k, 0xe3);
    break;

  }
}

/*
 * Smithy_ListenForHammer — Edge-trigger detector: returns true only when
 * the player is actively swinging the hammer at the smith (cooldown done,
 * hammer is the equipped item, mid-swing animation state, on the same
 * layer as the smith).
 */
bool Smithy_ListenForHammer(int k) {  // 86b43d
  return sprite_delay_aux1[k] == 0 && hud_cur_item == kHudItem_Hammer && (link_item_in_hand & 2) && player_handler_timer == 2 && Sprite_CheckDamageToLink_same_layer(k);
}

/*
 * Smithy_SpawnDwarfPal — Spawn the second smith slot (the dwarf pal)
 * adjacent to the first via +0x2c X offset. D=1 marks "the second smith";
 * A=4 sets the starting graphics frame.
 */
int Smithy_SpawnDwarfPal(int k) {  // 86b5a6
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x1a, &info);
  if (j < 0)
    return j;
  Sprite_SetX(j, info.r0_x);
  Sprite_SetY(j, info.r2_y);
  sprite_x_lo[j] += 0x2C;
  sprite_D[j] = 1;
  sprite_A[j] = 4;
  sprite_ignore_projectile[j] = 4;
  return j;
}

/*
 * Smithy_Draw — Render the smith as a 2-tile composite (head/torso +
 * arm). 5 graphics frames * 2 directions (D=0 dwarf, D=1 dwarf-pal) *
 * 2 tiles = 20 entries.
 */
void Smithy_Draw(int k) {  // 86b673
  static const DrawMultipleData kSmithy_Dmd[20] = {
    {  1,   0, 0x4040, 2},
    {-11, -10, 0x4060, 2},
    { -1,   0, 0x0040, 2},
    { 11, -10, 0x0060, 2},
    {  1,   0, 0x4040, 2},
    { -3, -14, 0x4044, 2},
    { -1,   0, 0x0040, 2},
    {  3, -14, 0x0044, 2},
    {  1,   0, 0x4042, 2},
    { 11, -10, 0x0060, 2},
    { -1,   0, 0x0042, 2},
    {-11, -10, 0x4060, 2},
    {  1,   0, 0x4042, 2},
    { 13,   2, 0x4062, 2},
    { -1,   0, 0x0042, 2},
    {-13,   2, 0x0062, 2},
    {  0,   0, 0x4064, 2},
    {  0,   0, 0x4062, 2},
    {  0,   0, 0x0064, 2},
    {  0,   0, 0x0064, 2},
  };
  PrepOamCoordsRet info;
  Sprite_DrawMultiplePlayerDeferred(k, &kSmithy_Dmd[sprite_graphics[k] * 4 + sprite_D[k] * 2], 2, &info);
  SpriteDraw_Shadow(k, &info);
}

/*
 * Smithy_Spark — Anvil spark particle. 7-frame fountain animation via
 * kSmithySpark_Gfx (with -1 sentinel termination). Used as a one-shot
 * effect when the hammer hits the anvil.
 */
void Smithy_Spark(int k) {  // 86b6a3
  static const int8 kSmithySpark_Gfx[7] = {0, 1, 2, 1, 2, 1, -1};
  static const int8 kSmithySpark_Delay[6] = {4, 1, 3, 2, 1, 1};
  SmithySpark_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (!sprite_delay_main[k]) {
    int j = sprite_A[k];
    sprite_A[k] = j + 1 & 7;
    if (sign8(kSmithySpark_Gfx[j])) {
      sprite_state[k] = 0;
      return;
    }
    sprite_graphics[k] = kSmithySpark_Gfx[j];
    sprite_delay_main[k] = kSmithySpark_Delay[j];
  }
}

/*
 * Smithy_SpawnSpark — Spawn an anvil-spark particle. Subtype2=1 routes
 * the new slot to Smithy_Spark. Per-smith X offset: ±15 px so sparks
 * fly out the side of the hammer (D=0 dwarf hits from the right, D=1
 * dwarf pal hits from the left).
 */
void Smithy_SpawnSpark(int k) {  // 86b6cd
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x1a, &info);
  if (j >= 0) {
    Sprite_SetX(j, info.r0_x);
    Sprite_SetY(j, info.r2_y);
    sprite_x_lo[j] += sprite_D[k] ? -15 : 15;
    sprite_y_lo[j] += 2;
    sprite_subtype2[j] = 1;
  }
}

/*
 * SmithySpark_Draw — Render the spark as 2 OAM tiles from region B. Three
 * graphics frames (anvil glow + radiating shards); each frame draws a
 * larger 16x16 anvil tile plus a small 8x8 shard offset.
 */
void SmithySpark_Draw(int k) {  // 86b72c
  Oam_AllocateFromRegionB(8);
  static const DrawMultipleData kSmithySpark_Dmd[6] = {
    { 0,  3, 0x41aa, 2},
    { 0, -1, 0x41aa, 2},
    {-4,  0, 0x0190, 0},
    {12,  0, 0x4190, 0},
    {-5, -2, 0x0191, 0},
    {13, -2, 0x0191, 0},
  };
  Sprite_DrawMultiple(k, &kSmithySpark_Dmd[sprite_graphics[k] * 2], 2, NULL);
}

/*
 * Sprite_1B_Arrow — Enemy arrow / javelin projectile (also reused for
 * Moblin spears via sprite_A=3). Two phases:
 *   sprite_state == 9 (active flight): delay_main counts down; if >= 32
 *     and even, randomly perturb direction so the arrow can be wind-
 *     blown. On Link hit (CheckDamageToLink_same_layer) deal damage. On
 *     wall hit: sprite_A != 0 (a passing arrow) schedules breakage with
 *     metal-clink SFX 0x5; sprite_A == 0 (Moblin spear etc.) ricochets
 *     with bonk SFX 0x8 and 48-frame post-bounce dwell.
 *   ai_state == 0 (just spawned, mid-recoil): apply ricochet velocity,
 *     z_vel = 24, 255-frame airborne lifespan. On each tick, pick the
 *     spin direction from kEnemyArrow_Dirs[delay >> 3 & 3] for the
 *     tumbling animation. Apply z gravity; on landing kill slot.
 */
void Sprite_1B_Arrow(int k) {  // 86b754
  int j;
  static const int8 kEnemyArrow_Xvel[8] = {0, 0, 16, 16, 0, 0, -16, -16};
  static const int8 kEnemyArrow_Yvel[8] = {16, 16, 0, 0, -16, -16, 0, 0};
  static const uint8 kEnemyArrow_Dirs[4] = {0, 2, 1, 3};

  EnemyArrow_Draw(k);
  if (Sprite_ReturnIfPaused(k))
    return;
  if (sprite_state[k] == 9) {
    j = sprite_delay_main[k];
    if (j != 0) {
      if (--j == 0) {
        sprite_state[k] = 0;
      } else if (j >= 32 && !(j & 1)) {
        j = (frame_counter << 1 & 4) | sprite_D[k];
        sprite_x_vel[k] = kEnemyArrow_Xvel[j];
        sprite_y_vel[k] = kEnemyArrow_Yvel[j];
        Sprite_MoveXY(k);
      }
      return;
    }
    Sprite_CheckDamageToLink_same_layer(k);
    if (sprite_E[k] == 0 && Sprite_CheckTileCollision(k)) {
      if (sprite_A[k]) {
        SpriteSfx_QueueSfx2WithPan(k, 0x5);
        Sprite_ScheduleForBreakage(k);
        Sprite_PlaceWeaponTink(k);
      } else {
        sprite_delay_main[k] = 48;
        sprite_A[k] = 2;
        SpriteSfx_QueueSfx2WithPan(k, 0x8);
      }
    } else {
      Sprite_MoveXY(k);
    }
  } else {
    if (sprite_ai_state[k] == 0) {
      Sprite_ApplyRicochet(k);
      sprite_z_vel[k] = 24;
      sprite_delay_main[k] = 255;
      sprite_ai_state[k]++;
      sprite_hit_timer[k] = 0;
    }
    sprite_D[k] = kEnemyArrow_Dirs[sprite_delay_main[k] >> 3 & 3];
    Sprite_MoveZ(k);
    Sprite_MoveXY(k);
    sprite_z_vel[k] -= 2;
    if (sign8(sprite_z[k]))
      sprite_state[k] = 0;
  }
}

/*
 * EnemyArrow_Draw — 2-tile arrow composite. The Char/Flags tables are
 * 32 entries (8 directions * 2 sub-poses * 2 tile-types — arrow vs
 * javelin via sprite_A * 8 offset). The 4-direction Draw_X/Y array gives
 * the two-tile arrow head + shaft positions in each cardinal direction.
 */
void EnemyArrow_Draw(int k) {  // 86b867
  static const int16 kEnemyArrow_Draw_X[8] = {-8, 0, 0, 8, 0, 0, 0, 0};
  static const int16 kEnemyArrow_Draw_Y[8] = {0, 0, 0, 0, -8, 0, 0, 8};
  static const uint8 kEnemyArrow_Draw_Char[32] = {
    0x3a, 0x3d, 0x3d, 0x3a, 0x2a, 0x2b, 0x2b, 0x2a, 0x7c, 0x6c, 0x6c, 0x7c, 0x7b, 0x6b, 0x6b, 0x7b,
    0x3a, 0x3b, 0x3b, 0x3a, 0x2a, 0x3c, 0x3c, 0x2a, 0x81, 0x80, 0x80, 0x81, 0x91, 0x90, 0x90, 0x91,
  };
  static const uint8 kEnemyArrow_Draw_Flags[32] = {
    8,    8, 0x48, 0x48, 8, 8, 0x88, 0x88,    9, 0x49, 9, 0x49,    9, 0x89, 9, 0x89,
    8, 0x88, 0xc8, 0x48, 8, 8, 0x88, 0x88, 0x49, 0x49, 9,    9, 0x89, 0x89, 9,    9,
  };

  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  OamEnt *oam = GetOamCurPtr();
  uint8 r6 = sprite_D[k] * 2, r7 = sprite_A[k] * 8;
  for (int i = 1; i >= 0; i--, oam++) {
    int j = r6 + i;
    SetOamHelper0(oam, info.x + kEnemyArrow_Draw_X[j], info.y + kEnemyArrow_Draw_Y[j],
                  kEnemyArrow_Draw_Char[j + r7], kEnemyArrow_Draw_Flags[j + r7] | info.flags, 0);
  }
}

/*
 * Sprite_1E_CrystalSwitch — Crystal switch (the blue/orange room-state
 * crystal Link hits with the sword). Per-tick:
 *   Update OAM palette via kCrystalSwitchPal[orange_blue_barrier_state & 1].
 *   On Link contact, repel dash (it's a hard barrier).
 *   Every 31 frames, spawn a sparkle garnish.
 *   Damage acceptance: only when button_b_frames < 9 (mid-swing of the
 *     sword); on a hit, sprite_F counts down from 11. When it reaches 0,
 *     toggle the orange/blue state, enter the dungeon "state change"
 *     submodule 22, play SFX 0x25 (the iconic flip sound).
 */
void Sprite_1E_CrystalSwitch(int k) {  // 86b8d0
  sprite_oam_flags[k] = sprite_oam_flags[k] & ~0xe | kCrystalSwitchPal[orange_blue_barrier_state & 1];
  Oam_AllocateDeferToPlayer(k);
  SpriteDraw_SingleLarge(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_CheckDamageToLink_same_layer(k)) {
    Sprite_NullifyHookshotDrag();
    link_speed_setting = 0;
    Sprite_RepelDash();
  }
  if (sprite_delay_main[k] == 0) {
    Sprite_GarnishSpawn_Sparkle(k, frame_counter & 7, GetRandomNumber() & 7);
    sprite_delay_main[k] = 31;
  }
  if (sprite_F[k] == 0) {
    if (sign8(button_b_frames - 9))
      Sprite_CheckDamageFromLink(k);
  } else if (sprite_F[k]-- == 11) {
    orange_blue_barrier_state ^= 1;
    submodule_index = 22;
    SpriteSfx_QueueSfx3WithPan(k, 0x25);
  }
}

/*
 * Sprite_1F_SickKid — Sick Kid NPC (Kakariko bug-net quest giver). 4-state:
 *   0 Resting : On Link contact, check empty bottle. If no bottle, show
 *               msg 0x104 ("you don't have one"). Else freeze Link and
 *               advance to perk.
 *   1 Perk    : Animate the wake-up via kBugNetKid_Gfx (8 frames with -1
 *               sentinel) and kBugNetKid_Delay (per-frame durations).
 *               On sentinel, show msg 0x105 (offer bug net), advance.
 *   2 Grant   : Give item 0x21 (bug net), unfreeze Link, advance.
 *   3 BackToRest: Show solicited msg 0x106 (thanks message) on contact;
 *               graphics 1 (the new resting-with-net pose).
 */
void Sprite_1F_SickKid(int k) {  // 86b94c
  static const int8 kBugNetKid_Gfx[8] = {0, 1, 0, 1, 0, 1, 2, -1};
  static const uint8 kBugNetKid_Delay[7] = {8, 12, 8, 12, 8, 96, 16};
  int j;
  BugNetKid_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  switch (sprite_ai_state[k]) {
  case 0:  // resting
    if (Sprite_CheckIfLinkIsBusy() || !Sprite_CheckDamageToLink_same_layer(k))
      return;
    if ((link_bottle_info[0] | link_bottle_info[1] | link_bottle_info[2] | link_bottle_info[3]) < 2) {
      Sprite_ShowSolicitedMessage(k, 0x104);
    } else {
      flag_is_link_immobilized++;
      sprite_ai_state[k] = 1;
    }
    break;
  case 1:  // perk
    if (sprite_delay_main[k])
      return;
    j = sprite_A[k];
    if (kBugNetKid_Gfx[j] >= 0) {
      sprite_graphics[k] = kBugNetKid_Gfx[j];
      sprite_delay_main[k] = kBugNetKid_Delay[j];
      sprite_A[k] = j + 1;
    } else {
      Sprite_ShowMessageUnconditional(0x105);
      sprite_ai_state[k] = 2;
    }
    break;
  case 2:  // grant
    item_receipt_method = 0;
    Link_ReceiveItem(0x21, 0);
    flag_is_link_immobilized = 0;
    sprite_ai_state[k] = 3;
    break;
  case 3:  // back to rest
    sprite_graphics[k] = 1;
    Sprite_ShowSolicitedMessage(k, 0x106);
    break;
  }
}

/*
 * Sprite_21_WaterSwitch — Water-level push switch (Swamp Palace). 3-state:
 *   0 PreparingPush : When Link is actively pushing (sprite_C set), tick
 *                     down sprite_B (48-frame countdown) and play push
 *                     SFX 0x22 every 4 frames. On expiry advance to state 1
 *                     (committed push). When Link releases, reset B to 48.
 *   1 PushingDown   : 10-step descent animation using kPushSwitch_Delay
 *                     (per-step durations) and kPushSwitch_Dir (per-step
 *                     graphics frames). On the final step, increment the
 *                     dung_flag_statechange_waterpuzzle (which toggles the
 *                     palace water level) and play SFX 0x25 (state-change
 *                     fanfare). Advance to state 2.
 *   2 Done          : Terminal state (no further input).
 */
void Sprite_21_WaterSwitch(int k) {  // 86b9fa
  PushSwitch_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  switch(sprite_ai_state[k]) {
  case 0:
    if (sprite_C[k]) {
      if (!--sprite_B[k])
        sprite_ai_state[k] = 1;
      if (!(frame_counter & 3))
        SpriteSfx_QueueSfx2WithPan(k, 0x22);
    } else {
      sprite_B[k] = 48;
    }
    break;
  case 1:
    if (!sprite_delay_main[k]) {
      static const uint8 kPushSwitch_Delay[10] = {40, 6, 3, 3, 3, 5, 1, 1, 3, 12};
      static const uint8 kPushSwitch_Dir[10] = {0, 1, 2, 3, 4, 5, 5, 6, 7, 6};
      int j = ++sprite_A[k];
      if (j == 10) {
        sprite_ai_state[k] = 2;
        dung_flag_statechange_waterpuzzle++;
        SpriteSfx_QueueSfx3WithPan(k, 0x25);
      } else {
        sprite_delay_main[k] = kPushSwitch_Delay[j];
        sprite_D[k] = kPushSwitch_Dir[j];
        SpriteSfx_QueueSfx2WithPan(k, 0x22);
      }
    }
    break;
  case 2:
    break;
  }
}

/*
 * PushSwitch_Draw — Render the push-switch with 8 different draw phases
 * (40-entry OAM table = 8 phases * 5 tiles each, indexed by sprite_D).
 * The switch comprises 5 OAM tiles: 4 for the post body + 1 anchor tile.
 *
 * Push deflection: r1 = sprite_B >> 2 & 3 picks how far the post is
 * currently depressed; xv/yv shift the body tiles up/down/left/right
 * based on the push direction so the post visually compresses.
 *
 * Palette swap: when palette_swap_flag is set (translucency mode), OR
 * the OAM flags with 0xe so the post draws in the alternate palette.
 *
 * Push detection: On same-layer Link contact, check if Link is overlapping
 * a per-direction hitbox (kPushSwitch_WH gives box width/height for each
 * of the 8 directions); if so AND Link is facing the right way (e.g.
 * facing 4 to push a north-facing post), set sprite_C++ to register the
 * push tick. Also repel-dash so Link can't bypass the switch by dashing.
 */
void PushSwitch_Draw(int k) {  // 86bb22
  static const OamEntSigned kPushSwitch_Oam[40] = {
    {  4, 20, 0xdc, 0x20},
    {  4, 12, 0xdd, 0x20},
    {  4, 12, 0xdd, 0x20},
    {  4, 12, 0xdd, 0x20},
    {  0,  0, 0xca, 0x20},
    {  3, 12, 0xdd, 0x20},
    {  3, 20, 0xdc, 0x20},
    {  3, 20, 0xdc, 0x20},
    {  3, 20, 0xdc, 0x20},
    {  0,  0, 0xca, 0x20},
    { -8,  8, 0xea, 0x20},
    {  0,  8, 0xeb, 0x20},
    { -8, 16, 0xfa, 0x20},
    {  0, 16, 0xfb, 0x20},
    {  0,  0, 0xca, 0x20},
    {-12,  4, 0xcc, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    {  0,  0, 0xca, 0x20},
    {-10,  4, 0xcc, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    {  0,  0, 0xca, 0x20},
    { -8,  4, 0xcc, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    {  0,  0, 0xca, 0x20},
    {  4,  3, 0xe2, 0x20},
    { -6,  4, 0xcc, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    {  0,  0, 0xca, 0x20},
    {  4,  3, 0xf1, 0x20},
    { -6,  4, 0xcc, 0x20},
    { -4,  4, 0xcd, 0x20},
    { -4,  4, 0xcd, 0x20},
    {  0,  0, 0xca, 0x20},
  };
  static const uint8 kPushSwitch_WH[16] = {8, 6, 0x10, 0x10, 0x10, 8, 0x10, 8, 0x10, 8, 0x10, 8, 0x10, 3, 0x10, 8};
  Oam_AllocateDeferToPlayer(k);
  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  uint8 flags;
  sprite_oam_flags[k] = flags = palette_swap_flag ? sprite_oam_flags[k] | 0xe : sprite_oam_flags[k] & ~0xe;
  uint8 r1 = sprite_B[k] >> 2 & 3;

  oam_cur_ptr += 4, oam_ext_cur_ptr += 1;

  OamEnt *oam = GetOamCurPtr();
  memcpy(oam, &kPushSwitch_Oam[sprite_D[k] * 5], 20);

  uint8 xv = -r1 + BYTE(dungmap_var7);
  uint8 yv = HIBYTE(dungmap_var7) - (r1 >> 1);

  oam[0].x += xv;
  oam[1].x += xv;
  oam[2].x += xv;
  oam[3].x += xv;
  oam[4].x += BYTE(dungmap_var7);

  oam[0].y += yv;
  oam[1].y += yv;
  oam[2].y += yv;
  oam[3].y += yv;
  oam[4].y += HIBYTE(dungmap_var7);

  oam[0].flags |= flags;
  oam[1].flags |= flags;
  oam[2].flags |= flags;
  oam[3].flags |= flags;
  oam[4].flags |= flags;

  uint8 *big = &g_ram[oam_ext_cur_ptr];
  big[0] = big[1] = big[2] = big[3] = 0;
  big[4] = 2;

  Sprite_CorrectOamEntries(k, 4, 0xff);

  if (sprite_floor[k] == link_is_on_lower_level) {
    sprite_C[k] = 0;
    int d = sprite_D[k];
    int x = Sprite_GetX(k) + (int8)kPushSwitch_Oam[d * 4].x;
    int y = Sprite_GetY(k) + (int8)kPushSwitch_Oam[d * 4].y;

    SpriteHitBox hb;
    hb.r4_spr_xlo = x;
    hb.r10_spr_xhi = x >> 8;
    hb.r5_spr_ylo = y;
    hb.r11_spr_yhi = y >> 8;
    hb.r6_spr_xsize = kPushSwitch_WH[d * 2 + 0];
    hb.r7_spr_ysize = kPushSwitch_WH[d * 2 + 1];
    Link_SetupHitBox(&hb);
    if (CheckIfHitBoxesOverlap(&hb)) {
      uint16 oldy = Sprite_GetY(k);
      Sprite_SetY(k, oldy + 19);
      uint8 new_dir = Sprite_DirectionToFaceLink(k, NULL);
      Sprite_SetY(k, oldy);
      if (new_dir == 0 && link_direction_facing == 4)
        sprite_C[k]++;
    } else {
      if (!Sprite_CheckDamageToLink_same_layer(k))
        return;
    }
    Sprite_NullifyHookshotDrag();
    link_speed_setting = 0;
    Sprite_RepelDash();
  }
}

/*
 * Sprite_39_Locksmith — Locksmith NPC (carries the Sahasrahla's house key
 * to Link). 6-state machine:
 *   0 Chilling         : Idle dialog msg 0x107. Probe west cell for a
 *                        valid tile so the locksmith can transition out
 *                        of the way; on success, advance. If another
 *                        follower already exists, jump to state 5 (silence).
 *   1 TransitionToTagalong: Promote to follower slot 9, init follower
 *                          graphics, kill the slot.
 *   2 OfferChest        : Show msg 0x109 (offer to deliver the chest);
 *                        the "follower_dropped" variant uses Solicited
 *                        (Link can walk away), the on-contact variant
 *                        triggers automatically.
 *   3 ReactToSecretKeeping: Yes path: drop chest, give item 0x16
 *                          (purple chest), set progress bit 0x10, advance
 *                          to state 4. No path: show msg 0x10a, return.
 *                          Already-dropped path: show msg 0x10c.
 *   4 PromiseReminder   : Loop msg 0x10b (silent thanks).
 *   5 SilenceOtherTagalong: Loop msg 0x107 (can't help while busy).
 */
void Sprite_39_Locksmith(int k) {  // 86bcac
  uint8 bak;
  int j;

  MiddleAgedMan_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);

  switch (sprite_ai_state[k]) {
  case 0:  // chilling
    Sprite_ShowSolicitedMessage(k, 0x107);
    bak = sprite_x_lo[k];
    sprite_x_lo[k] -= 16;
    Sprite_Get16BitCoords(k);
    sprite_x_vel[k] = 1;
    sprite_y_vel[k] = 1;
    if (!Sprite_CheckTileCollision(k)) {
      sprite_ai_state[k]++;
      if (follower_indicator != 0)
        sprite_ai_state[k] = 5;
    }
    sprite_x_lo[k] = bak;
    break;
  case 1:  // transition to tagalong
    follower_indicator = 9;
    tagalong_var5 = 0;
    LoadFollowerGraphics();
    Follower_Initialize();
    word_7E02CD = 0x40;
    sprite_state[k] = 0;
    break;
  case 2:  // offer chest
    if (Sprite_CheckIfLinkIsBusy())
      return;
    if (follower_dropped) {
      j = Sprite_ShowSolicitedMessage(k, 0x109);
    } else {
      j = Sprite_ShowMessageOnContact(k, 0x109);
    }
    if (j & 0x100)
      sprite_ai_state[k] = 3;
    break;
  case 3:  // react to secret keeping
    if (!choice_in_multiselect_box) {
      if (follower_dropped) {
        Sprite_ShowMessageUnconditional(0x10c);
        sprite_ai_state[k] = 2;
      } else {
        item_receipt_method = 0;
        Link_ReceiveItem(0x16, 0);
        sram_progress_indicator_3 |= 0x10;
        sprite_ai_state[k] = 4;
        follower_indicator = 0;
      }
    } else {
      Sprite_ShowMessageUnconditional(0x10a);
      sprite_ai_state[k] = 2;
    }
    break;
  case 4:  // promise reminder
    Sprite_ShowSolicitedMessage(k, 0x10b);
    break;
  case 5:  // silence other tagalong
    Sprite_ShowSolicitedMessage(k, 0x107);
    break;
  }
}

/*
 * MiddleAgedMan_Draw — Render the locksmith (and other middle-aged-man
 * NPCs) as a 2-tile head+body composite. Deferred-OAM so Link draws on top.
 */
void MiddleAgedMan_Draw(int k) {  // 86bdac
  static const DrawMultipleData kMiddleAgedMan_Dmd[2] = {
    {0, -8, 0x00ea, 2},
    {0,  0, 0x00ec, 2},
  };
  PrepOamCoordsRet info;
  Sprite_DrawMultiplePlayerDeferred(k, &kMiddleAgedMan_Dmd[0], 2, &info);
  SpriteDraw_Shadow(k, &info);
}

/*
 * Sprite_2B_Hobo — Hobo NPC family dispatcher (Lost Woods Hobo and his
 * effects). subtype2:
 *   0 Bum     : The hobo himself at the campfire.
 *   1 Bubble  : Sleep "Zzz" bubble particle.
 *   2 Fire    : Campfire flame.
 *   3 Smoke   : Smoke puff rising from the fire.
 */
void Sprite_2B_Hobo(int k) {  // 86bdc1
  switch (sprite_subtype2[k]) {
  case 0:
    Sprite_Hobo_Bum(k);
    break;
  case 1:
    Sprite_Hobo_Bubble(k);
    break;
  case 2:
    Sprite_Hobo_Fire(k);
    break;
  case 3:
    Sprite_Hobo_Smoke(k);
    break;
  }
}

/*
 * Sprite_Hobo_Bum — Hobo NPC (the bottle-quest giver in Lost Woods).
 * 4-state interaction:
 *   0 Sleeping   : Idle; respawn sleep-bubble every 160 frames. On Y-press
 *                  while overlapping, wake the bubble (delay=4 to make it
 *                  drift away), freeze Link, advance to wake-up.
 *   1 WakeUp     : 7-frame yawn-and-rise animation via kHobo_Gfx/Delay.
 *                  On completion show msg 0xd7 (give bottle dialog) and
 *                  advance to grant.
 *   2 GrantBottle: Give item 0x16 (empty bottle), set screen-event bit
 *                  0x20 + sram progress bit 1.
 *   3 BackToSleep: Unfreeze Link, restart bubble spawn cycle.
 */
void Sprite_Hobo_Bum(int k) {  // 86bdd0
  Hobo_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  sprite_flags4[k] = 3;
  if (Sprite_CheckDamageToLink_same_layer(k)) {
    Sprite_NullifyHookshotDrag();
    link_speed_setting = 0;
    Link_CancelDash();
  }
  switch(sprite_ai_state[k]) {
  case 0:  // sleeping
    sprite_flags4[k] = 7;
    if (Sprite_CheckDamageToLink_same_layer(k) && (filtered_joypad_L & 0x80)) {
      sprite_ai_state[k] = 1;
      int j = sprite_E[k];
      sprite_delay_main[j] = 4;
      flag_is_link_immobilized = 1;
    }
    if (!sprite_delay_aux2[k]) {
      sprite_delay_aux2[k] = 160;
      sprite_E[k] = Hobo_SpawnBubble(k);
    }
    break;
  case 1: // wake up
    if (!sprite_delay_main[k]) {
      static const int8 kHobo_Gfx[7] = {0, 1, 0, 1, 0, 1, 2};
      static const int8 kHobo_Delay[7] = {6, 2, 6, 6, 2, 100, 30};
      int j = sprite_A[k];
      if (j != 7) {
        sprite_graphics[k] = kHobo_Gfx[j];
        sprite_delay_main[k] = kHobo_Delay[j];
        sprite_A[k]++;
      } else {
        Sprite_ShowMessageUnconditional(0xd7);
        sprite_ai_state[k] = 2;
      }
    }
    break;
  case 2:  // grant bottle
    sprite_ai_state[k] = 3;
    sprite_graphics[k] = 1;
    save_ow_event_info[BYTE(overworld_screen_index)] |= 0x20;
    item_receipt_method = 0;
    Link_ReceiveItem(0x16, 0);
    sram_progress_indicator_3 |= 1;
    break;
  case 3:  // back to sleep
    flag_is_link_immobilized = 0;
    sprite_graphics[k] = 0;
    if (!sprite_delay_main[k]) {
      sprite_delay_main[k] = 160;
      Hobo_SpawnBubble(k);
    }
    break;
  }
}

/*
 * SpritePrep_Hobo_SpawnSmoke — Helper called from SpritePrep_Hobo to seed
 * the campfire smoke trail. Spawns subtype2=0 (the Hobo Bum) sprites at
 * the source — confusingly named: this actually pre-populates the slot
 * pool, not smoke; the actual smoke spawn happens via Hobo_SpawnSmoke.
 */
void SpritePrep_Hobo_SpawnSmoke(int k) {  // 86be9d
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x2b, &info);
  if (j >= 0) {
    Sprite_SetSpawnedCoordinates(j, &info);
    sprite_subtype2[j] = 0;
    sprite_ignore_projectile[j] = 0;
  }
}

/*
 * Sprite_Hobo_Bubble — Sleep "Zzz" bubble that floats above the hobo. Two
 * graphics phases (frame_counter >> 4): 2/3 alternating. Once delay_aux1
 * empties, advance to a third graphics frame (the burst) and start rising
 * (Sprite_MoveZ). Self-destructs on delay_main 0.
 */
void Sprite_Hobo_Bubble(int k) {  // 86beb4
  Oam_AllocateFromRegionC(4);
  SpriteDraw_SingleSmall(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  sprite_graphics[k] = (frame_counter >> 4 & 1) + 2;
  if (!sprite_delay_aux1[k]) {
    sprite_graphics[k]++;
    Sprite_MoveZ(k);
    if (!sprite_delay_main[k])
      sprite_state[k] = 0;
  }
  if (sprite_delay_main[k] < 4)
    sprite_graphics[k] = 3;
}

/*
 * Hobo_SpawnBubble — Spawn the Zzz bubble subtype=1 with 2 z-vel (slow
 * rise) and 96-frame lifespan (48-frame visible + 48-frame rise). Returns
 * the child slot index so the parent can reference it (sprite_E).
 */
int Hobo_SpawnBubble(int k) {  // 86beed
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x2b, &info);
  if (j >= 0) {
    Sprite_SetSpawnedCoordinates(j, &info);
    sprite_subtype2[j] = 1;
    sprite_z_vel[j] = 2;
    sprite_delay_main[j] = 96;
    sprite_delay_aux1[j] = 96 >> 1;
    sprite_ignore_projectile[j] = 96 >> 1;
    sprite_flags2[j] = 0;
  }
  return j;
}

/*
 * Sprite_Hobo_Fire — Campfire flame. 2-frame flicker via
 * frame_counter >> 3. Every 47 frames spawn a smoke puff (Hobo_SpawnSmoke).
 * Forces left-flip off (oam_flags &= ~0x40).
 */
void Sprite_Hobo_Fire(int k) {  // 86bf15
  SpriteDraw_SingleSmall(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  sprite_graphics[k] = frame_counter >> 3 & 1;
  sprite_oam_flags[k] &= ~0x40;
  if (!sprite_delay_main[k]) {
    Hobo_SpawnSmoke(k);
    sprite_delay_main[k] = 47;
  }
}

/*
 * SpritePrep_Hobo_SpawnFire — Spawn the campfire at the fixed Lost Woods
 * coordinate (0x0194, 0x003f) with subtype2=2 (fire variant), palette 2.
 */
void SpritePrep_Hobo_SpawnFire(int k) {  // 86bf4b
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x2b, &info);
  if (j >= 0) {
    Sprite_SetX(j, 0x194);
    Sprite_SetY(j, 0x03f);
    sprite_subtype2[j] = 2;
    sprite_ignore_projectile[j] = 2;
    sprite_flags2[j] = 0;
    sprite_oam_flags[j] = sprite_oam_flags[j] & ~0xE | 2;
  }
}

/*
 * Sprite_Hobo_Smoke — Rising smoke puff. Single 8x8 tile (graphics 6).
 * Cycles through 4 hflip/vflip combinations via kHoboSmoke_OamFlags
 * (frame_counter >> 4) for puff variation. Drift via Sprite_MoveXY +
 * Sprite_MoveZ; self-destruct on delay_main 0.
 */
void Sprite_Hobo_Smoke(int k) {  // 86bf81
  static const uint8 kHoboSmoke_OamFlags[4] = {0, 64, 128, 192};
  sprite_graphics[k] = 6;
  SpriteDraw_SingleSmall(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_MoveXY(k);
  Sprite_MoveZ(k);
  sprite_oam_flags[k] = sprite_oam_flags[k] & 0x3f | kHoboSmoke_OamFlags[frame_counter >> 4 & 3];
  if (!sprite_delay_main[k])
    sprite_state[k] = 0;
}

/*
 * Hobo_SpawnSmoke — Spawn one rising smoke puff (subtype2=3) just above
 * (Y-4) the fire with 7 z-vel and 96-frame lifetime.
 */
void Hobo_SpawnSmoke(int k) {  // 86bfaf
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x2b, &info);
  if (j >= 0) {
    Sprite_SetSpawnedCoordinates(j, &info);
    Sprite_SetY(j, info.r2_y - 4);
    sprite_subtype2[j] = 3;
    sprite_z_vel[j] = 7;
    sprite_delay_main[j] = 96;
    sprite_ignore_projectile[j] = 96;
    sprite_flags2[j] = 0;
  }
}

/*
 * Sprite_73_UncleAndPriest — Slot reused for 3 different actors depending
 * on sprite_E (set during prep):
 *   0 Uncle           : Intro/passage cutscenes.
 *   1 Priest          : Sanctuary priest dialog.
 *   2 SanctuaryMantle : The mantle covering Zelda.
 */
void Sprite_73_UncleAndPriest(int k) {  // 86bfe0
  switch (sprite_E[k]) {
  case 0:
    Sprite_Uncle(k);
    break;
  case 1:
    Sprite_Priest(k);
    break;
  case 2:
    Sprite_SanctuaryMantle(k);
    break;
  }
}

/*
 * SpritePrep_UncleAndPriest_bounce — One-shot setup for the slot. Three
 * room-dependent branches:
 *   Room 18 (Sanctuary): Spawn the Mantle child (Priest_SpawnMantle).
 *     If progress >= 3 (chapter 3+) set the "priest met" flag and either:
 *       - sword level >= 2: D=4 (recoil pose), graphics 0, subtype2=0
 *         (priest already busy/dead).
 *       - Zelda follower (=1): set 0x4 progress + 0x20 screen bit,
 *         170-frame entrance delay, subtype2=1 (rescue cutscene).
 *       - otherwise: subtype2=2 (chill).
 *     Per-subtype Y offset (kUncleAndSage_Y).
 *   Room 4 (Link's house): If no progress bit 0x10 (haven't slept yet),
 *     X +8 align; else despawn.
 *   Other rooms: If no progress bit 1 (uncle not delivered sword yet),
 *     set D=3 + subtype2=1 (passage uncle); else despawn.
 */
void SpritePrep_UncleAndPriest_bounce(int k) {  // 86bfe5
  if (BYTE(dungeon_room_index) == 18) {
    Priest_SpawnMantle(k);
    if (sram_progress_indicator >= 3)
      sram_progress_flags |= 2;
    if (sram_progress_flags & 2) {
      sprite_state[k] = 0;
      return;
    }
    sprite_E[k] = 1;
    sprite_flags2[k] = sprite_flags2[k] & 0xf0 | 0x2;
    sprite_flags4[k] = 3;
    int j;
    if (link_sword_type >= 2) {
      sprite_D[k] = 4;
      sprite_graphics[k] = 0;
      j = 0;
    } else {
      sprite_D[k] = sprite_head_dir[k] = Sprite_DirectionToFaceLink(k, NULL) ^ 3;
      if (follower_indicator == 1) {
        sram_progress_flags |= 0x4;
        save_ow_event_info[0x1b] |= 0x20;
        sprite_delay_main[k] = 170;
        j = 1;
      } else {
        j = 2;
      }
    }
    sprite_subtype2[k] = j;
    static const int16 kUncleAndSage_Y[3] = {0, -9, 0};
    Sprite_SetX(k, Sprite_GetX(k) - 6);
    Sprite_SetY(k, Sprite_GetY(k) + kUncleAndSage_Y[j]);
    sprite_ignore_projectile[k]++;
    byte_7FFE01 = 0;
  } else if (BYTE(dungeon_room_index) == 4) {
    if (!(sram_progress_flags & 0x10))
      sprite_x_lo[k] += 8;
    else
      sprite_state[k] = 0;
  } else {
    if (!(sram_progress_flags & 1)) {
      sprite_D[k] = 3;
      sprite_subtype2[k] = 1;
    } else {
      sprite_state[k] = 0;
    }
  }
}

/*
 * SpritePrep_OldMan_bounce — Old Man on Death Mountain. Room 0xe4 (his
 * cave) uses subtype2=2 (cave variant). On overworld, if no current
 * follower: promote to follower slot 4 with graphics loaded; mirror
 * item == 2 (mirror used) kills the slot. With existing follower, despawn.
 */
void SpritePrep_OldMan_bounce(int k) {  // 86bff9
  sprite_ignore_projectile[k]++;
  if (BYTE(dungeon_room_index) == 0xe4) {
    sprite_subtype2[k] = 2;
    return;
  }
  if (follower_indicator == 0) {
    if (link_item_mirror == 2)
      sprite_state[k] = 0;
    follower_indicator = 4;
    LoadFollowerGraphics();
    follower_indicator = 0;
  } else {
    sprite_state[k] = 0;
    LoadFollowerGraphics();
  }
}

/*
 * Sprite_TutorialGuardOrBarrier — Slot reused for the intro castle-grounds
 * guards (types 0x3f/0x41 etc.) and the EvilBarrier sprite (type 0x40).
 * Type 0x40 routes to Sprite_EvilBarrier entirely.
 *
 * Guard path: D-locked pose during alert (delay_aux1 set). Graphics
 * picked from kSprite_TutorialEntities_Tab[D] for the 4-entity layout.
 * Dialog branches on overworld area:
 *   Area 0x1b (castle gate) with Y=0x50 or 0x90: special location-tied
 *     messages (msg 0xB2 for upper guard, 0xB3 for lower).
 *   Other locations: cycle through 7 dialog options indexed by
 *     byte_7E0B69 (advanced once per dismiss, wrapping 0..6).
 * Every 32 frames, snap facing toward Link; if the new direction is a
 * 90° turn, queue a 12-frame "glance" delay_aux1.
 */
void Sprite_TutorialGuardOrBarrier(int k) {  // 86bffe
  if (sprite_type[k] == 0x40) {
    Sprite_EvilBarrier(k);
    return;
  }
  int jbak = sprite_D[k];
  if (sprite_delay_aux1[k])
    sprite_D[k] = kSoldier_DirectionLockSettings[jbak];

  sprite_graphics[k] = kSprite_TutorialEntities_Tab[sprite_D[k]];
  TutorialSoldier_Draw(k);
  sprite_D[k] = jbak;

  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_CheckDamageFromLink(k);

  if (BYTE(overworld_area_index) == 0x1b && (sprite_y_lo[k] == 0x50 || sprite_y_lo[k] == 0x90)) {
    Sprite_TutorialGuard_ShowMessageOnContact(k, sprite_y_lo[k] == 0x50 ? 0xB2 : 0xB3);
  } else {
    if (Sprite_TutorialGuard_ShowMessageOnContact(k, byte_7E0B69 + 0xf)) {
      byte_7E0B69 = byte_7E0B69 != 6 ? byte_7E0B69 + 1 : 0;
    }
  }
  Sprite_CheckDamageToAndFromLink(k);
  if (((k ^ frame_counter) & 0x1f) == 0) {
    uint8 jbak = sprite_D[k];
    sprite_D[k] = Sprite_DirectionToFaceLink(k, NULL);
    if (sprite_D[k] != jbak && !((sprite_D[k] ^ jbak) & 2))
      sprite_delay_aux1[k] = 12;
  }
}

/*
 * Sprite_F2_MedallionTablet — Slot dispatch: subtype2=0 the tablet itself
 * (MedallionTablet_Main), subtype2=1 the dust cloud spawned when the
 * tablet crumbles.
 */
void Sprite_F2_MedallionTablet(int k) {  // 86c00d
  switch (sprite_subtype2[k]) {
  case 0:
    MedallionTablet_Main(k);
    break;
  case 1:
    Sprite_DustCloud(k);
    break;
  }
}

/*
 * Sprite_33_RupeePull — Pull-rupee mini-game (the rope you yank for
 * rupees in Kakariko). On entry coords cached for proximity checks. The
 * handler (see below) detects Link's yank gesture, ticks the rope-pull
 * animation, and dispenses rupees on completion.
 */
void Sprite_33_RupeePull(int k) {  // 86c017
  PrepOamCoordsRet info;
  Sprite_PrepOamCoord(k, &info);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_CheckIfLinkIsBusy())
    return;
  if (Sprite_CheckDamageToLink_same_layer(k)) {
    link_need_for_pullforrupees_sprite = 1;
    sprite_A[k] = 1;
  } else {
    if (sprite_A[k]) {
      link_need_for_pullforrupees_sprite = 0;
      if (link_state_bits & 1) {
        sprite_state[k] = 0;
        RupeePull_SpawnPrize(k);
        Sprite_SpawnPoofGarnish(k);
      }
    }
  }
}

/*
 * Sprite_14_ThievesTownGrate — Thieves' Town overworld grate. Same yank
 * mechanic as RupeePull but on release (link_state_bits & 1) triggers
 * Gargoyle's Domain opening: play SFX 0x1f, run OpenGargoylesDomain to
 * reveal the screen change, spawn a dust cloud, and despawn the grate.
 */
void Sprite_14_ThievesTownGrate(int k) {  // 86c01c
  PrepOamCoordsRet info;
  Sprite_PrepOamCoord(k, &info);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_CheckIfLinkIsBusy())
    return;
  if (Sprite_CheckDamageToLink_same_layer(k)) {
    link_need_for_pullforrupees_sprite = 1;
    sprite_A[k] = 1;
  } else {
    if (!sprite_A[k])
      return;
    link_need_for_pullforrupees_sprite = 0;
    if (!(link_state_bits & 1))
      return;
    SpriteSfx_QueueSfx2WithPan(k, 0x1f);
    OpenGargoylesDomain();
    int j = Sprite_SpawnDustCloud(k);
    Sprite_SetX(j, Sprite_GetX(k));
    Sprite_SetY(j, Sprite_GetY(k));
    sprite_state[k] = 0;
  }
}

