/*
 * Sprite_D8_Heart — Heart refill pickup. 4-phase motion:
 *   0 InitializeAscent: 18-frame z_vel=20 ascent, graphics=1 (bouncing).
 *   1 BeginDescending : Decrement z_vel each frame; at delay==0 start
 *                       descent with z_vel=253 (negative).
 *   2 GlideGroundward : Apply X-accel toward kHeartRefill_VelTarget
 *                       (-10..+10 alternating); on reaching target swap
 *                       direction (D ^= 1).
 *   3 Grounded        : Stop fully; await Link absorption.
 *
 * The MiscBugFixes guard skips a double-call to HandleAbsorptionByPlayer
 * when the heart is being dragged by a magnet ancilla, avoiding a
 * double-pickup bug.
 */
void Sprite_D8_Heart(int k) {  // 86cec0
  if (SpriteDraw_AbsorbableTransient(k, true))
    return;
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_CheckAbsorptionByPlayer(k);

  // Avoid calling Sprite_HandleAbsorptionByPlayer twice, it's called
  // also from within Sprite_HandleDraggingByAncilla
  if (sprite_state[k] == 0 && (enhanced_features0 & kFeatures0_MiscBugFixes))
    return;

  if (Sprite_HandleDraggingByAncilla(k))
    return;
  Sprite_MoveXY(k);
  Sprite_MoveZ(k);
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    sprite_ai_state[k]++;
    sprite_graphics[k] = 0;
  }
  sprite_oam_flags[k] &= ~0x40;
  if (!sign8(sprite_x_vel[k]))
    sprite_oam_flags[k] |= 0x40;
  switch (sprite_ai_state[k] >= 3 ? 3 : sprite_ai_state[k]) {
  case 0:  // InitializeAscent
    sprite_ai_state[k]++;
    sprite_delay_main[k] = 18;
    sprite_z_vel[k] = 20;
    sprite_graphics[k] = 1;
    sprite_D[k] = 0;
    break;
  case 1:  // BeginDescending
    if (sprite_delay_main[k] != 0) {
      sprite_z_vel[k]--;
    } else {
      sprite_ai_state[k]++;
      sprite_z_vel[k] = 253;
      sprite_x_vel[k] = 0;
    }
    break;
  case 2:  // GlideGroundward
    if (sprite_delay_main[k] == 0) {
      int j = sprite_D[k] & 1;
      sprite_x_vel[k] += kHeartRefill_AccelX[j];
      if (sprite_x_vel[k] == (uint8)kHeartRefill_VelTarget[j]) {
        sprite_D[k]++;
        sprite_delay_main[k] = 8;
      }
    }
    break;
  case 3:  // Grounded
    sprite_z_vel[k] = sprite_x_vel[k] = sprite_y_vel[k] = 0;
    break;
  }
}

/*
 * Sprite_E3_Fairy — Catchable fairy (the green sparkle that revives Link
 * or can be bottled). Always projectile-immune. Outdoor: force priority
 * 48 (in front of background).
 * 2-state:
 *   0 Normal: On Link contact via boomerang/etc. (kCheckDamageFromPlayer_Ne)
 *             show "do you want to keep this fairy?" msg 0xc9 and advance
 *             to capture. Direct contact triggers HandleAbsorptionByPlayer
 *             (heals Link).
 *   1 Capture: Yes -> find empty bottle, store fairy as type 6, kill slot.
 *              No / no bottle -> bounce back with 48-frame cooldown and
 *              "no bottle" message 0xca.
 *
 * The MiscBugFixes guard avoids a stale double-pickup when the fairy
 * is currently being magnet-dragged.
 */
void Sprite_E3_Fairy(int k) {  // 86cf94
  sprite_ignore_projectile[k] = 1;
  if (!sprite_ai_state[k]) {
    if (!player_is_indoors)
      sprite_obj_prio[k] = 48;
    if (SpriteDraw_AbsorbableTransient(k, true))
      return;
  }
  Fairy_CheckIfTouchable(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  switch (sprite_ai_state[k]) {
  case 0: // normal
    if (!sprite_delay_aux4[k]) {
      if (Sprite_CheckDamageToLink(k)) {
        Sprite_HandleAbsorptionByPlayer(k);
      } else if (Sprite_CheckDamageFromLink(k) & kCheckDamageFromPlayer_Ne) {
        sprite_ai_state[k]++;
        Sprite_ShowMessageUnconditional(0xc9);
        return;
      }
    }
    // Avoid calling Sprite_HandleAbsorptionByPlayer twice, it's called
    // also from within Sprite_HandleDraggingByAncilla
    if (sprite_state[k] == 0 && (enhanced_features0 & kFeatures0_MiscBugFixes))
      return;
    if (Sprite_HandleDraggingByAncilla(k))
      return;
    Faerie_HandleMovement(k);
    break;
  case 1: // capture
    if (choice_in_multiselect_box == 0) {
      int j = Sprite_Find_EmptyBottle();
      if (j >= 0) {
        link_bottle_info[j] = 6;
        Hud_RefreshIcon();
        sprite_state[k] = 0;
        return;
      }
      Sprite_ShowMessageUnconditional(0xca);
    }
    sprite_delay_aux4[k] = 48;
    sprite_ai_state[k] = 0;
    break;
  }
}

/*
 * Fairy_CheckIfTouchable — While dialog 0xc9 or 0xca is active (the
 * fairy capture prompts), arm a 40-frame post-prompt grace period so
 * Link doesn't accidentally re-trigger the same dialog.
 */
void Fairy_CheckIfTouchable(int k) {  // 86d011
  if (submodule_index == 2 && (dialogue_message_index == 0xc9 || dialogue_message_index == 0xca))
    sprite_delay_aux4[k] = 40;
}

/*
 * Sprite_E4_SmallKey — Small key pickup. Skip if the save's "key absorbed"
 * bit (kAbsorbBigKey[die_action] << 8) is already set. Otherwise tick
 * standard Absorbable_Main physics with water-ripple if in shallow water.
 */
void Sprite_E4_SmallKey(int k) {  // 86d032
  if (dung_savegame_state_bits & (kAbsorbBigKey[sprite_die_action[k]] << 8)) {
    sprite_state[k] = 0;
    return;
  }
  Sprite_DrawRippleIfInWater(k);
  if (SpriteDraw_AbsorbableTransient(k, false))
    return;
  Sprite_Absorbable_Main(k);
}

/*
 * Sprite_D9_GreenRupee — Green rupee pickup. Slot family covers all
 * rupee variants (D9 green, DB blue, DC red, etc.) via the kSpriteActive
 * routine; the active handler just runs Absorbable_Main physics.
 */
void Sprite_D9_GreenRupee(int k) {  // 86d04a
  Sprite_DrawRippleIfInWater(k);
  if (SpriteDraw_AbsorbableTransient(k, true))
    return;
  Sprite_Absorbable_Main(k);
}

/*
 * Sprite_Absorbable_Main — Shared per-tick physics for all absorbable
 * pickups (hearts, rupees, keys, fairies, etc.).
 *   Move XY + Z; apply gravity (z_vel -= 2).
 *   On landing (z negative): zero z, halve x/y velocities (bounce damping).
 *     If the remaining z-vel magnitude is < 9, full stop. Else continue
 *     to bounce. For sprite_I == 8 or 9 (water variants), zero z_vel and
 *     spawn a small splash; for indoor key-tier pickups (type >= 0xe4),
 *     play clink SFX 5.
 *   Tile-collision + wall-bounce while not in absorb-attract delay_aux3.
 *   Magnet-cape / ancilla drag handling first; then check for Link
 *     absorption (CheckAbsorptionByPlayer).
 *
 * The "wtf carry propagation" inline annotation marks an original ROM
 * quirk where the splash position carry-propagates incorrectly; preserved
 * here for byte-identity.
 */
void Sprite_Absorbable_Main(int k) {  // 86d051
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_MoveZ(k);
  Sprite_MoveXY(k);
  if (sprite_delay_aux3[k] == 0) {
    Sprite_CheckTileCollision2(k);
    Sprite_BounceOffWall(k);
  }
  sprite_z_vel[k] -= 2;
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    sprite_x_vel[k] = (int8)sprite_x_vel[k] >> 1;
    sprite_y_vel[k] = (int8)sprite_y_vel[k] >> 1;
    uint8 t = -sprite_z_vel[k];
    t >>= 1;
    if (t < 9) {
      sprite_z_vel[k] = sprite_x_vel[k] = sprite_y_vel[k] = 0;
    } else {
      sprite_z_vel[k] = t;
      if (sprite_I[k] == 8 || sprite_I[k] == 9) {
        sprite_z_vel[k] = 0;
        int j = Sprite_SpawnSmallSplash(k);
        if (j >= 0 && sprite_flags3[k] & 0x20) {
          // wtf carry propagation
          Sprite_SetX(j, Sprite_GetX(j) - 4);
          Sprite_SetY(j, Sprite_GetY(j) - 4);
        }
      } else {
        if (sprite_type[k] >= 0xe4 && player_is_indoors)
          SpriteSfx_QueueSfx2WithPan(k, 5);
      }
    }
  }
  if (Sprite_HandleDraggingByAncilla(k))
    return;
  Sprite_CheckAbsorptionByPlayer(k);
}

/*
 * Sprite_08_Octorok — Octorok (the spitting plant enemy). Slot covers
 * both the normal Octorok (type 8) and the 4-shooter variant (type 0xa).
 * Animation: subtype2 >> 3 picks one of 4 walk poses; sprite_C drives
 * the head-poke phase via kOctorock_Tab0/Tab1 timing curves.
 *
 * 2-state-pair AI (even/odd ai_state alternates between walk and pause):
 *   ai_state even (walk): step XY along D-direction; on wall hit reverse
 *     D (^= 1). On delay==0 advance to pause (state 1 with 60-frame
 *     normal / 160-frame 4-shooter dwell).
 *   ai_state odd (pause): pick a new random direction (delay & 3) and
 *     reset 48..111-frame walk timer. During pause:
 *       type 8 (normal): at delay==28 fire one loogie (Octorok_FireLoogie).
 *         Anim cursor from kOctorock_Tab0.
 *       type 0xa (4-shooter): in the first half of the delay (j < 128),
 *         every 16 frames rotate to NextDir; every 16 frames + 8 fire
 *         a loogie. Anim cursor from kOctorock_Tab1.
 */
void Sprite_08_Octorok(int k) {  // 86d377
  static const uint8 kOctorock_Tab0[20] = {
    0, 2, 2, 2, 1, 1, 1, 0, 0, 0, 0, 0, 2, 2, 2, 2, 2, 1, 1, 0,
  };
  static const uint8 kOctorock_Tab1[10] = {2, 2, 2, 2, 2, 2, 2, 2, 1, 0};
  static const uint8 kOctorock_NextDir[4] = {2, 3, 1, 0};
  static const uint8 kOctorock_Dir[4] = {3, 2, 0, 1};
  static const int8 kOctorock_Xvel[4] = {24, -24, 0, 0};
  static const int8 kOctorock_Yvel[4] = {0, 0, 24, -24};
  static const uint8 kOctorock_OamFlags[4] = {0x40, 0, 0, 0};

  int j = sprite_D[k];
  if (sprite_delay_aux1[k])
    sprite_D[k] = kOctorock_Dir[j];
  sprite_oam_flags[k] = sprite_oam_flags[k] & ~0x40 | kOctorock_OamFlags[j] | (sprite_graphics[k] == 7 ? 0x40 : 0);
  Octorock_Draw(k);
  sprite_D[k] = j;

  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  Sprite_MoveXY(k);
  Sprite_CheckDamageToAndFromLink(k);
  if (!(sprite_ai_state[k] & 1)) {
    sprite_graphics[k] = ++sprite_subtype2[k] >> 3 & 3 | (sprite_D[k] & 2) << 1;
    if (!sprite_delay_main[k]) {
      sprite_ai_state[k]++;
      sprite_delay_main[k] = sprite_type[k] == 8 ? 60 : 160;
    } else {
      j = sprite_D[k];
      sprite_x_vel[k] = kOctorock_Xvel[j];
      sprite_y_vel[k] = kOctorock_Yvel[j];
      if (Sprite_CheckTileCollision(k))
        sprite_D[k] ^= 1;
    }
    return;
  } else {
    Sprite_ZeroVelocity_XY(k);
    if (!sprite_delay_main[k]) {
      sprite_ai_state[k]++;
      sprite_delay_main[k] = (GetRandomNumber() & 0x3f) + 48;
      sprite_D[k] = sprite_delay_main[k] & 3;
    } else {
      switch (sprite_type[k]) {
      case 8:  // normal
        j = sprite_delay_main[k];
        if (j == 28)
          Octorok_FireLoogie(k);
        sprite_C[k] = kOctorock_Tab0[j >> 3];
        break;
      case 10:  // four shooter
        j = sprite_delay_main[k];
        if (j < 128) {
          if (!(j & 15))
            sprite_D[k] = kOctorock_NextDir[sprite_D[k]];
          if ((j & 15) == 8)
            Octorok_FireLoogie(k);
        }
        sprite_C[k] = kOctorock_Tab1[j >> 4];
        break;
      }
    }
  }
}

/*
 * Octorok_FireLoogie — Spawn the projectile (sprite type 0xc) at the
 * Octorok's mouth offset (per-direction kOctorock_Spit_X/Y), with 44
 * px/frame cardinal velocity. SFX 0x7 = spit sound.
 */
void Octorok_FireLoogie(int k) {  // 86d4cd
  static const int8 kOctorock_Spit_X[4] = {12, -12, 0, 0};
  static const int8 kOctorock_Spit_Y[4] = {4, 4, 12, -12};
  static const int8 kOctorock_Spit_Xvel[4] = {44, -44, 0, 0};
  static const int8 kOctorock_Spit_Yvel[4] = {0, 0, 44, -44};
  SpriteSpawnInfo info;
  SpriteSfx_QueueSfx2WithPan(k, 0x7);
  int j = Sprite_SpawnDynamically(k, 0xc, &info);
  if (j >= 0) {
    int i = sprite_D[k];
    Sprite_SetX(j, info.r0_x + kOctorock_Spit_X[i]);
    Sprite_SetY(j, info.r2_y + kOctorock_Spit_Y[i]);
    sprite_x_vel[j] = kOctorock_Spit_Xvel[i];
    sprite_y_vel[j] = kOctorock_Spit_Yvel[i];
  }
}

/*
 * Octorock_Draw — Render Octorok as a head tile + body tile composite.
 * The head tile is positioned by (sprite_C * 3 + sprite_D) so it tracks
 * both the spit cycle and facing direction. D==3 (facing down) hides the
 * head (skip head tile). Body uses SingleLarge with flags2-- temporarily
 * adjusting OAM size for the wider 16x16 body.
 */
void Octorock_Draw(int k) {  // 86d54a
  static const int8 kOctorock_Draw_X[9] = {8, 0, 4, 8, 0, 4, 9, -1, 4};
  static const int8 kOctorock_Draw_Y[9] = {6, 6, 9, 6, 6, 9, 6, 6, 9};
  static const uint8 kOctorock_Draw_Char[9] = {0xbb, 0xbb, 0xba, 0xab, 0xab, 0xaa, 0xa9, 0xa9, 0xb9};
  static const uint8 kOctorock_Draw_Flags[9] = {0x65, 0x25, 0x25, 0x65, 0x25, 0x25, 0x65, 0x25, 0x25};
  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  if (sprite_D[k] != 3) {
    OamEnt *oam = GetOamCurPtr();
    int j = sprite_C[k] * 3 + sprite_D[k];
    SetOamHelper0(oam, info.x + kOctorock_Draw_X[j], info.y + kOctorock_Draw_Y[j],
                  kOctorock_Draw_Char[j], kOctorock_Draw_Flags[j] | info.flags, 0);
  }
  oam_cur_ptr += 4;
  oam_ext_cur_ptr++;
  sprite_flags2[k]--;
  Sprite_PrepAndDrawSingleLargeNoPrep(k, &info);
  sprite_flags2[k]++;
}

/*
 * Sprite_0C_OctorokStone — Octorok spit projectile. Two modes:
 *   state == 6 (crumbling): play OctorokStoneCrumbling animation. At
 *     delay==30 play shatter SFX 0x1f.
 *   Normal flight: move, check tile collision every 4 frames, on hit
 *     trigger crumble via Sprite_Func3.
 */
void Sprite_0C_OctorokStone(int k) {  // 86d5b9
  if (sprite_state[k] == 6) {
    SpriteDraw_OctorokStoneCrumbling(k);
    if (Sprite_ReturnIfPaused(k))
      return;
    if (sprite_delay_main[k] == 30)
      SpriteSfx_QueueSfx2WithPan(k, 0x1f);
  } else {
    SpriteDraw_SingleLarge(k);
    if (Sprite_ReturnIfInactive(k))
      return;
    Sprite_CheckDamageToLink(k);
    Sprite_MoveXY(k);
    if (!((k ^ frame_counter) & 3) && Sprite_CheckTileCollision(k))
      Sprite_Func3(k);
  }
}

/*
 * SpriteDraw_OctorokStoneCrumbling — 4-tile starburst that expands outward
 * over 4 frames. The frame index `g` is delay_main >> 1 & 0xc ^ 0xc so
 * the animation runs in reverse as delay drains (outward expansion).
 */
void SpriteDraw_OctorokStoneCrumbling(int k) {  // 86d643
  static const int8 kOctostone_Draw_X[16] = {0, 8, 0, 8, -8, 16, -8, 16, -12, 20, -12, 20, -14, 22, -14, 22};
  static const int8 kOctostone_Draw_Y[16] = {0, 0, 8, 8, -8, -8, 16, 16, -12, -12, 20, 20, -14, -14, 22, 22};
  static const uint8 kOctostone_Draw_Flags[16] = {0, 0x40, 0x80, 0xc0, 0, 0x40, 0x80, 0xc0, 0, 0x40, 0x80, 0xc0, 0, 0x40, 0x80, 0xc0};

  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  OamEnt *oam = GetOamCurPtr();
  int g = ((sprite_delay_main[k] >> 1 & 0xc) ^ 0xc);
  for (int i = 3; i >= 0; i--, oam++) {
    int j = g + i;
    SetOamHelper0(oam, info.x + kOctostone_Draw_X[j], info.y + kOctostone_Draw_Y[j],
                  0xbc, kOctostone_Draw_Flags[j] | 0x2d, 0);
  }

}

/*
 * Sprite_0F_Octoballoon — Octoballoon mother (the floating spike-balloon
 * that splits into babies on hit). Z hover (16..20 px bobbing via the
 * 8-entry Z table indexed by subtype2 >> 3). Every 16 frames, project
 * speed toward Link at 4 px/frame; nudge current velocity by ±1 toward
 * that target so the balloon glides toward Link. On Octoballoon_Find
 * returning false (no other Octoballoons in the room — the mother died
 * by other means), transition to state 6 (burst) with 15-frame death
 * animation. On Link contact use Octoballoon_RecoilLink (inverts the
 * balloon's velocity + applies 16 px recoil to Link).
 */
void Sprite_0F_Octoballoon(int k) {  // 86d6aa
  static const uint8 kSprite_Octoballoon_Z[8] = {16, 17, 18, 19, 20, 19, 18, 17};
  sprite_z[k] = kSprite_Octoballoon_Z[sprite_subtype2[k] >> 3 & 7];
  Octoballoon_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (!sprite_delay_main[k]) {
    sprite_delay_main[k] = 3;
    if (!Octoballoon_Find()) {
      sprite_state[k] = 6;
      sprite_hit_timer[k] = 0;
      sprite_delay_main[k] = 15;
      return;
    }
  }
  if (Sprite_ReturnIfRecoiling(k))
    return;
  sprite_subtype2[k]++;
  if (!((k ^ frame_counter) & 15)) {
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLink(k, 4);
    if (sprite_x_vel[k] - pt.x)
      sprite_x_vel[k] += sign8(sprite_x_vel[k] - pt.x) ? 1 : -1;
    if (sprite_y_vel[k] - pt.y)
      sprite_y_vel[k] += sign8(sprite_y_vel[k] - pt.y) ? 1 : -1;
  }
  Sprite_MoveXY(k);
  if (Sprite_CheckDamageToLink(k))
    Octoballoon_RecoilLink(k);
  Sprite_CheckDamageFromLink(k);
  Sprite_CheckTileCollision2(k);
  Sprite_BounceOffWall(k);
}

/*
 * Octoballoon_RecoilLink — Bounce Link off the balloon: 4-frame stun + 16
 * px recoil; invert the balloon's velocity so the two separate.
 */
void Octoballoon_RecoilLink(int k) {  // 86d72b
  if (!link_incapacitated_timer) {
    link_incapacitated_timer = 4;
    Sprite_ApplyRecoilToLink(k, 16);
    Sprite_InvertSpeed_XY(k);
  }
}

/*
 * Octoballoon_Draw — 4-tile composite. Different graphics phases for the
 * normal floating pose vs the burst frames. On state 6 (popping) the 4
 * burst frames are picked from offset (delay_main >> 1 & 4) + 4; at
 * delay==6 spawn the 6 baby Octoballoons via Octoballoon_FormBabby.
 */
void Octoballoon_Draw(int k) {  // 86d784
  static const int8 kOctoballoon_Draw_X[12] = {-4, 4, -4, 4, -8, 8, -8, 8, -4, 4, -4, 4};
  static const int8 kOctoballoon_Draw_Y[12] = {-4, -4, 4, 4, -8, -8, 8, 8, -4, -4, 4, 4};
  static const uint8 kOctoballoon_Draw_Char[12] = {0x8c, 0x8c, 0x9c, 0x9c, 0x86, 0x86, 0x86, 0x86, 0x86, 0x86, 0x86, 0x86};
  static const uint8 kOctoballoon_Draw_Flags[12] = {0, 0x40, 0, 0x40, 0, 0x40, 0x80, 0xc0, 0, 0x40, 0x80, 0xc0};
  int d = 0;
  if (sprite_state[k] == 6) {
    if (sprite_delay_main[k] == 6 && !submodule_index)
      Octoballoon_FormBabby(k);
    d = (sprite_delay_main[k] >> 1 & 4) + 4;
  }
  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  OamEnt *oam = GetOamCurPtr();
  for (int i = 3; i >= 0; i--, oam++) {
    int j = d + i;
    SetOamHelper0(oam, info.x + kOctoballoon_Draw_X[j], info.y + kOctoballoon_Draw_Y[j],
                  kOctoballoon_Draw_Char[j], kOctoballoon_Draw_Flags[j] | info.flags, 2);
  }
  SpriteDraw_Shadow(k, &info);
}

/*
 * Octoballoon_FormBabby — Spawn 6 baby Octoballoons at the mother's
 * position with a hex-pattern velocity spread (6 entries of
 * kOctoballoon_Spawn_Xv/Yv): right, NE, NW, left, SW, SE radial cone.
 * All babies share z_vel=48 (high arc) and subtype2=255 (fresh life).
 * Plays the burst SFX 0xc once for the whole group.
 */
void Octoballoon_FormBabby(int k) {  // 86d80e
  static const int8 kOctoballoon_Spawn_Xv[6] = {16, 11, -11, -16, -11, 11};
  static const int8 kOctoballoon_Spawn_Yv[6] = {0, 11, 11, 0, -11, -11};

  SpriteSfx_QueueSfx2WithPan(k, 0xc);
  for (int i = 5; i >= 0; i--) {
    SpriteSpawnInfo info;
    int j = Sprite_SpawnDynamically(k, 0x10, &info);
    if (j >= 0) {
      Sprite_SetSpawnedCoordinates(j, &info);
      sprite_x_vel[j] = kOctoballoon_Spawn_Xv[i];
      sprite_y_vel[j] = kOctoballoon_Spawn_Yv[i];
      sprite_z_vel[j] = 48;
      sprite_subtype2[j] = 255;
    }
  }
}

/*
 * Sprite_10_OctoballoonBaby — Baby Octoballoon. subtype2 counts down each
 * frame (initial 255 from spawn). At subtype2==0 the baby self-destructs.
 * The blinking-out animation kicks in subtype2 < 64 (every other frame
 * skipped) so the baby visually winks before vanishing. Z hop with
 * bounce on landing (z_vel reset to 16).
 */
void Sprite_10_OctoballoonBaby(int k) {  // 86d853
  if (!sprite_subtype2[k])
    sprite_state[k] = 0;
  if (sprite_subtype2[k] >= 64 || !(sprite_subtype2[k] & 1))
    SpriteDraw_SingleSmall(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  sprite_subtype2[k]--;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  sprite_z_vel[k]--;
  Sprite_MoveZ(k);
  if (sign8(sprite_z[k])) {
    sprite_z[k] = 0;
    sprite_z_vel[k] = 16;
  }
  Sprite_MoveXY(k);
  Sprite_CheckTileCollision2(k);
  Sprite_BounceOffWall(k);
  Sprite_CheckDamageToAndFromLink(k);
}

/*
 * Sprite_0D_Buzzblob — Buzzblob (the electric green slug that transforms
 * into Cukeman on magic powder). Per-tick:
 *   delay_aux1 (powder transformation timer) active: cycle through 4 obj-
 *     prio phases via kBuzzBlob_ObjPrio so the slug flashes during the
 *     transformation.
 *   Animation: 4-frame walk-cycle via subtype2 >> 3 (offset by 3 during
 *     transformation).
 *   On delay_main==0 pick a new random 8-direction movement vector via
 *     Buzzblob_SelectNewDirection.
 *   While transforming (delay_aux1 set), skip movement (frozen).
 *   Bounce off walls; check damage to/from Link normally.
 */
void Sprite_0D_Buzzblob(int k) {  // 86d89a
  static const uint8 kBuzzBlob_Gfx[4] = {0, 1, 0, 2};
  static const uint8 kBuzzBlob_ObjPrio[4] = {10, 2, 8, 2};
  if (sprite_delay_aux1[k])
    sprite_obj_prio[k] = sprite_obj_prio[k] & 0xf1 | kBuzzBlob_ObjPrio[sprite_delay_aux1[k] >> 1 & 3];
  Sprite_Cukeman(k);
  BuzzBlob_Draw(k);
  sprite_graphics[k] = kBuzzBlob_Gfx[sprite_subtype2[k] >> 3 & 3] + (sprite_delay_aux1[k] ? 3 : 0);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  sprite_subtype2[k]++;
  if (!sprite_delay_main[k])
    Buzzblob_SelectNewDirection(k);
  if (!sprite_delay_aux1[k])
    Sprite_MoveXY(k);
  Sprite_CheckTileCollision2(k);
  Sprite_BounceOffWall(k);
  Sprite_CheckDamageToAndFromLink(k);
}

/*
 * Buzzblob_SelectNewDirection — Pick one of 8 random directions (6 movement
 * directions + 2 stationary). 48 or 64-frame walk timer.
 */
void Buzzblob_SelectNewDirection(int k) {  // 86d906
  static const int8 kBuzzBlob_Xvel[8] = {3, 2, -2, -3, -2, 2, 0, 0};
  static const int8 kBuzzBlob_Yvel[8] = {0, 2, 2, 0, -2, -2, 0, 0};
  static const uint8 kBuzzBlob_Delay[8] = {48, 48, 48, 48, 48, 48, 64, 64};
  int j = GetRandomNumber() & 7;
  sprite_x_vel[k] = kBuzzBlob_Xvel[j];
  sprite_y_vel[k] = kBuzzBlob_Yvel[j];
  sprite_delay_main[k] = kBuzzBlob_Delay[j];
}

/*
 * BuzzBlob_Draw — 3-tile composite (top + 2 side tiles). Each pose entry
 * occupies 3 chr/flag entries indexed by graphics; ext byte controls
 * tile size (0/0/2 = small/small/large body).
 */
void BuzzBlob_Draw(int k) {  // 86d953
  static const uint16 kBuzzBlob_DrawX[3] = {0, 8, 0};
  static const int16 kBuzzBlob_DrawY[3] = {-8, -8, 0};
  static const uint8 kBuzzBlob_DrawChar[18] = { 0xf0, 0xf0, 0xe1, 0, 0, 0xce, 0, 0, 0xce, 0xe3, 0xe3, 0xca, 0xe4, 0xe5, 0xcc, 0xe5, 0xe4, 0xcc };
  static const uint8 kBuzzBlob_DrawFlags[18] = { 0, 0x40, 0, 0, 0, 0, 0, 0, 0x40, 0, 0x40, 0, 0, 0, 0, 0x40, 0x40, 0x40 };
  static const uint8 kBuzzBlob_DrawExt[3] = {0, 0, 2};

  PrepOamCoordsRet info;
  if (Sprite_PrepOamCoordOrDoubleRet(k, &info))
    return;
  OamEnt *oam = GetOamCurPtr();
  int g = sprite_graphics[k];
  for (int i = 2; i >= 0; i--, oam++) {
    SetOamHelper0(oam, info.x + kBuzzBlob_DrawX[i], info.y + kBuzzBlob_DrawY[i],
                  kBuzzBlob_DrawChar[g * 3 + i],
                  kBuzzBlob_DrawFlags[g * 3 + i] | info.flags, kBuzzBlob_DrawExt[i]);
    if (oam->charnum == 0)
      oam->y = 240;
  }
  SpriteDraw_Shadow(k, &info);
}

/*
 * Sprite_02_StalfosHead — Stalfos Head (the disembodied skull projectile).
 * Animation: subtype2 >> 3 cycles 4 facing-pose frames. obj_prio 0x30
 * keeps the skull in front of tiles. F-flag (recoil) zeros velocity.
 *
 * Homing logic: every 4 frames pick a project-speed vector. While in
 * delay_main, alternate frames pull the head toward Link (positive speed);
 * otherwise pull away (negative speed). Velocity is moved one ±1 step
 * toward the target per call so the head curves smoothly. Provides the
 * characteristic "swirling" Stalfos Head motion.
 */
void Sprite_02_StalfosHead(int k) {  // 86ddb7
  static const uint8 kStalfosHead_OamFlags[4] = {0, 0, 0, 0x40};
  static const uint8 kStalfosHead_Gfx[4] = {0, 1, 2, 1};

  sprite_floor[k] = link_is_on_lower_level;
  if (sprite_delay_aux1[k])
    Oam_AllocateFromRegionC(8);
  int j = sprite_subtype2[k] >> 3 & 3;
  sprite_oam_flags[k] = sprite_oam_flags[k] & ~0x40 | kStalfosHead_OamFlags[j];
  sprite_graphics[k] = kStalfosHead_Gfx[j];
  sprite_obj_prio[k] = 0x30;
  SpriteDraw_SingleLarge(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  Sprite_CheckDamageToAndFromLink(k);
  if (sprite_F[k])
    Sprite_ZeroVelocity_XY(k);
  Sprite_MoveXY(k);
  sprite_subtype2[k]++;
  ProjectSpeedRet pt;
  if (sprite_delay_main[k]) {
    if (sprite_delay_main[k] & 1)
      return;
    pt = Sprite_ProjectSpeedTowardsLink(k, 16);
  } else {
    if ((k ^ frame_counter) & 3)
      return;
    pt = Sprite_ProjectSpeedTowardsLink(k, 16);
    pt.x = -pt.x;
    pt.y = -pt.y;
  }
  if (sprite_x_vel[k] - pt.x != 0)
    sprite_x_vel[k] += sign8(sprite_x_vel[k] - pt.x) ? 1 : -1;
  if (sprite_y_vel[k] - pt.y != 0)
    sprite_y_vel[k] += sign8(sprite_y_vel[k] - pt.y) ? 1 : -1;
}

/*
 * Pipe_ValidateEntry — Helper called when Link interacts with a pipe
 * (sprite type 0xAE). Looks for an active "in-pipe" ancilla (type 0x31)
 * in slots 0..4. If found, clear Link's pipe-position mode and free
 * direction lock, then null the ancilla. Returns true if either pipe
 * entry bit (link_state_bits & 0x80 or link_auxiliary_state) was set.
 */
bool Pipe_ValidateEntry() {  // 87f4f1
  for (int k = 4; k >= 0; k--) {
    if (ancilla_type[k] == 0x31) {
      link_position_mode = 0;
      link_cant_change_direction = 0;
      ancilla_type[k] = 0;
      break;
    }
  }
  return ((link_state_bits & 0x80) | link_auxiliary_state) != 0;
}

/*
 * Ancilla_TerminateSparkleObjects — Walk the 5 ancilla slots and null any
 * that match the "transient effect" classes: somaria/byrna sparkles
 * (0x2a/0x2b), pipe entry (0x30/0x31), arrow tink sparks (0x18/0x19), or
 * hookshot chain (0xc). Used when triggering a major state change (e.g.
 * a Happiness Pond cutscene starts) to clear visual clutter.
 */
void Ancilla_TerminateSparkleObjects() {  // 89adc7
  for (int i = 4; i >= 0; i--) {
    uint8 t = ancilla_type[i];
    if (t == 0x2a || t == 0x2b || t == 0x30 || t == 0x31 || t == 0x18 || t == 0x19 || t == 0xc)
      ancilla_type[i] = 0;
  }
}

/*
 * Sprite_SpawnSuperficialBombBlast — Spawn a non-damaging "fake" bomb
 * explosion (type 0x4a state 6 with C=3 = pure-visual). 31-frame
 * animation, palette 4, plays explosion SFX 0x15. Used by cutscenes that
 * want the visual without dealing damage (Mad Batter summon, etc.).
 */
int Sprite_SpawnSuperficialBombBlast(int k) {  // 89ae40
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x4a, &info);
  if (j >= 0) {
    sprite_state[j] = 6;
    sprite_delay_aux1[j] = 31;
    sprite_C[j] = 3;
    sprite_flags2[j] = 3;
    sprite_oam_flags[j] = 4;
    SpriteSfx_QueueSfx2WithPan(k, 0x15);
    Sprite_SetSpawnedCoordinates(j, &info);
  }
  return j;
}

/*
 * Sprite_SpawnDummyDeathAnimation — Spawn the generic "puff of smoke"
 * death animation (sprite type 0xb state 6, 15-frame fuse). Plays SFX
 * 0x14 (death poof). Forces floor=2 for upper-layer rendering.
 */
void Sprite_SpawnDummyDeathAnimation(int k) {  // 89ae7e
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0xb, &info);
  if (j >= 0) {
    Sprite_SetSpawnedCoordinates(j, &info);
    sprite_state[j] = 6;
    sprite_delay_main[j] = 15;
    SpriteSfx_QueueSfx2WithPan(k, 0x14);
    sprite_floor[j] = 2;
  }
}

/*
 * Sprite_MagicBat_SpawnLightning — Spawn 4 Mad Batter lightning bolt
 * children (sprite type 0x3a head_dir=24 marks them as projectiles). Each
 * gets a per-slot Xvel from kSpawnMadderBolts_Xvel (-8,-4,4,8 = wide cross),
 * unique subtype2 phase, and palette/flag setup for the lightning render.
 * sprite_G[k] tracks the spawn cursor (0..3).
 */
void Sprite_MagicBat_SpawnLightning(int k) {  // 89aea8
  static const int8 kSpawnMadderBolts_Xvel[4] = {-8, -4, 4, 8};
  static const int8 kSpawnMadderBolts_St2[4] = {0, 0x11, 0x22, 0x33};
  for (int i = 0; i < 4; i++) {
    SpriteSpawnInfo info;
    int j = Sprite_SpawnDynamically(k, 0x3a, &info);
    if (j >= 0) {
      SpriteSfx_QueueSfx3WithPan(k, 0x1);
      Sprite_SetSpawnedCoordinates(j, &info);
      Sprite_SetX(j, info.r0_x + 4);
      Sprite_SetY(j, info.r2_y + 12 - sprite_z[k]);
      sprite_z[j] = 0;
      sprite_y_vel[j] = 24;
      sprite_head_dir[j] = 24;
      sprite_ignore_projectile[j] = 24;
      sprite_flags2[j] = 0x80;
      sprite_flags3[j] = 3;
      sprite_oam_flags[j] = 3;
      sprite_delay_main[j] = 32;
      sprite_graphics[j] = 2;
      int i = sprite_G[k];
      sprite_x_vel[j] = kSpawnMadderBolts_Xvel[i];
      sprite_subtype2[j] = kSpawnMadderBolts_St2[i];
      sprite_floor[j] = 2;
      sprite_G[k]++;
    }
  }
}

/*
 * Fireball_SpawnTrailGarnish — Every 4 frames spawn a garnish-type-8
 * trail particle behind a fireball. 11-frame fade. Y offset +16 anchors
 * the trail to the fireball's tail.
 */
void Fireball_SpawnTrailGarnish(int k) {  // 89b020
  if ((k ^ frame_counter) & 3)
    return;
  int j = GarnishAlloc();
  garnish_type[j] = 8;
  garnish_active = 8;
  garnish_countdown[j] = 11;
  garnish_x_lo[j] = cur_sprite_x;
  garnish_x_hi[j] = cur_sprite_x >> 8;
  garnish_y_lo[j] = cur_sprite_y + 16;
  garnish_y_hi[j] = (cur_sprite_y + 16) >> 8;
  garnish_sprite[j] = k;
}

/*
 * GarnishSpawn_PyramidDebris — Spawn a single chunk of falling rubble at
 * the fixed Pyramid hole position (232, 96) + (x, y) offset. Garnish type
 * 19 (debris chunk) with 48..79 frame lifetime. Plays a layered rumble
 * SFX cue (sfx_2=3 + sfx_1=31 + ambient=5) — three channels firing at
 * once for the dramatic "Triforce shatter" rumble.
 */
void GarnishSpawn_PyramidDebris(int8 x, int8 y, int8 xvel, int8 yvel) {  // 89b1bd
  int k = GarnishAllocForce();
  sound_effect_2 = 3;
  sound_effect_1 = 31;
  sound_effect_ambient = 5;

  garnish_type[k] = 19;
  garnish_active = 19;
  garnish_x_lo[k] = 232 + x;
  garnish_y_lo[k] = 96 + y;
  garnish_x_vel[k] = xvel;
  garnish_y_vel[k] = yvel;
  garnish_countdown[k] = (GetRandomNumber() & 31) + 48;
}

/*
 * Snitch_SpawnGuard — Spawn a guard (sprite type 0x45) at one of three
 * fixed map locations (selected by snitch type: 0x3d->slot 0, 0x35->slot
 * 1, other->slot 2). Uses sprcoll_x/y_base high-byte to anchor the guard
 * to the current map page. Guard preset: 4 HP, deflect-immune (0x80),
 * flags5=0x90 (special class), palette 0xb.
 */
void Snitch_SpawnGuard(int k) {  // 89c02f
  static const uint16 kCrazyVillageSoldier_X[3] = {0x120, 0x340, 0x2e0};
  static const uint16 kCrazyVillageSoldier_Y[3] = {0x100, 0x3b0, 0x160};
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamicallyEx(k, 0x45, &info, 0);
  if (j < 0)
    return;
  int i = sprite_type[k] == 0x3d ? 0 :
          sprite_type[k] == 0x35 ? 1 : 2;
  Sprite_SetX(j, kCrazyVillageSoldier_X[i] + (sprcoll_x_base & 0xff00));
  Sprite_SetY(j, kCrazyVillageSoldier_Y[i] + (sprcoll_y_base & 0xff00));
  sprite_floor[j] = 0;
  sprite_health[j] = 4;
  sprite_defl_bits[j] = 0x80;
  sprite_flags5[j] = 0x90;
  sprite_oam_flags[j] = 0xb;
}

