/*
 * Probe_CheckTileSolidity — Test the tile under the probe sprite.
 *   Indoor : Read dung_bg2_attr_table directly. The cell index is built
 *            from (cur_sprite_x & 0x1f8) >> 3 (low 6 bits = column) plus
 *            (cur_sprite_y & 0x1f8) << 3 (high 6 bits = row), with a
 *            0x1000 offset added when the probe is on the upper layer
 *            (sprite_floor >= 1).
 *   Outdoor: Use Overworld_ReadTileAttribute which handles the OW's
 *            tile-attribute decoding.
 * Returns true if the resolved kSprite_SimplifiedTileAttr class is >= 1
 * (i.e. solid wall or other blocker, not floor).
 */
bool Probe_CheckTileSolidity(int k) {  // 8dc26e
  uint8 tiletype;
  if (player_is_indoors) {
    int t = (sprite_floor[k] >= 1) ? 0x1000 : 0;
    t += (cur_sprite_x & 0x1f8) >> 3;
    t += (cur_sprite_y & 0x1f8) << 3;
    tiletype = dung_bg2_attr_table[t];
  } else {
    tiletype = Overworld_ReadTileAttribute(cur_sprite_x >> 3, cur_sprite_y);
  }
  sprite_tiletype = tiletype;
  return kSprite_SimplifiedTileAttr[tiletype] >= 1;
}

/*
 * Sprite_HumanMulti_1 — Shared slot for the 3 "human-multi" NPC variants
 * by subtype2: Flute Dad (Light World father of Flute Boy), Thief Hideout
 * Guy, Blind's Hut Guy.
 */
void Sprite_HumanMulti_1(int k) {  // 8dc2d9
  switch (sprite_subtype2[k]) {
  case 0: Sprite_FluteDad(k); break;
  case 1: Sprite_ThiefHideoutGuy(k); break;
  case 2: Sprite_BlindsHutGuy(k); break;
  }

}

/*
 * Sprite_BlindsHutGuy — Blind's Hut NPC. Static barrier; idle dialog
 * msg 0x172. On dismiss, update facing direction.
 */
void Sprite_BlindsHutGuy(int k) {  // 8dc2e6
  BlindHideoutGuy_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);
  Sprite_TrackBodyToHead(k);
  sprite_head_dir[k] = 0;
  int j = Sprite_ShowSolicitedMessage(k, 0x172);
  if (j & 0x100)
    sprite_D[k] = sprite_head_dir[k] = j;
}

/*
 * Sprite_ThiefHideoutGuy — Thief NPC inside the Thieves' Hideout. Every 4
 * frames snap facing toward Link (rebound facing-3 special-case keeps him
 * looking sideways). Force OAM palette 15 + deferred-OAM. Idle dialog
 * msg 0x171.
 */
void Sprite_ThiefHideoutGuy(int k) {  // 8dc308
  if (!(frame_counter & 3)) {
    sprite_graphics[k] = 2;
    uint8 dir = Sprite_DirectionToFaceLink(k, NULL);
    sprite_head_dir[k] = dir == 3 ? 2 : dir;
  }
  sprite_oam_flags[k] = 15;
  Oam_AllocateDeferToPlayer(k);
  Thief_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);
  Sprite_ShowSolicitedMessage(k, 0x171);
  sprite_graphics[k] = 2;
}

/*
 * Sprite_FluteDad — Flute Boy's father NPC. Animation: first 48 frames
 * after entry show graphics 2 (crying pose), then alternate 2-frame walk
 * via frame_counter >> 7.
 *
 * Conversation tree:
 *   ai_state set (post-flute-delivered) : msg 0xa3 loop + crying pose.
 *   Flute level < 2 : msg 0xa1 (offer story).
 *   Otherwise       : msg 0xa4 (post-flute thanks). If player presses Y
 *                     with flute selected while overlapping, queue msg
 *                     0xa2 + advance to "thanks" loop.
 */
void Sprite_FluteDad(int k) {  // 8dc343
  FluteBoyFather_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);
  sprite_graphics[k] = (frame_counter < 48) ? 2 : (frame_counter >> 7) & 1;

  if (sprite_ai_state[k]) {
    Sprite_ShowSolicitedMessage(k, 0xa3);
    sprite_graphics[k] = 2;
  } else if (link_item_flute < 2) {
    Sprite_ShowSolicitedMessage(k, 0xa1);
  } else if (!(Sprite_ShowSolicitedMessage(k, 0xa4) & 0x100) &&
             hud_cur_item == kHudItem_Flute && (joypad1H_last&0x40) && Sprite_CheckDamageToLink_same_layer(k)) {
    Sprite_ShowMessageUnconditional(0xa2);
    sprite_ai_state[k]++;
    sprite_graphics[k] = 2;
  }
}

