/*
 * Sprite_FortuneTeller — Slot reused for two roles:
 *   subtype2 0: The fortune teller herself — runs FortuneTeller_Draw and
 *               the 7-state interaction (FortuneTeller_LightOrDarkWorld
 *               picks LW vs DW variant from the savegame_is_darkworld bit).
 *   subtype2 1: An invisible "dwarf solidity" placeholder — pure barrier
 *               that repels Link's dash so he can't walk through a wall.
 */
void Sprite_FortuneTeller(int k) {  // 8dc762
  switch (sprite_subtype2[k]) {
  case 0: // fortuneteller main
    FortuneTeller_Draw(k);
    if (Sprite_ReturnIfInactive(k))
      return;
    FortuneTeller_LightOrDarkWorld(k, savegame_is_darkworld >> 6 & 1);
    break;
  case 1: // dwarf solidity
    if (Sprite_ReturnIfInactive(k))
      return;
    if (Sprite_CheckDamageToLink_same_layer(k)) {
      Sprite_NullifyHookshotDrag();
      link_speed_setting = 0;
      Link_CancelDash();
    }
    break;
  }
}

/*
 * FortuneTeller_PerformPseudoScience — Pick 1 of 16 fortune-reading
 * messages based on the player's outstanding progress. Walks a priority-
 * ordered list of "have you done X yet?" checks (ADD_MSG macro pushes
 * the slot index into a 2-entry array, stopping once 2 slots are filled).
 * Then sram_progress_flags bit 0x40 alternates between the two collected
 * slots so consecutive readings give different tips (j toggles 0/1).
 *
 * Progress checks in priority order:
 *   no Book of Mudora -> #2
 *   no Power Pendant  -> #1
 *   no mushroom       -> #3
 *   no flippers       -> #4
 *   no moon pearl     -> #5
 *   pre-progress-3    -> #6
 *   no magic upgrade  -> #7
 *   no Bombos         -> #8
 *   no chest delivered-> #9
 *   no Smith escorted -> #10
 *   no cape           -> #11
 *   no powder used    -> #12
 *   sword < L4        -> #13
 *   else: defaults #14 #15.
 */
void FortuneTeller_PerformPseudoScience(int k) {  // 8dc849
  sprite_graphics[k] = 0;
  sprite_ai_state[k]++;

  static const uint8 kFortuneTeller_Readings[16] = {0xea, 0xeb, 0xec, 0xed, 0xee, 0xef, 0xf0, 0xf1, 0xf6, 0xf7, 0xf8, 0xf9, 0xfa, 0xfb, 0xfc, 0xfd};

  uint8 slots[2] = { 0, 0 };
  int n = 0;
#define ADD_MSG(q) { slots[n++]=(q); if (n==2) goto done; }

  if (savegame_map_icons_indicator < 3)
    goto done;
  if (!link_item_book_of_mudora) ADD_MSG(2);
  if (!(link_which_pendants & 2)) ADD_MSG(1);
  if (link_item_mushroom < 2) ADD_MSG(3);
  if (!link_item_flippers) ADD_MSG(4);
  if (!link_item_moon_pearl) ADD_MSG(5);
  if (sram_progress_indicator < 3) ADD_MSG(6);
  if (!link_magic_consumption) ADD_MSG(7);
  if (!link_item_bombos_medallion) ADD_MSG(8);
  if (!(sram_progress_indicator_3 & 0x10)) ADD_MSG(9);
  if (!(sram_progress_indicator_3 & 0x20)) ADD_MSG(10);
  if (!link_item_cape) ADD_MSG(11);
  if (!(save_ow_event_info[0x5b] & 2)) ADD_MSG(12);
  if (link_sword_type < 4) ADD_MSG(13);
  ADD_MSG(14);
  ADD_MSG(15);
  int j;
done:
  j = ((sram_progress_flags ^= 0x40) & 0x40) != 0;
  Sprite_ShowMessageUnconditional(kFortuneTeller_Readings[slots[j]]);
}

