/*
 * Smithy_SpawnDumbBarrierSprite — Spawn an invisible barrier sprite
 * (type 0x31 = fortune-teller family with subtype2=1 = dwarf-solidity)
 * at the smith's position so Link can't walk through him.
 */
void Smithy_SpawnDumbBarrierSprite(int k) {  // 8dcb2a
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0x31, &info);
  if (j < 0)
    return;
  Sprite_SetX(j, info.r0_x);
  Sprite_SetY(j, info.r2_y);
  sprite_subtype2[j] = 1;
  sprite_flags4[j] = 0;
  sprite_ignore_projectile[j] = 1;
}

/*
 * Sprite_MazeGameLady — Maze Game host (the lady who times Link's run).
 * 3-state:
 *   0 Startup    : If Link approaches from the left (sprite X > Link X),
 *                  show "go!" msg 0xcc and start the timer; else show
 *                  "wait" msg 0xd0. Initializes word_7FFE00 (frames lo)
 *                  and word_7FFE02 (frames hi) to 0.
 *   1 Sound      : Play start SFX 0x7 and advance.
 *   2 AccumulateTime: Every 63 frames bump word_7FFE00; on overflow
 *                  carry into word_7FFE02. Forms a 32-bit timer for
 *                  the run.
 */
void Sprite_MazeGameLady(int k) {  // 8dcb5c
  Lady_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_TrackBodyToHead(k);
  sprite_head_dir[k] = Sprite_DirectionToFaceLink(k, NULL) ^ 3;
  switch (sprite_ai_state[k]) {
  case 0:  // startup
    if (sprite_x_lo[k] < BYTE(link_x_coord)) {
      int j = Sprite_ShowMessageOnContact(k, 0xcc);
      if (j & 0x100) {
        sprite_D[k] = sprite_head_dir[k] = (uint8)j;
        sprite_ai_state[k] = 1;
        word_7FFE00 = 0;
        word_7FFE02 = 0;
        sprite_A[k] = 0;
        flag_overworld_area_did_change = 0;
      }
    } else {
      Sprite_ShowMessageOnContact(k, 0xd0);
    }
    break;
  case 1:  // sound
    SpriteSfx_QueueSfx3WithPan(k, 0x7);
    sprite_ai_state[k] = 2;
    break;
  case 2:  // accumulate time
    if (++sprite_A[k] == 63) {
      sprite_A[k] = 0;
      word_7FFE00 += 1;
      if (word_7FFE00 == 0)
        word_7FFE02++;
    }
    break;
  }
}

/*
 * Sprite_MazeGameGuy — Maze Game finish judge. 5-state machine:
 *   0 ParseTime    : Format the accumulated frame count into a 4-digit
 *                    BCD display (mm:ss.dd-ish). Show "your time" msg 0xcb.
 *   1 CheckQualify : If sram bit 0x40 set (already collected prize): show
 *                    "nothing more" msg 0xcf -> state 4.
 *                    If time < 16 (too fast / cheated): "sorry" msg 0xcd
 *                    -> state 3 (still grant prize).
 *                    Else: "qualified" msg 0xce -> state 2.
 *                    The "wtf" annotations preserve original ROM quirks
 *                    on writing link_player_handler_state to sprite_D.
 *   2 Sorry        : Loop msg 0xce.
 *   3 CanHaveIt    : Loop msg 0xcd.
 *   4 NothingMore  : Loop msg 0xcf.
 *
 * On screen exit (flag_overworld_area_did_change) reset the dialog to
 * msg 0xd0 (intro again).
 */
void Sprite_MazeGameGuy(int k) {  // 8dcbf2
  int j;
  MazeGameGuy_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_TrackBodyToHead(k);
  sprite_head_dir[k] = 0;
  Sprite_BehaveAsBarrier(k);
  sprite_graphics[k] = frame_counter >> 3 & 1;
  if (flag_overworld_area_did_change) {
    Sprite_ShowMessageOnContact(k, 0xd0);
    return;
  }
  switch (sprite_ai_state[k]) {
  case 0: {  // parse time
    word_7FFE04 = word_7FFE00;
    word_7FFE06 = word_7FFE02;
    int t = word_7FFE04 % 6000;
    int a = t / 600;
    t %= 600;
    int b = t / 60;
    t %= 60;
    int c = t / 10;
    t %= 10;
    dialogue_number[0] = t | c << 4;
    dialogue_number[1] = b | a << 4;
    t = Sprite_ShowMessageOnContact(k, 0xcb);
    if (t & 0x100) {
      sprite_D[k] = sprite_head_dir[k] = (uint8)t;
      sprite_ai_state[k] = 1;
    }
    break;
  }
  case 1:  // check qualify
    if (save_ow_event_info[BYTE(overworld_screen_index)] & 0x40) {
      Sprite_ShowMessageUnconditional(0xcf);
      sprite_ai_state[k] = 4;
    } else if (word_7FFE04 < 16) {
      Sprite_ShowMessageUnconditional(0xcd);
      sprite_D[k] = sprite_head_dir[k] = (uint8)link_player_handler_state;  // wtf
      sprite_ai_state[k] = 3;
    } else {
      Sprite_ShowMessageUnconditional(0xce);
      sprite_D[k] = sprite_head_dir[k] = (uint8)link_player_handler_state;  // wtf
      sprite_ai_state[k] = 2;
    }
    break;
  case 2:  // sorry
    j = Sprite_ShowMessageOnContact(k, 0xce);
    if (j & 0x100)
      sprite_D[k] = sprite_head_dir[k] = (uint8)j;
    break;
  case 3:  // can have it
    j = Sprite_ShowSolicitedMessage(k, 0xcd);
    if (j & 0x100)
      sprite_D[k] = sprite_head_dir[k] = (uint8)j;
    break;
  case 4:  // nothing more
    j = Sprite_ShowSolicitedMessage(k, 0xcf);
    if (j & 0x100)
      sprite_D[k] = sprite_head_dir[k] = (uint8)j;
    break;
  }
}

