/*
 * BatCrash_DrawHardcodedGarbage — Write 8 fixed OAM entries directly into
 * oam_buf+76 representing the static parts of the bat-crash scene (the
 * castle wall fragments and pyramid silhouette tiles). The 9-iteration
 * loop (annotated "wtf 9") writes one extra extended-OAM byte beyond the
 * 8 OAM entries it copies — preserved as-is from the original ROM.
 */
void BatCrash_DrawHardcodedGarbage(int k) {  // 9af750
  static const OamEntSigned kRetreatBat_Oams[8] = {
    { 104, -105, 0x57, 0x01},
    { 120, -105, 0x57, 0x01},
    {-120, -105, 0x57, 0x01},
    { 104,  -89, 0x57, 0x01},
    { 120,  -89, 0x57, 0x01},
    {-120,  -89, 0x57, 0x01},
    { 101, -112, 0x57, 0x01},
    {-117, -112, 0x57, 0x01},
  };
  memcpy(oam_buf + 76, kRetreatBat_Oams, 32);
  for (int i = 0; i < 9; i++) // wtf 9
    bytewise_extended_oam[i + 76] = 2;
}

