/*
 * Overworld_DrawWoodenDoor — Stamp a 2-cell wooden door tile pattern into
 * the overworld map at the given map-cell position. `unlocked` swaps the
 * open/closed tile variants (0xda5/0xda7 vs 0xda4/0xda6). Flags
 * nmi_load_bg_from_vram so the change shows up on the next frame.
 */
void Overworld_DrawWoodenDoor(uint16 pos, bool unlocked) {  // 9bc952
  Overworld_DrawMap16_Persist(pos, unlocked ? 0xda5 : 0xda4);
  Overworld_DrawMap16_Persist(pos+2, unlocked ? 0xda7 : 0xda6);
  nmi_load_bg_from_vram = 1;
}

/*
 * Sprite_D4_Landmine — Landmine sprite. Two trigger paths:
 *   Hammer (Landmine_CheckDetonationFromHammer): immediate detonation.
 *   Link contact: arm a 8-frame fuse (delay_main), with palette cycling
 *     via kLandMine_OamFlags during the countdown for the "blinking
 *     warning" look.
 * On detonation, despawn the mine and spawn a bomb (Sprite_SpawnBomb)
 * pre-configured as state 6 (exploding immediately) with explosion SFX.
 */
void Sprite_D4_Landmine(int k) {  // 9d8099
  static const uint8 kLandMine_OamFlags[4] = {4, 2, 8, 2};

  Landmine_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (!Landmine_CheckDetonationFromHammer(k)) {
    if (!sprite_delay_main[k]) {
      sprite_oam_flags[k] = 4;
      if (Sprite_CheckDamageToLink(k))
        sprite_delay_main[k] = 8;
      return;
    }
    if (sprite_delay_main[k] != 1) {
      sprite_oam_flags[k] = kLandMine_OamFlags[sprite_delay_main[k] >> 1 & 3];
      return;
    }
  }
  sprite_state[k] = 0;
  int j = Sprite_SpawnBomb(k);
  if (j >= 0) {
    sprite_state[j] = 6;
    sprite_C[j] = 2;
    sprite_oam_flags[j] = 2;
    sprite_flags4[j] = 9;
    sprite_delay_aux1[j] = 31;
    sprite_flags2[j] = 3;
    sound_effect_1 = Sprite_CalculateSfxPan(k) | 12;
  }
}

/*
 * Landmine_Draw — Render the mine as 2 tiles. Skip rendering entirely
 * during fade transitions (byte_7E0FC6 >= 3). Allocates 8 OAM bytes
 * from region B regardless so the slot reservation is consistent.
 */
void Landmine_Draw(int k) {  // 9d810c
  static const DrawMultipleData kLandmine_Dmd[2] = {
    {0, 4, 0x0070, 0},
    {8, 4, 0x4070, 0},
  };
  Oam_AllocateFromRegionB(8);
  if (byte_7E0FC6 >= 3)
    return;
  Sprite_DrawMultiple(k, kLandmine_Dmd, 2, NULL);
}

/*
 * Sprite_D3_Stal — Stal (the falling-ceiling skull). 2-state:
 *   0 Dormant : Projectile-immune. On Link contact: nullify hookshot,
 *               repel dash, queue 64-frame fall timer + scrape SFX 0x22.
 *               During the countdown set the hit_timer to flash the
 *               sprite. On expiry: drop the immune flag, trigger fall,
 *               clear "above" and "no-shadow" flags.
 *   1 Active  : Move XYZ; on landing (z negative), 16 z_vel bounce + apply
 *               speed toward Link (12 px/frame). 5-frame skull-rolling
 *               animation via kStal_Gfx.
 */
void Sprite_D3_Stal(int k) {  // 9d8129
  static const uint8 kStal_Gfx[5] = {2, 2, 1, 0, 1};
  if (byte_7E0FC6 < 3) {
    if (!sprite_ai_state[k])
      Oam_AllocateFromRegionB(4);
    Stal_Draw(k);
  }
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  switch(sprite_ai_state[k]) {
  case 0: // dormant
    sprite_ignore_projectile[k] = 1;
    if (Sprite_CheckDamageToLink_same_layer(k)) {
      Sprite_NullifyHookshotDrag();
      Sprite_RepelDash();
      if (!sprite_delay_main[k]) {
        sprite_delay_main[k] = 64;
        SpriteSfx_QueueSfx2WithPan(k, 0x22);
      }
    }
    if (sprite_delay_main[k] != 0) {
      if (sprite_delay_main[k] - 1) {
        sprite_hit_timer[k] = (sprite_delay_main[k] - 1) | 64;
      } else {
        sprite_ignore_projectile[k] = 0;
        sprite_ai_state[k]++;
        sprite_hit_timer[k] = 0;
        sprite_flags3[k] &= ~0x40;
        sprite_flags2[k] &= ~0x80;
      }
    }
    break;
  case 1: // active
    Sprite_CheckDamageToAndFromLink(k);
    Sprite_MoveXYZ(k);
    Sprite_CheckTileCollision(k);
    sprite_z_vel[k]-=2;
    if (sign8(sprite_z[k])) {
      sprite_z[k] = 0;
      sprite_z_vel[k] = 16;
      Sprite_ApplySpeedTowardsLink(k, 12);
    }
    if (!(frame_counter & 3) && ++sprite_subtype2[k] == 5)
      sprite_subtype2[k] = 0;
    sprite_graphics[k] = kStal_Gfx[sprite_subtype2[k]];
    break;
  }
}

/*
 * Stal_Draw — Render the falling skull. Dormant state draws 1 tile (the
 * skull only); active state draws 2 tiles (skull + shadow stretching
 * outward via the 6-entry DMD). Shadow appears only while active.
 */
void Stal_Draw(int k) {  // 9d820c
  static const DrawMultipleData kStal_Dmd[6] = {
    {0,  0, 0x0044, 2},
    {4, 11, 0x0070, 0},
    {0,  0, 0x0044, 2},
    {4, 12, 0x0070, 0},
    {0,  0, 0x0044, 2},
    {4, 13, 0x0070, 0},
  };
  PrepOamCoordsRet info;
  int n = sprite_ai_state[k] ? 2 : 1;
  Sprite_DrawMultiple(k, &kStal_Dmd[sprite_graphics[k] * 2], n, &info);
  if (sprite_ai_state[k])
    SpriteDraw_Shadow(k, &info);
}

/*
 * Sprite_D2_FloppingFish — Fish carried out of water. 5-state:
 *   0 CheckDeepWater : If on tile 8 (deep water), instakill; else activate.
 *   1 FlopAround     : Z gravity (-2/frame); on landing pick random
 *                      diagonal velocity from kFish_Xvel/Yvel + new z=16..31
 *                      bounce. Flop animation kFish_Gfx via subtype2.
 *                      Tile 9 (shallow water) spawns splashes; tile 8
 *                      (deep) kills + splash. Can be lifted permissively.
 *   2 PauseBeforeLeap: Idle wait, then advance with z_vel=48 + splash.
 *   3 Leaping        : Z gravity; at zero-velocity peak (mid-arc), if A
 *                      set show msg 0x176 ("a magic fish!"). On landing
 *                      spawn a good bee (0xdb) with toward-Link motion +
 *                      another splash, then die.
 *   4 Wiggle         : Carried-by-Link variant — physics passed through
 *                      ThrownSprite_TileAndSpriteInteraction.
 *   sprite_state==10 (held) maps to state 4 + frame_counter wiggle anim.
 */
void Sprite_D2_FloppingFish(int k) {  // 9d8235
  static const int8 kFish_Xvel[8] = {0, 12, 16, 12, 0, -12, -16, -12};
  static const int8 kFish_Yvel[8] = {-16, -12, 0, 12, 16, 12, 0, -12};
  static const uint8 kFish_Tab1[2] = {2, 0};
  static const uint8 kFish_Gfx[3] = {1, 5, 3};
  static const uint8 kFish_Gfx2[17] = {5, 5, 6, 6, 5, 5, 4, 4, 3, 7, 7, 8, 8, 7, 7, 8, 8 };

  if (byte_7E0FC6 < 3)
    Fish_Draw(k);
  if (sprite_state[k] == 10) {
    sprite_ai_state[k] = 4;
    sprite_graphics[k] = (frame_counter >> 4 & 1) + 3;
  }
  if (Sprite_ReturnIfInactive(k))
    return;
  switch (sprite_ai_state[k]) {
  case 0:  // check deep water
    Sprite_CheckTileCollision(k);
    if (sprite_tiletype == 8)
      sprite_state[k] = 0;
    else
      sprite_ai_state[k] = 1;
    break;
  case 1:  // flop around
    Sprite_CheckIfLifted_permissive(k);
    Sprite_BounceFromTileCollision(k);
    Sprite_MoveXYZ(k);
    sprite_z_vel[k] -= 2;
    if (sign8(sprite_z[k])) {
      sprite_z[k] = 0;
      if (sprite_tiletype == 9) {
        Sprite_SpawnSmallSplash(k);
      } else if (sprite_tiletype == 8) {
        sprite_state[k] = 0;
        Sprite_SpawnSmallSplash(k);
      }
      sprite_z_vel[k] = (GetRandomNumber() & 15) + 16;
      int j = GetRandomNumber() & 7;
      sprite_x_vel[k] = kFish_Xvel[j];
      sprite_y_vel[k] = kFish_Yvel[j];
      sprite_D[k]++;
      sprite_subtype2[k] = 3;
    }
    sprite_subtype2[k]++;
    if (!(sprite_subtype2[k] & 7)) {
      int j = sprite_D[k] & 1;
      if (sprite_A[k] != kFish_Tab1[j])
        sprite_A[k] += j ? -1 : 1;
    }
    sprite_graphics[k] = kFish_Gfx[sprite_A[k]] + (frame_counter >> 3 & 1);
    break;
  case 2:  // pause before leap
    if (!sprite_delay_main[k]) {
      sprite_ai_state[k] = 3;
      sprite_z_vel[k] = 48;
      Sprite_SpawnSmallSplash(k);
    }
    break;
  case 3:  // leaping
    Sprite_MoveZ(k);
    sprite_z_vel[k] -= 2;
    if (sprite_z_vel[k] == 0 && sprite_A[k] != 0) {
      dialogue_message_index = 0x176;
      Sprite_ShowMessageMinimal();
    }
    if (sign8(sprite_z[k])) {
      sprite_z[k] = 0;
      Sprite_SpawnSmallSplash(k);
      if (sprite_A[k]) {
        SpriteSpawnInfo info;
        int j = Sprite_SpawnDynamically(k, 0xdb, &info);
        if (j >= 0) {
          Sprite_SetSpawnedCoordinates(j, &info);
          Sprite_SetX(j, info.r0_x + 4);
          sprite_stunned[j] = 255;
          sprite_z_vel[j] = 48;
          sprite_delay_aux3[j] = 48;
          Sprite_ApplySpeedTowardsLink(j, 16);
        }
      }
      sprite_state[k] = 0;
    }
    sprite_graphics[k] = kFish_Gfx2[++sprite_subtype2[k] >> 2];
    break;
  case 4:  // wiggle
    if (!sprite_z[k])
      sprite_ai_state[k] = 1;
    Sprite_MoveXY(k);
    ThrownSprite_TileAndSpriteInteraction(k);
    break;
  }
}

/*
 * Fish_Draw — 2-tile fish body composite. graphics==0 is a "preview only"
 * no-render frame (just prep coord for hit detection). Otherwise:
 *   Body: 2 tiles from kFish_Dmd (16 entries / 2 tiles per pose = 8 poses
 *         covering all flop angles).
 *   Shadow: 3-tile shadow strip drawn at the ground using kFish_Dmd2;
 *           the z-clamped (>= 2 ? 2 : z) selector picks the shadow size
 *           as the fish rises.
 */
void Fish_Draw(int k) {  // 9d8483
  static const DrawMultipleData kFish_Dmd[16] = {
    {-4, 8, 0x045e, 0},
    { 4, 8, 0x045f, 0},
    {-4, 8, 0x845e, 0},
    { 4, 8, 0x845f, 0},
    {-4, 8, 0x445f, 0},
    { 4, 8, 0x445e, 0},
    {-4, 8, 0xc45f, 0},
    { 4, 8, 0xc45e, 0},
    { 0, 0, 0x0461, 0},
    { 0, 8, 0x0471, 0},
    { 0, 0, 0x4461, 0},
    { 0, 8, 0x4471, 0},
    { 0, 0, 0x8471, 0},
    { 0, 8, 0x8461, 0},
    { 0, 0, 0xc471, 0},
    { 0, 8, 0xc461, 0},
  };
  static const DrawMultipleData kFish_Dmd2[9] = {
    {-2, 11, 0x0438, 0},
    { 0, 11, 0x0438, 0},
    { 2, 11, 0x0438, 0},
    {-1, 11, 0x0438, 0},
    { 0, 11, 0x0438, 0},
    { 1, 11, 0x0438, 0},
    { 0, 11, 0x0438, 0},
    { 0, 11, 0x0438, 0},
    { 0, 11, 0x0438, 0},
  };
  PrepOamCoordsRet info;
  if (sprite_graphics[k] == 0) {
    Sprite_PrepOamCoord(k, &info);
    return;
  }
  cur_sprite_x += 4;
  Sprite_DrawMultiple(k, &kFish_Dmd[(sprite_graphics[k] - 1) * 2], 2, &info);
  cur_sprite_y += sprite_z[k];
  int j = sprite_z[k] >> 2;
  oam_cur_ptr += 8, oam_ext_cur_ptr += 2;
  Sprite_DrawMultiple(k, &kFish_Dmd2[((j >= 2) ? 2 : j) * 3], 3, &info);
  Sprite_Get16BitCoords(k);
}

