/*
 * Sprite_D1_BunnyBeam — Slot reused indoor (Bunny Beam — the rabbit-
 * transformation beam from the Dark World) vs outdoor (Chimney smoke
 * spawner).
 */
void Sprite_D1_BunnyBeam(int k) {  // 9d858b
  if (player_is_indoors)
    Sprite_BunnyBeam(k);
  else
    Sprite_Chimney(k);

}

/*
 * Sprite_Chimney — Overworld chimney smoke source + child smoke handler.
 * ai_state 0 = the chimney itself: every 67 frames spawn a smoke-puff child
 * (subtype reuses the same sprite type 0xd1 with ai_state=4). ai_state set =
 * the smoke puff: drift with x_vel oscillating ±1 every 8 frames toward
 * ±4 cap (alternates direction via sprite_D parity). Cycle palette every
 * 32 frames via graphics++.
 */
void Sprite_Chimney(int k) {  // 9d858f
  sprite_flags3[k] = 64;
  sprite_ignore_projectile[k] = 64;
  if (!sprite_ai_state[k]) {
    if (Sprite_ReturnIfInactive(k))
      return;
    if (sprite_delay_main[k])
      return;
    sprite_delay_main[k] = 67;
    SpriteSpawnInfo info;
    int j = Sprite_SpawnDynamically(k, 0xd1, &info);
    if (j < 0)
      return;
    Sprite_SetSpawnedCoordinates(j, &info);
    int t = (uint8)info.r0_x + 8;
    sprite_x_lo[j] = t;
    sprite_y_lo[j] = info.r2_y + 4 + (t >> 8);
    sprite_oam_flags[j] = 4;
    sprite_ai_state[j] = 4;
    sprite_flags2[j] = 67;
    sprite_flags3[j] = 67;
    sprite_x_vel[j] = -4;
    sprite_y_vel[j] = -6;
  } else {
    sprite_obj_prio[k] = 0x30;
    ChimneySmoke_Draw(k);
    if (Sprite_ReturnIfInactive(k))
      return;
    Sprite_MoveXY(k);
    if (!(++sprite_subtype2[k] & 7)) {
      int j = sprite_D[k] & 1;
      sprite_x_vel[k] += j ? -1 : 1;
      if (sprite_x_vel[k] == (uint8)(j ? -4 : 4))
        sprite_D[k]++;
    }
    if (!(sprite_subtype2[k] & 31))
      sprite_graphics[k]++;
  }
}

/*
 * Sprite_BunnyBeam — Indoor Bunny Beam (transformation projectile fired
 * by anti-fairies). 2-state:
 *   0 SeekValidSpawn : Wait until the test position isn't blocked by a
 *                      tile; once clear, advance with 128-frame lifetime.
 *   1 Active         : Render via SpriteDraw_Antfairy (5-tile composite),
 *                      overlay all 5 tiles with kRabbitBeam_Gfx chr (3
 *                      crystal phases + 3 rabbit phases) and force palette
 *                      2. After delay_main: enable 0x30 bump damage; on
 *                      Link contact set link_timer_tempbunny=256 (force
 *                      bunny form for 256 frames) and die. Same-layer Link
 *                      homing at 16 px/frame. Wall hit -> SFX 0x15 +
 *                      smoke poof + die.
 */
void Sprite_BunnyBeam(int k) {  // 9d85e0
  static const uint8 kRabbitBeam_Gfx[6] = {0xd7, 0xd7, 0xd7, 0x91, 0x91, 0x91};
  PrepOamCoordsRet info;
  if (!sprite_ai_state[k]) {
    Sprite_PrepOamCoord(k, &info);
    if (Sprite_ReturnIfInactive(k))
      return;
    if (!Sprite_CheckTileCollision(k)) {
      sprite_ai_state[k]++;
      sprite_delay_main[k] = 128;
    }
    return;
  }

  SpriteDraw_Antfairy(k);
  if (!sprite_pause[k]) {
    OamEnt *oam = GetOamCurPtr();
    uint8 charnum = kRabbitBeam_Gfx[sprite_graphics[k]];
    for (int i = 0; i < 5; i++) {
      oam[i].charnum = charnum;
      oam[i].flags = oam[i].flags & 0xf0 | 2;
    }
  }
  if (Sprite_ReturnIfInactive(k))
    return;
  if (!sprite_delay_main[k]) {
    sprite_bump_damage[k] = 0x30;
    if (Sprite_CheckDamageToLink(k)) {
      sprite_state[k] = 0;
      link_timer_tempbunny = 256;
    }
    if (link_is_on_lower_level == sprite_floor[k])
      Sprite_ApplySpeedTowardsLink(k, 16);
    Sprite_MoveXY(k);
    if (Sprite_CheckTileCollision(k)) {
      sprite_state[k] = 0;
      Sprite_SpawnPoofGarnish(k);
      SpriteSfx_QueueSfx2WithPan(k, 0x15);
    }
  }
}

/*
 * Sprite_D0_Lynel — Lynel (Death Mountain centaur-lion). Always re-faces
 * Link each frame (D snaps to DirectionToFaceLink). 3-state combat AI:
 *   0 Target   : Pick a vector to a flanking position (kLynel_X/Ytarget
 *                offsets Link by -96/+96 px on the perpendicular axis).
 *                Cache target into A/B/C/E, schedule 80-frame approach.
 *                Animate walk via subtype2 bit 2.
 *   1 Approach : Every 4 frames re-project speed (24 px/frame) toward
 *                cached target. On reaching within 5 px of target OR on
 *                wall hit, advance to attack with 32-frame windup.
 *   2 Attack   : At delay==16 spawn fire-phlegm projectile via
 *                Sprite_SpawnFirePhlegm. Without level-3 (red) shield,
 *                clear flags5 so the projectile pierces. Animate via
 *                kLynel_AttackGfx. On expiry pick a fresh 16..31-frame
 *                cooldown and return to target.
 */
void Sprite_D0_Lynel(int k) {  // 9d866a
  static const int8 kLynel_AttackGfx[4] = {5, 2, 8, 10};
  static const int8 kLynel_Gfx[8] = {3, 0, 6, 9, 4, 1, 7, 10};
  Lynel_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (Sprite_ReturnIfRecoiling(k))
    return;
  sprite_D[k] = Sprite_DirectionToFaceLink(k, NULL);
  Sprite_CheckDamageToAndFromLink(k);
  switch(sprite_ai_state[k]) {
  case 0:  // target
    if (!sprite_delay_main[k]) {
      static const int8 kLynel_Xtarget[4] = {-96, 96, 0, 0};
      static const int8 kLynel_Ytarget[4] = {8, 8, -96, 112};
      int j = sprite_D[k];
      int x = link_x_coord + kLynel_Xtarget[j];
      sprite_A[k] = x, sprite_B[k] = x >> 8;
      int y = link_y_coord + kLynel_Ytarget[j];
      sprite_C[k] = y, sprite_E[k] = y >> 8;
      sprite_ai_state[k]++;
      sprite_delay_main[k] = 80;
    }
    sprite_graphics[k] = kLynel_Gfx[sprite_subtype2[k] & 4 | sprite_D[k]];
    break;
  case 1:  // approach
    if (sprite_delay_main[k]) {
      if (!((k ^ frame_counter) & 3)) {
        uint16 x = sprite_A[k] | sprite_B[k] << 8;
        uint16 y = sprite_C[k] | sprite_E[k] << 8;
        if ((uint16)(x - cur_sprite_x + 5) < 10 && (uint16)(y - cur_sprite_y + 5) < 10)
          goto incr_state;
        ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLocation(k, x, y, 24);
        sprite_x_vel[k] = pt.x;
        sprite_y_vel[k] = pt.y;
      }
      Sprite_MoveXY(k);
      if (Sprite_CheckTileCollision(k))
        goto incr_state;
      sprite_graphics[k] = kLynel_Gfx[++sprite_subtype2[k] & 4 | sprite_D[k]];
    } else {
incr_state:
      sprite_ai_state[k]++;
      sprite_delay_main[k] = 32;
    }
    break;
  case 2:  // attack
    if (!sprite_delay_main[k]) {
      sprite_delay_main[k] = (GetRandomNumber() & 15) + 16;
      sprite_ai_state[k] = 0;
      return;
    }
    if (sprite_delay_main[k] == 16) {
      int j = Sprite_SpawnFirePhlegm(k);
      if (j >= 0 && link_shield_type != 3)
        sprite_flags5[j] = 0;
    }
    sprite_graphics[k] = kLynel_AttackGfx[sprite_D[k]];
    Sprite_CheckTileCollision(k);
    break;
  }
}

