/*
 * Sprite_SpawnPhantomGanon — Spawn the Phantom Ganon boss (sprite type
 * 0xc9) at the source position. anim_clock=1 marks "ascending" phase
 * (first state of the boss machine).
 */
void Sprite_SpawnPhantomGanon(int k) {  // 9d88a1
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0xc9, &info);
  Sprite_SetSpawnedCoordinates(j, &info);
  sprite_flags2[j] = 2;
  sprite_ignore_projectile[j] = 2;
  sprite_anim_clock[j] = 1;
  sprite_oam_flags[j] = 0;
}

/*
 * Sprite_PhantomGanon — Phantom Ganon mini-boss (the bouncing bat-form
 * Ganon from Ganon's Tower). 2-phase machine:
 *   ai_state 0 (rising): Y velocity counts down via subtype2 ticking; on
 *     y_vel hitting 252 spawn a teleport-poof particle 20 px above; on
 *     y_vel 251 advance to phase 1, schedule 255-frame attack window,
 *     y_vel = -4.
 *   ai_state 1 (attacking): Render via GanonBat_Draw with 4-frame flap.
 *     On sprite_pause (defeated): set the dungeon boss-finished bit
 *     (0x8000) and die.
 *     During delay (< 208): Approach the target screen position
 *     (Link's screen quadrant ~0x78,0x50). X/Y velocities ramp ±1 toward
 *     kGanonBat_TargetXvel/Yvel; flip head_dir/D on reaching target.
 *     Plays SFX 0x1e once per velocity zero-cross. Velocity zeroed and
 *     position homed via ProjectSpeedTowardsLocation before MoveXY.
 *     On delay==0: just drift, velocity ramps to +64 cap.
 */
void Sprite_PhantomGanon(int k) {  // 9d88bc
  static const uint8 kGanonBat_Gfx[4] = {0, 1, 2, 1};
  static const int8 kGanonBat_TargetXvel[2] = {32, -32};
  static const int8 kGanonBat_TargetYvel[2] = {16, -16};

  if (!sprite_ai_state[k]) {
    PhantomGanon_Draw(k);
    if (Sprite_ReturnIfInactive(k))
      return;
    Sprite_MoveY(k);
    if (!(++sprite_subtype2[k] & 31)) {
      if (--sprite_y_vel[k] == 252) {
        int j = SpawnBossPoof(k);
        Sprite_SetY(j, Sprite_GetY(j) - 20);
      } else if (sprite_y_vel[k] == 251) {
        sprite_ai_state[k]++;
        sprite_delay_main[k] = 255;
        sprite_y_vel[k] = -4;
      }
    }
  } else {
    GanonBat_Draw(k);
    if (sprite_pause[k]) {
      sprite_state[k] = 0;
      dung_savegame_state_bits |= 0x8000;
    }
    if (Sprite_ReturnIfInactive(k))
      return;
    sprite_graphics[k] = kGanonBat_Gfx[frame_counter >> 2 & 3];
    if (sprite_delay_main[k]) {
      if (sprite_delay_main[k] < 208) {
        int j = sprite_head_dir[k] & 1;
        sprite_y_vel[k] += j ? -1 : 1;
        if (sprite_y_vel[k] == (uint8)kGanonBat_TargetYvel[j])
          sprite_head_dir[k]++;
        j = sprite_D[k] & 1;
        sprite_x_vel[k] += j ? -1 : 1;
        if (sprite_x_vel[k] == (uint8)kGanonBat_TargetXvel[j])
          sprite_D[k]++;
        if (sprite_x_vel[k] == 0)
          SpriteSfx_QueueSfx3WithPan(k, 0x1e);
      }
      ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLocation(k, link_x_coord & 0xff00 | 0x78, link_y_coord & 0xff00 | 0x50, 5);
      uint8 xvel = sprite_x_vel[k], yvel = sprite_y_vel[k];
      sprite_x_vel[k] = xvel + pt.x, sprite_y_vel[k] = yvel + pt.y;
      Sprite_MoveXY(k);
      sprite_x_vel[k] = xvel, sprite_y_vel[k] = yvel;
    } else {
      Sprite_MoveXY(k);
      if (sprite_x_vel[k] != 64) {
        sprite_x_vel[k]++;
        sprite_y_vel[k]--;
      }
    }
  }
}

