/*
 * ShopItem_HandleReceipt — Award an item via Link_ReceiveItem then
 * (if the slot subtype is 7..13, i.e. a shop counter item) show the
 * appropriate "thanks for purchasing" msg from kShopKeeper_GiveItemMsgs
 * and call ShopKeeper_RapidTerminateReceiveItem to fast-forward through
 * the receive-item animation so the shop UI stays responsive.
 */
void ShopItem_HandleReceipt(int k, uint8 item) {  // 9ef366
  static const uint16 kShopKeeper_GiveItemMsgs[7] = {0x168, 0x167, 0x167, 0x16c, 0x169, 0x16a, 0x16b};
  item_receipt_method = 0;
  Link_ReceiveItem(item, 0);
  int j = sprite_subtype2[k];
  if (j >= 7) {
    Sprite_ShowMessageUnconditional(kShopKeeper_GiveItemMsgs[j - 7]);
    ShopKeeper_RapidTerminateReceiveItem();
  }
}

/*
 * ShopItem_PlayBeep — Plays the "can't buy" rejection SFX 0x3c with pan.
 */
void ShopItem_PlayBeep(int k) {  // 9ef38a
  SpriteSfx_QueueSfx2WithPan(k, 0x3c);
}

/*
 * ShopItem_CheckForAPress — Returns true only if the A button was hit
 * this frame AND Link's hitbox overlaps this slot on the same dungeon
 * floor.
 */
bool ShopItem_CheckForAPress(int k) {  // 9ef391
  if (!(filtered_joypad_L & 0x80))
    return false;
  return Sprite_CheckDamageToLink_same_layer(k);
}

/*
 * ShopItem_HandleCost — Deducts amt rupees from link_rupees_goal if
 * the player can afford it. Returns true on success, false if too poor.
 */
bool ShopItem_HandleCost(int amt) {  // 9ef39e
  if (amt > link_rupees_goal)
    return false;
  link_rupees_goal -= amt;
  return true;
}

