/*
 * Sprite_AC_Apple — Apple (dropped by Tarin or thrown by Apple-tree
 * monsters). ai_state non-zero defers to Sprite_Apple (individual
 * fruit). Otherwise this is the "spawner" head: when sprite_E hits 0,
 * destroy the spawner and emit 2..5 child apples via SpawnApple.
 */
void Sprite_AC_Apple(int k) {  // 9ef515
  if (sprite_ai_state[k]) {
    Sprite_Apple(k);
    return;
  }
  if (sprite_E[k] == 0) {
    sprite_state[k] = 0;
    int n = (GetRandomNumber() & 3) + 2;
    do {
      SpawnApple(k);
    } while (--n >= 0);
  }
}

/*
 * SpawnApple — Spawn one apple child (ai 1, A=255 lifetime, z=8 above
 * ground, zvel 22). Random target landing position picked near parent
 * via GetRandomNumber and projected speed 10.
 */
void SpawnApple(int k) {  // 9ef535
  SpriteSpawnInfo info;
  int j = Sprite_SpawnDynamically(k, 0xac, &info);
  if (j < 0)
    return;
  Sprite_SetSpawnedCoordinates(j, &info);
  sprite_ai_state[j] = 1;
  sprite_A[j] = 255;
  sprite_z[j] = 8;
  sprite_z_vel[j] = 22;
  uint16 x = info.r0_x & ~0xff | GetRandomNumber();
  uint16 y = info.r2_y & ~0xff | GetRandomNumber();
  ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLocation(k, x, y, 10);
  sprite_x_vel[j] = pt.x;
  sprite_y_vel[j] = pt.y;
}

/*
 * Sprite_Apple — Bouncing apple pickup. Blinks (only draws while A>=16
 * or alternating frame_counter bits) to signal it's about to despawn.
 * Link contact: queue chomp SFX 0xb, +8 hearts, destroy. Bounces with
 * parabolic Z (zvel -=1 / frame); on landing damp Z to half and slow
 * X/Y velocities by ±1 toward 0. sprite_A counts down lifetime.
 */
void Sprite_Apple(int k) {  // 9ef57c
  if (sprite_A[k] >= 16 || frame_counter & 2)
    SpriteDraw_SingleLarge(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  if (sprite_A[k] == 0) {
    sprite_state[k] = 0;
    return;
  }
  Sprite_MoveXYZ(k);
  if (Sprite_CheckDamageToLink(k)) {
    SpriteSfx_QueueSfx3WithPan(k, 0xb);
    link_hearts_filler += 8;
    sprite_state[k] = 0;
    return;
  }
  if (!(frame_counter & 1))
    sprite_A[k]--;

  if (!sign8(sprite_z[k] - 1)) {
    sprite_z_vel[k] -= 1;
    return;
  }
  sprite_z[k] = 0;
  uint8 a = sign8(sprite_z_vel[k]) ? sprite_z_vel[k] : 0;
  sprite_z_vel[k] = (uint8)(-a) >> 1;
  if (sprite_x_vel[k])
    sprite_x_vel[k] += sign8(sprite_x_vel[k]) ? 1 : -1;
  if (sprite_y_vel[k])
    sprite_y_vel[k] += sign8(sprite_y_vel[k]) ? 1 : -1;
}

/*
 * Sprite_BC_Drunkard — Drunkard NPC at the LW village tavern. Random
 * 32-frame "stumble" picks gfx pose 1 (animated lurch), otherwise
 * pose 0. Behaves as a barrier. Dialogue: msg 0x175 on contact.
 */
void Sprite_BC_Drunkard(int k) {  // 9ef603
  DrinkingGuy_Draw(k);
  if (Sprite_ReturnIfInactive(k))
    return;
  Sprite_BehaveAsBarrier(k);
  if (!GetRandomNumber())
    sprite_delay_main[k] = 32;
  sprite_graphics[k] = sprite_delay_main[k] ? 1 : 0;
  if (Sprite_ShowSolicitedMessage(k, 0x175) & 0x100)
    sprite_graphics[k] = 0;
}

/*
 * SomariaPlatform_LocatePath — Boot-time path discovery for a Cane-of-
 * Somaria platform. Walks the sprite diagonally (Sprite_SetX/Y +8) until
 * the underlying tile attribute lands in the conveyor-rail range (0xb0
 * to 0xbe). Snaps the position to a tile-grid +4 offset, seeds head_dir
 * = sprite_D as the first travel direction, advances the platform via
 * SomariaPlatformAndPipe_HandleMovement, and arms 14-frame aux4 + bump
 * graphics so the platform appears.
 */
void SomariaPlatform_LocatePath(int k) {  // 9ef640
  for (;;) {
    uint8 tiletype = SomariaPlatformAndPipe_CheckTile(k);
    sprite_E[k] = tiletype;
    if (tiletype >= 0xb0 && tiletype < 0xbf)
      break;
    Sprite_SetX(k, Sprite_GetX(k) + 8);
    Sprite_SetY(k, Sprite_GetY(k) + 8);
  }
  sprite_x_lo[k] = (sprite_x_lo[k] & ~7) + 4;
  sprite_y_lo[k] = (sprite_y_lo[k] & ~7) + 4;
  sprite_head_dir[k] = sprite_D[k];
  SomariaPlatformAndPipe_HandleMovement(k);
  sprite_ignore_projectile[k]++;
  player_on_somaria_platform = 0;
  sprite_delay_aux4[k] = 14;
  sprite_graphics[k]++;
}

/*
 * Sprite_ED_SomariaPlatform — Cane-of-Somaria red platform that rides
 * the conveyor-rail tile. gfx 0 = boot state: call SomariaPlatform_
 * LocatePath, then spawn a superficial bomb blast at -8/-8 (the
 * summon sparkle).
 * gfx 1 = active: every 8 frames check the underlying tile; if the
 * tile attribute changed (junction reached), pick a new direction and
 * call SomariaPlatform_HandleDrag to drag Link in tow. drag_player_x/y
 * are nudged by per-direction kSomariaPlatform_DragX/Y so Link slides
 * with the platform. Special-case room 36 (Misery Mire conveyor maze)
 * sets player_on_somaria_platform = 1 instead of dragging.
 * sprite_C set means "Link is currently riding"; cleared when Link
 * gets off or the platform de-aggros.
 */
void Sprite_ED_SomariaPlatform(int k) {  // 9ef6d4
  switch(sprite_graphics[k]) {
  case 0: {
    SomariaPlatform_LocatePath(k);
    int j = Sprite_SpawnSuperficialBombBlast(k);
    if (j >= 0) {
      Sprite_SetX(j, Sprite_GetX(j) - 8);
      Sprite_SetY(j, Sprite_GetY(j) - 8);
    }
    break;
  }
  case 1:
    SomariaPlatform_Draw(k);
    if (Sprite_ReturnIfInactive(k))
      return;
    if (!(drag_player_x | drag_player_y) && sign8(player_near_pit_state - 2) && Sprite_CheckDamageToLink_ignore_layer(k)) {
      sprite_C[k] = 1;
      Link_CancelDash();
      if (link_player_handler_state != kPlayerState_Hookshot && link_player_handler_state != kPlayerState_SpinAttacking) {
        if (sprite_ai_state[k]) {
          SomariaPlatformAndPipe_HandleMovement(k);
          return;
        }
        sprite_A[k]++;
        player_on_somaria_platform = 2;
        if (!(sprite_A[k] & 7)) {
          uint8 a = SomariaPlatformAndPipe_CheckTile(k);
          if (a != sprite_E[k]) {
            sprite_E[k] = a;
            sprite_head_dir[k] = sprite_D[k];
            SomariaPlatformAndPipe_HandleMovement(k);
            SomariaPlatform_HandleDrag(k);
          }
        }
        if (BYTE(dungeon_room_index) != 36) {
          static const int8 kSomariaPlatform_DragX[8] = {0, 0, -1, 1, -1, 1, 1, -1};
          static const int8 kSomariaPlatform_DragY[8] = {-1, 1, 0, 0, -1, 1, -1, 1};
          int j = sprite_D[k];
          drag_player_x += kSomariaPlatform_DragX[j];
          drag_player_y += kSomariaPlatform_DragY[j];
          Sprite_MoveXY(k);
          SomariaPlatform_DragLink(k);
        } else {
          player_on_somaria_platform = 1;
        }
        return;
      }
    }
    if (sprite_C[k]) {
      player_on_somaria_platform = 0;
      sprite_C[k] = 0;
    }
    break;
  }
}

/*
 * SomariaPlatformAndPipe_HandleMovement — Per-direction velocity setter
 * for somaria platforms + Cane-of-Somaria pipes. Calls SomariaPlatform_
 * HandleJunctions first to maybe pivot the direction at branching
 * rails, then applies kSomariaPlatform_Xvel/Yvel (±16 cardinal or
 * diagonal) per the chosen sprite_D 0..7.
 */
void SomariaPlatformAndPipe_HandleMovement(int k) {  // 9ef7af
  static const int8 kSomariaPlatform_Xvel[8] = {0, 0, -16, 16, -16, 16, 16, -16};
  static const int8 kSomariaPlatform_Yvel[8] = {-16, 16, 0, 0, -16, 16, -16, 16};
  SomariaPlatform_HandleJunctions(k);
  int j = sprite_D[k];
  sprite_x_vel[k] = kSomariaPlatform_Xvel[j];
  sprite_y_vel[k] = kSomariaPlatform_Yvel[j];
}

/*
 * SomariaPlatformAndPipe_CheckTile — Returns the BG attribute byte at
 * the platform's current world coords. Used to detect rail/junction
 * type changes for direction-switching logic.
 */
uint8 SomariaPlatformAndPipe_CheckTile(int k) {  // 9ef7c2
  uint16 x = Sprite_GetX(k), y = Sprite_GetY(k);
  return GetTileAttribute(0, &x, y);
}

/*
 * SomariaPlatform_Draw — 16-entry composite (4 emerge poses x 4-tile
 * cross layout). delay_aux4 & 12 selects the emerge frame: progressively
 * tighter clusters as the platform forms. Allocated from region B so
 * the platform always draws above the rail tiles.
 */
void SomariaPlatform_Draw(int k) {  // 9ef860
  static const DrawMultipleData kSomariaPlatform_Dmd[16] = {
    {-16, -16, 0x00ac, 2},
    {  0, -16, 0x40ac, 2},
    {-16,   0, 0x80ac, 2},
    {  0,   0, 0xc0ac, 2},
    {-13, -13, 0x00ac, 2},
    { -3, -13, 0x40ac, 2},
    {-13,  -3, 0x80ac, 2},
    { -3,  -3, 0xc0ac, 2},
    {-10, -10, 0x00ac, 2},
    { -6, -10, 0x40ac, 2},
    {-10,  -6, 0x80ac, 2},
    { -6,  -6, 0xc0ac, 2},
    { -8,  -8, 0x00ac, 2},
    { -8,  -8, 0x40ac, 2},
    { -8,  -8, 0x80ac, 2},
    { -8,  -8, 0xc0ac, 2},
  };
  Oam_AllocateFromRegionB(0x10);
  Sprite_DrawMultiple(k, &kSomariaPlatform_Dmd[sprite_delay_aux4[k] & 12], 4, NULL);
}

/*
 * SomariaPlatform_HandleJunctions — Rail tile-type dispatcher. Each
 * tile id 0xb2..0xbe encodes a different junction:
 *   0xb2/0xb5 ZigZag rising slope -> reverse X-direction bit.
 *   0xb3/0xb4 ZigZag falling slope -> reverse Y-direction bit.
 *   0xb6 Transit -> wait for player input that matches one of the 4
 *     allowed exits (kSomariaPlatform_TransitDir per current dir).
 *   0xb7..0xba T-junctions (no Up/Down/Left/Right) — each blocks one
 *     direction and re-aims the platform when Link pushes a valid
 *     d-pad. Defaults split based on incoming direction.
 *   0xbb TransitTileNoBack — wait for a d-pad in any non-backward
 *     direction.
 *   0xbc TransitTileQuestion — yes/no branching, dir set per chosen
 *     joypad bit.
 *   0xbe endpoint — flip direction to reverse, set Link visible.
 * Used by both Sprite_ED platforms and Pipe variants.
 */
void SomariaPlatform_HandleJunctions(int k) {  // 9ef87d
  switch (sprite_E[k]) {
  case 0xb2:
  case 0xb5:  // ZigZagRisingSlope
    sprite_D[k] ^= 3;
    break;
  case 0xb3:
  case 0xb4:  // ZigZagFallingSlope
    sprite_D[k] ^= 2;
    break;
  case 0xb6: { // TransitTile
    static const uint8 kSomariaPlatform_TransitDir[4] = {4, 8, 1, 2};
    sprite_ai_state[k] = 1;
    if (!link_auxiliary_state && joypad1H_last & kSomariaPlatform_TransitDir[sprite_D[k]]) {
      sprite_ai_state[k] = 0;
      sprite_D[k] ^= 1;
    }
    link_visibility_status = 0;
    player_on_somaria_platform = 1;
    break;
  }
  case 0xb7: {  // Tjunc_NoUp
    static const uint8 kSomariaPlatform_Keys1[4] = {3, 7, 6, 5};
    uint8 t = joypad1H_last & kSomariaPlatform_Keys1[sprite_D[k]];
    if (t & 8) {
      sprite_D[k] = 0;
    } else if (t & 4) {
      sprite_D[k] = 1;
    } else if (t & 2) {
      sprite_D[k] = 2;
    } else if (t & 1) {
      sprite_D[k] = 3;
    } else if (sprite_D[k] == 0) {
      sprite_D[k] = 2;
    }
    sprite_ai_state[k] = 0;
    break;
  }
  case 0xb8: {  // Tjunc_NoDown
    static const uint8 kSomariaPlatform_Keys2[4] = {11, 3, 10, 9};
    uint8 t = joypad1H_last & kSomariaPlatform_Keys2[sprite_D[k]];
    if (t & 8) {
      sprite_D[k] = 0;
    } else if (t & 4) {
      sprite_D[k] = 1;
    } else if (t & 2) {
      sprite_D[k] = 2;
    } else if (t & 1) {
      sprite_D[k] = 3;
    } else if (sprite_D[k] == 1) {
      sprite_D[k] = 2;
    }
    sprite_ai_state[k] = 0;
    break;
  }
  case 0xb9: {  // Tjunc_NoLeft
    static const uint8 kSomariaPlatform_Keys3[4] = {9, 5, 12, 13};
    uint8 t = joypad1H_last & kSomariaPlatform_Keys3[sprite_D[k]];
    if (t & 8) {
      sprite_D[k] = 0;
    } else if (t & 4) {
      sprite_D[k] = 1;
    } else if (t & 2) {
      sprite_D[k] = 2;
    } else if (t & 1) {
      sprite_D[k] = 3;
    } else if (sprite_D[k] == 2) {
      sprite_D[k] = 0;
    }
    sprite_ai_state[k] = 0;
    break;
  }
  case 0xba: {  // Tjunc_NoRight
    static const uint8 kSomariaPlatform_Keys4[4] = {0xa, 6, 0xe, 0xc};
    uint8 t = joypad1H_last & kSomariaPlatform_Keys4[sprite_D[k]];
    if (t & 8) {
      sprite_D[k] = 0;
    } else if (t & 4) {
      sprite_D[k] = 1;
    } else if (t & 2) {
      sprite_D[k] = 2;
    } else if (t & 1) {
      sprite_D[k] = 3;
    } else if (sprite_D[k] == 3) {
      sprite_D[k] = 0;
    }
    sprite_ai_state[k] = 0;
    break;
  }
  case 0xbb: {  // TransitTileNoBack
    static const uint8 kSomariaPlatform_Keys5[4] = {0xb, 7, 0xe, 0xd};
    uint8 t = joypad1H_last & kSomariaPlatform_Keys5[sprite_D[k]];
    if (t & 8) {
      sprite_D[k] = 0;
    } else if (t & 4) {
      sprite_D[k] = 1;
    } else if (t & 2) {
      sprite_D[k] = 2;
    } else if (t & 1) {
      sprite_D[k] = 3;
    }
    break;
  }
  case 0xbc: {  // TransitTileQuestion
    static const uint8 kSomariaPlatform_Keys6[4] = {0xc, 0xc, 3, 3};
    sprite_ai_state[k] = 1;
    uint8 t = joypad1H_last & kSomariaPlatform_Keys6[sprite_D[k]];
    if (t) {
      if (t & 8) {
        sprite_D[k] = 0;
      } else if (t & 4) {
        sprite_D[k] = 1;
      } else if (t & 2) {
        sprite_D[k] = 2;
      } else {
        sprite_D[k] = 3;
      }
      sprite_ai_state[k] = 0;
    }
    player_on_somaria_platform = 1;
    break;
  }
  case 0xbe:  // endpoint
    sprite_ai_state[k] = 0;
    sprite_D[k] ^= 1;
    link_visibility_status = 0;
    player_on_somaria_platform = 1;
    break;
  }
}

/*
 * SomariaPlatform_HandleDragX — On direction change with perpendicular
 * X-axis flip, snap the platform's X to a tile-grid +4 position and
 * record the snap distance into drag_player_x so Link slides along with
 * the platform (no abrupt jump).
 */
void SomariaPlatform_HandleDragX(int k) {  // 9ef8ad
  if ((sprite_D[k] ^ sprite_head_dir[k]) & 2) {
    uint8 x = (sprite_x_lo[k] & ~7) + 4;
    uint8 t = x - sprite_x_lo[k];
    if (!t)
      return;
    drag_player_x = (int8)t;
    sprite_x_lo[k] = x;
  }
}

/*
 * SomariaPlatform_HandleDragY — Y-axis twin of HandleDragX.
 */
void SomariaPlatform_HandleDragY(int k) {  // 9ef8d7
  if ((sprite_D[k] ^ sprite_head_dir[k]) & 2) {
    uint8 y = (sprite_y_lo[k] & ~7) + 4;
    uint8 t = y - sprite_y_lo[k];
    if (!t)
      return;
    drag_player_y = (int8)t;
    sprite_y_lo[k] = y;
  }
}

/*
 * SomariaPlatform_HandleDrag — Run both X and Y drag helpers in one
 * call.
 */
void SomariaPlatform_HandleDrag(int k) {  // 9ef901
  SomariaPlatform_HandleDragX(k);
  SomariaPlatform_HandleDragY(k);
}

/*
 * SomariaPlatform_DragLink — Each frame, nudge drag_player_x/y by ±1
 * toward (cur_sprite_x - 8, cur_sprite_y - 16) so Link's position
 * tracks the platform center (8 / 16 px hot-spot offset).
 */
void SomariaPlatform_DragLink(int k) {  // 9efb49
  uint16 x = cur_sprite_x - 8 - link_x_coord;
  if (x)
    drag_player_x += sign16(x) ? -1 : 1;
  uint16 y = cur_sprite_y - 16 - link_y_coord;
  if (y)
    drag_player_y += sign16(y) ? -1 : 1;
}

/*
 * Sprite_AE_Pipe_Down — Cane-of-Somaria pipe traversal (and matching
 * up/left/right variants 0xae..0xb1). 6-state pipe-ride cutscene:
 *   gfx 0 boot: lock alt_sprite_spawned_flag, walk to first rail tile.
 *   gfx 1 locate endpoint: traverse rails until 0xbe (endpoint) found
 *     and reverse direction.
 *   gfx 2 wait for player: on Link touching the pipe mouth (and pipe
 *     validation passes), arm 4-frame aux1 entry window, immobilize
 *     Link.
 *   gfx 3 draw player in: pulls Link along the pipe axis using
 *     kPipe_Dirs (1/2/4/8 bit per direction) via Pipe_HandlePlayerMov.
 *   gfx 4 along the pipe: 3 steps per frame (subtype2 loop) walking
 *     both the platform and Link along; junction handling, conveyor
 *     SFX 0xb at 0xb2..b5. On reaching 0xbe -> exit.
 *   gfx 5 exit: 24-frame post-exit slide; restore Link's input.
 */
void Sprite_AE_Pipe_Down(int k) {  // 9efb7e
  static const uint8 kPipe_Dirs[4] = {8, 4, 2, 1};

  uint8 t;
  if (Sprite_ReturnIfInactive(k))
    return;
  switch(sprite_graphics[k]) {
  case 0:  // locate transit tile
    alt_sprite_spawned_flag[0] = 255;
    sprite_D[k] = sprite_type[k] - 0xae;
    SomariaPlatform_LocatePath(k);
    break;
  case 1:  // locate endpoint
    t = SomariaPlatformAndPipe_CheckTile(k);
    if (t == 0xbe) {
      sprite_graphics[k]++;
      t = (sprite_D[k] ^= 1);
    }
    sprite_E[k] = t;
    sprite_head_dir[k] = sprite_D[k];
    SomariaPlatformAndPipe_HandleMovement(k);
    Sprite_MoveXY(k);
    break;
  case 2:  // wait for player
    if (alt_sprite_spawned_flag[0] == 255 && Sprite_CheckDamageToLink_ignore_layer(k)) {
      if (!Pipe_ValidateEntry()) {
        sprite_graphics[k]++;
        sprite_delay_aux1[k] = 4;
        Link_ResetProperties_A();
        flag_is_link_immobilized = 1;
        link_disable_sprite_damage = 1;
        alt_sprite_spawned_flag[0] = k;
      } else {
        Sprite_HaltAllMovement();
      }
    }
    break;
  case 3:  // draw player in
    if (!sprite_delay_aux1[k]) {
      sprite_graphics[k]++;
      link_visibility_status = 12;
    } else {
      flag_is_link_immobilized = 1;
      link_disable_sprite_damage = 1;
      Pipe_HandlePlayerMovement(kPipe_Dirs[sprite_D[k]]);
    }
    break;
  case 4: {  // draw player along
    sprite_subtype2[k] = 3;
    link_x_coord_safe_return_lo = link_x_coord;
    link_x_coord_safe_return_hi = link_x_coord >> 8;
    link_y_coord_safe_return_lo = link_y_coord;
    link_y_coord_safe_return_hi = link_y_coord >> 8;
    do {
      if (!(++sprite_A[k] & 7)) {
        uint8 t = SomariaPlatformAndPipe_CheckTile(k);
        if (t >= 0xb2 && t < 0xb6)
          SpriteSfx_QueueSfx2WithPan(k, 0xb);
        if (t != sprite_E[k]) {
          sprite_E[k] = t;
          if (t == 0xbe) {
            sprite_graphics[k]++;
            sprite_delay_aux1[k] = 24;
          }
          sprite_head_dir[k] = sprite_D[k];
          SomariaPlatformAndPipe_HandleMovement(k);
          SomariaPlatform_HandleDrag(k);
        }
      }
      Sprite_MoveXY(k);
      uint16 x = Sprite_GetX(k) - 8;
      uint16 y = Sprite_GetY(k) - 14;
      if (x != link_x_coord)
        link_x_coord += (x < link_x_coord) ? -1 : 1;
      if (y != link_y_coord)
        link_y_coord += (y < link_y_coord) ? -1 : 1;
    } while (--sprite_subtype2[k]);
    link_x_vel = link_x_coord - link_x_coord_safe_return_lo;
    link_y_vel = link_y_coord - link_y_coord_safe_return_lo;
    link_direction_last = kPipe_Dirs[sprite_D[k]];
    Link_HandleMovingAnimation_FullLongEntry();
    HandleIndoorCameraAndDoors();
    Link_CancelDash();
    break;
  }
  case 5:  //
    if (!sprite_delay_aux1[k]) {
      flag_is_link_immobilized = 0;
      player_on_somaria_platform = 0;
      link_disable_sprite_damage = 0;
      link_visibility_status = 0;
      link_x_vel = link_y_vel = 0;
      alt_sprite_spawned_flag[0] = 255;
      sprite_graphics[k] = 2;
    } else {
      Pipe_HandlePlayerMovement(kPipe_Dirs[sprite_D[k] ^ 1]);
    }
    break;
  }
}

/*
 * Pipe_HandlePlayerMovement — Drives Link's walk animation in pipe
 * direction `dir` (1/2/4/8 bit pattern). Calls the standard movement
 * pipeline (HandleVelocity, animation, camera) so Link visually walks
 * inside the pipe even though sprite_AE handles the actual position
 * updates.
 */
void Pipe_HandlePlayerMovement(uint8 dir) {  // 9efcff
  link_direction_last = link_direction = dir;
  Link_HandleVelocity();
  Link_HandleMovingAnimation_FullLongEntry();
  HandleIndoorCameraAndDoors();
}

/*
 * Faerie_HandleMovement — Shared 2D wander for fairy / great-fairy
 * sprites. Indoor variants (player_is_indoors) bounce off walls and
 * arm a 32-frame aux1 turn-around (clears the targeted-velocity bias).
 * Gfx alternates 0/1 every 8 frames (wing flap).
 * Velocity blending: every 64 frames, pick a new random target near
 * Link (link_coord top byte | random low byte) at speed 16; store the
 * resulting vector in sprite_A (Y) and sprite_D (X). Every 16 frames
 * blend half the current velocity with half of that target, so the
 * fairy drifts smoothly toward the chosen point.
 * Z float: sprite_z oscillates between 8 and 24 with random ±1 zvel
 * (Brownian flutter inside the 16-pixel band).
 * OAM flip-bit follows X-vel sign for facing.
 */
void Faerie_HandleMovement(int k) {  // 9efd1c
  sprite_graphics[k] = frame_counter >> 3 & 1;
  if (player_is_indoors && !sprite_delay_aux1[k]) {
    if (Sprite_CheckTileCollision(k) & 3) {
      sprite_x_vel[k] = -sprite_x_vel[k];
      sprite_D[k] = -sprite_D[k];
      sprite_delay_aux1[k] = 32;
    }
    if (sprite_wallcoll[k] & 12) {
      sprite_y_vel[k] = -sprite_y_vel[k];
      sprite_A[k] = -sprite_A[k];
      sprite_delay_aux1[k] = 32;
    }
  }
  if (sprite_x_vel[k]) {
    if (sign8(sprite_x_vel[k]))
      sprite_oam_flags[k] &= ~0x40;
    else
      sprite_oam_flags[k] |= 0x40;
  }
  Sprite_MoveXY(k);
  if (!(frame_counter & 63)) {
    uint16 x = (link_x_coord & ~0xff) + GetRandomNumber();
    uint16 y = (link_y_coord & ~0xff) + GetRandomNumber();
    ProjectSpeedRet pt = Sprite_ProjectSpeedTowardsLocation(k, x, y, 16);
    sprite_A[k] = pt.y;
    sprite_D[k] = pt.x;
  }
  if (!(frame_counter & 15)) {
    sprite_y_vel[k] = ((int8)sprite_A[k] + (int8)sprite_y_vel[k]) >> 1;
    sprite_x_vel[k] = ((int8)sprite_D[k] + (int8)sprite_x_vel[k]) >> 1;
  }
  Sprite_MoveZ(k);
  sprite_z_vel[k] += (GetRandomNumber() & 1) ? -1 : 1;
  if (sprite_z[k] < 8) {
    sprite_z[k] = 8;
    sprite_z_vel[k] = 5;
  } else if (sprite_z[k] >= 24) {
    sprite_z[k] = 24;
    sprite_z_vel[k] = -5;
  }
}

